// PRIVATE — internal helper. External callers must use TimeKeeper.clockDay() / clockDayOf().
// Do not call _toLocalDateKey directly outside this module — preflight lint will flag it.
function _toLocalDateKey(input = new Date()) {
  const dt = input instanceof Date ? input : new Date(input);
  if (Number.isNaN(dt.getTime())) return _toLocalDateKey(new Date());
  const yyyy = dt.getFullYear();
  const mm = String(dt.getMonth() + 1).padStart(2, "0");
  const dd = String(dt.getDate()).padStart(2, "0");
  return `${yyyy}-${mm}-${dd}`;
}

// PRIVATE — internal helper. External callers must use TimeKeeper.stillformDay() / stillformDayOf().
// Returns the user's "logical today" — calendar day shifted by morning_start.
// Used for daily-ceremony comparisons (morning check-in, EOD, "is it done today")
// where the user's day rolls over at their configured morning start, not midnight.
// Default morning start: 270 minutes (4:30 AM local). Always returns a local date key.
// Do not call _getStillformToday directly outside this module — preflight lint will flag it.
function _getStillformToday(date = new Date()) {
  const morningStart = (() => {
    try { const v = localStorage.getItem("stillform_morning_start"); return v ? parseInt(v) : 270; }
    catch { return 270; }
  })();
  const minutesNow = date.getHours() * 60 + date.getMinutes();
  const target = new Date(date);
  if (minutesNow < morningStart) target.setDate(target.getDate() - 1);
  return _toLocalDateKey(target);
}

// ─────────────────────────────────────────────────────────────────────────────
// ─── TimeKeeper — Single Source of Truth for All Date/Time Operations ───────
//
// The phone is the source of truth for time. The OS already handles DST,
// timezone changes, and leap years. TimeKeeper just reads the phone correctly
// and exposes one consistent API so date logic doesn't drift across the codebase.
//
// USE THIS MODULE for every date/time question in the app.
// DO NOT use raw `new Date().toISOString().slice/split` or `Date.now() - 86400000`
// patterns — those bypass the user's local time and the morning_start setting.
//
// Two flavors of "today":
//   - clockDay():     phone's wall-clock day  (use for: timestamps, log entries)
//   - stillformDay(): morning_start-aware day (use for: ceremonies, streaks, practice continuity)
//
// All date strings returned in YYYY-MM-DD format, local time.
// ─────────────────────────────────────────────────────────────────────────────
const TimeKeeper = {
  // ─── CLOCK DAY (phone's wall-clock calendar day) ─────────────────────────

  /** Today by phone clock. e.g. "2026-04-27" */
  clockDay() {
    return _toLocalDateKey(new Date());
  },

  /** Extract clock day from a Date object or ISO timestamp string.
   *  Returns null if input is missing or invalid.
   *  REPLACES the broken `timestamp.slice(0, 10)` pattern (which extracts UTC). */
  clockDayOf(input) {
    if (!input) return null;
    const dt = input instanceof Date ? input : new Date(input);
    if (Number.isNaN(dt.getTime())) return null;
    return _toLocalDateKey(dt);
  },

  // ─── STILLFORM DAY (morning_start-aware practice day) ────────────────────

  /** Today as the user's practice day. If now is before their morning_start
   *  setting (default 4:30 AM local), returns yesterday's date so late-night
   *  sessions stay grouped with the practice day they belong to. */
  stillformDay() {
    return _getStillformToday(new Date());
  },

  /** Yesterday as the user's practice day. */
  stillformYesterday() {
    const todayKey = _getStillformToday(new Date());
    // Use noon-of-today to avoid DST edge cases when subtracting a day
    const d = new Date(`${todayKey}T12:00:00`);
    d.setDate(d.getDate() - 1);
    return _toLocalDateKey(d);
  },

  /** Extract Stillform day from a Date object or ISO timestamp string.
   *  Honors the user's morning_start setting at time of call.
   *  Returns null if input is missing or invalid. */
  stillformDayOf(input) {
    if (!input) return null;
    const dt = input instanceof Date ? input : new Date(input);
    if (Number.isNaN(dt.getTime())) return null;
    return _getStillformToday(dt);
  },

  // ─── PERIOD FILTERS (millisecond cutoffs for sliding windows) ────────────

  /** Millisecond timestamp for N days ago. Use for "last 30 days" filter math:
   *  `sessions.filter(s => new Date(s.timestamp).getTime() > TimeKeeper.daysAgoMs(30))`
   *  This is a sliding window — exactly N × 24 hours back from now. */
  daysAgoMs(n) {
    return Date.now() - n * 24 * 60 * 60 * 1000;
  },

  // ─── TIMEZONE ────────────────────────────────────────────────────────────

  /** User's IANA timezone string. e.g. "America/New_York", "Asia/Tokyo".
   *  Reads the OS — auto-updates when user travels.
   *  Returns null if browser doesn't support Intl (very rare). */
  timezone() {
    try {
      return Intl.DateTimeFormat().resolvedOptions().timeZone || null;
    } catch {
      return null;
    }
  },

  /** Detect if the user has changed timezone since last app open.
   *  Use the result to inform AI context — does NOT change time logic itself
   *  (the OS already handled that). Just lets the AI know the user moved.
   *  Returns: { changed: boolean, from: string|null, to: string|null }
   *  Updates the stored timezone every call so future calls compare against most recent. */
  detectTravel() {
    try {
      const STORAGE_KEY = "stillform_last_timezone";
      const currentTz = this.timezone();
      if (!currentTz) return { changed: false, from: null, to: null };
      const prevTz = (() => {
        try { return localStorage.getItem(STORAGE_KEY); } catch { return null; }
      })();
      try { localStorage.setItem(STORAGE_KEY, currentTz); } catch {}
      if (!prevTz) return { changed: false, from: null, to: currentTz };
      if (prevTz === currentTz) return { changed: false, from: prevTz, to: currentTz };
      return { changed: true, from: prevTz, to: currentTz };
    } catch {
      return { changed: false, from: null, to: null };
    }
  }
};

// Captures timezone travel status once at module load.
// Read by Reframe AI context construction. Doesn't re-run on every send —
// detectTravel() updates the stored timezone after first call so subsequent
// reads inside the same session would always return changed:false anyway.
const APP_LOAD_TRAVEL = TimeKeeper.detectTravel();

// ─────────────────────────────────────────────────────────────────────────────
// Bio-filter staleness guard — bio-filter is the user's hardware diagnostic
// (activated, depleted, pain, sleep, medicated, off-baseline). It drives
// AI context, win-suppression, body-first routing, and the hero CTA override.
//
// PROBLEM: previously stored as a plain string with no date. Yesterday's
// hardware drove today's routing forever until the user re-checked in.
//
// SCHEMA: {"value": "<filter>", "date": "<stillformDay>"}
// Reads return "" if the stored date doesn't match today's Stillform-day.
// External callers must use getActiveBioFilter() / setActiveBioFilter() —
// direct localStorage access on the key bypasses the staleness check.
// ─────────────────────────────────────────────────────────────────────────────
function getActiveBioFilter() {
  try {
    const stored = secureRead("stillform_bio_filter", null);
    if (!stored) return "";
    if (typeof stored === "object") {
      if (stored?.date !== TimeKeeper.stillformDay()) return "";
      return stored.value || "";
    }
    return ""; // Legacy plain-string format — no date — treat as expired (safe default)
  } catch { return ""; }
}

function setActiveBioFilter(value) {
  try {
    secureWrite("stillform_bio_filter", {
      value: String(value || ""),
      date: TimeKeeper.stillformDay()
    });
  } catch {}
}

// Low-demand mode trigger — aligned with Apr 28 locked decision
// ("broad cognitive-bandwidth-limited population: SSRI users, post-anesthesia,
// sleep aids, chemo, recreational, sleep-deprived parents, migraine,
// dissociative episodes, etc"). Originally only triggered on "medicated".
// May 6, 2026 audit found this was narrower than the locked decision intended —
// users marking depleted/sleep/pain/hormonal/gut have the same reduced
// executive function low-demand was designed to meet.
//
// EXPLICITLY EXCLUDED: "activated" (high arousal is a different physiological
// state, needs activation-specific framing — not cognitive simplification).
// EXPLICITLY EXCLUDED: "clear" (no flag, normal voice).
const LOW_DEMAND_FLAGS = ["medicated", "depleted", "sleep", "pain", "hormonal", "gut"];

function isLowDemandBioFilter(bf) {
  if (!bf) return false;
  const tokens = String(bf).toLowerCase().split(",").map(t => t.trim());
  return tokens.some(t => LOW_DEMAND_FLAGS.includes(t));
}

// Body-routing rule per the science:
// - Pain → Body Scan (Kabat-Zinn 1982 MBSR, Reiner et al. 2013, Farb et al. 2013 — mindful pain pathway)
// - Off-baseline / Something → Body Scan (locate the unnamed signal first)
// - Activated / Sleep / Depleted / Medicated → straight to Breathe (Ochsner & Gross 2005 — parasympathetic regulation IS the science answer for these states; body-scanning would be friction without benefit)
const shouldBodyRouteToScan = (bioFilter) => (
  bioFilter.includes("pain") ||
  bioFilter.includes("off-baseline") ||
  bioFilter.includes("something")
);

