const applyThemePreset = (themeId, highContrast = false) => {
  if (typeof document === "undefined") return;
  const preset = THEME_PRESETS[themeId] || THEME_PRESETS.dark;
  const root = document.documentElement;
  Object.entries(preset).forEach(([token, value]) => root.style.setProperty(token, value));
  if (highContrast) {
    const overlay = themeId === "light" ? HIGH_CONTRAST_OVERLAY_LIGHT : HIGH_CONTRAST_OVERLAY;
    Object.entries(overlay).forEach(([token, value]) => root.style.setProperty(token, value));
  }
};

const readArrayFromStorage = (key) => {
  try {
    const parsed = JSON.parse(localStorage.getItem(key) || "[]");
    return Array.isArray(parsed) ? parsed : [];
  } catch {
    return [];
  }
};

const getSessionsFromStorage = () => readArrayFromStorage(SESSION_STORAGE_KEY);

const setSessionsInStorage = (sessions) => {
  try {
    localStorage.setItem(SESSION_STORAGE_KEY, JSON.stringify(Array.isArray(sessions) ? sessions : []));
  } catch {}
};

const appendSessionToStorage = (entry) => {
  if (!entry) return getSessionCountFromStorage();
  const sessions = getSessionsFromStorage();
  sessions.push(entry);
  setSessionsInStorage(sessions);
  return sessions.length;
};

// Compute the current consecutive-day session streak. Looks back from today
// using stillformDay (morning_start-aware) so a 5am session counts toward the
// previous day for late-night practitioners. Returns 0 if today and yesterday
// have no sessions.
const computeStreak = () => {
  try {
    const sessions = getSessionsFromStorage();
    const daySet = new Set(sessions.map(s => TimeKeeper.stillformDayOf(s.timestamp)).filter(Boolean));
    let streak = 0;
    for (let i = 0; i < 365; i++) {
      const d = new Date();
      d.setDate(d.getDate() - i);
      if (daySet.has(TimeKeeper.stillformDayOf(d))) streak++;
      else break;
    }
    return streak;
  } catch { return 0; }
};

// Count today's sessions for the home-screen daily-rep counter. Uses
// stillformDay so the count rolls over at the user's morning_start, not midnight.
const countTodaysSessions = () => {
  try {
    const today = TimeKeeper.stillformDay();
    return getSessionsFromStorage().filter(s => TimeKeeper.stillformDayOf(s.timestamp) === today).length;
  } catch { return 0; }
};

// Get the most recent session (any tool) within the last 24h. Used for the
// "pick up where you left off" affordance on home. Returns null if no recent
// session.
const getMostRecentSession = () => {
  try {
    const sessions = getSessionsFromStorage();
    if (!sessions.length) return null;
    const last = sessions[sessions.length - 1];
    if (!last?.timestamp) return null;
    const ageMs = Date.now() - new Date(last.timestamp).getTime();
    if (ageMs > 24 * 60 * 60 * 1000) return null; // >24h, not relevant
    return { ...last, ageMs };
  } catch { return null; }
};

// Format an age in ms as a brief human label: "12m ago", "2h ago", "yesterday".
const formatSessionAge = (ageMs) => {
  if (ageMs < 60 * 1000) return "just now";
  if (ageMs < 60 * 60 * 1000) return `${Math.floor(ageMs / (60 * 1000))}m ago`;
  if (ageMs < 24 * 60 * 60 * 1000) return `${Math.floor(ageMs / (60 * 60 * 1000))}h ago`;
  return "yesterday";
};

// Map session.tools array to a readable tool label for the resume affordance.
const labelForLastSession = (session) => {
  const tools = Array.isArray(session?.tools) ? session.tools : [];
  if (tools.includes("reframe")) return "Reframe";
  if (tools.includes("body-scan")) return "Body Scan";
  if (tools.includes("breathe") && tools.includes("ground")) return "Breathe + Ground";
  if (tools.includes("breathe")) return "Breathe";
  if (tools.includes("metacognition")) return "Self Mode";
  return "Last session";
};

// ─── COGNITIVE FUNCTION MEASUREMENT — Phase 0 storage infrastructure ────
// Per COGNITIVE_FUNCTION_MEASUREMENT_SPEC.md (Apr 30, 2026). This is the
// data layer only — no UI, no stimulus libraries, no surfacing logic.
// Stimulus libraries, exercise UI, and surfacing logic ship in subsequent
// phases per the spec.
//
// Storage shape: an array of function-check records. Each record:
//   {
//     v: 1,                          // schema version
//     id: "fc_<timestamp>",          // unique
//     candidate: "affect-labeling" | "interoceptive-latency" | "cognitive-defusion",
//     timestamp: ISO8601,
//     primaryMs: number,             // latency in ms (Candidate 1, 2)
//     primaryCount: number,          // count of frames (Candidate 3)
//     specificity: 0 | 0.5 | 1,      // for Candidate 2
//     bioFilter: string[]|null,      // user state at measurement time
//     toolsBeforeMs: { breathe, body-scan, reframe } | null,
//                                    // recent practice context
//   }
//
// Honest framing rules from spec §"What it can't do" enforced at surfacing
// time, not at storage time. Storage is dumb; comparison logic is where
// the integrity claim lives.
// ─── PATTERN DISRUPTION LAYER — May 7, 2026 ───────────────────────────
// Per PATTERN_DISRUPTION_SPEC.md. Detects repeated loops across the user's
// recent sessions (≥3 instances of the same signal across 8 dimensions),
// surfaces the pattern with an offered disruptor, tracks dismissals
// (two-strikes-and-drop), and records disruptor sessions.
//
// Storage:
//   stillform_pattern_detections: array of detected pattern instances
//   stillform_disruptor_sessions: array of disruptor tool runs
//
// Detection runs deterministically (no AI cost) on a recent-session window.
// AI-aware enrichment (reasoning + dimension classification) layered on top
// when a pre-filter threshold trips. Per spec §4 open question Q4: AI runs
// only after deterministic pre-filter, not on every data point.

const PATTERN_DETECTIONS_KEY = "stillform_pattern_detections";
const DISRUPTOR_SESSIONS_KEY = "stillform_disruptor_sessions";

// Detection threshold: 3 data points of the same signal in the recent window.
// Window: last 14 days OR last 10 sessions, whichever is shorter.
const PATTERN_THRESHOLD = 3;
const PATTERN_WINDOW_DAYS = 14;
const PATTERN_WINDOW_SESSIONS = 10;

// Maximum stored detections — older ones are pruned to keep storage bounded.
const PATTERN_DETECTIONS_MAX = 50;
const DISRUPTOR_SESSIONS_MAX = 100;

// Eight loop-signal dimensions per spec §2.2. Each is one axis the
// detector can register repetition on. Body-first detection (chips +
// bio-filter) is explicit per spec §2.3.
const PATTERN_DIMENSIONS = Object.freeze({
  SAME_CHIP: "same_chip",            // post-state chip repeats
  SAME_BIO_FILTER: "same_bio_filter", // hardware state repeats
  SAME_FEELSTATE: "same_feelstate",  // entry feel state repeats
  SAME_TENSION_AREA: "same_tension_area", // body scan area repeats
  SAME_DISTORTION: "same_distortion", // bias profile distortion repeats
  SAME_TOOL_PATH: "same_tool_path",  // tool sequence repeats
  SHIFT_NOT_LANDING: "shift_not_landing", // post-rate stays equal/lower
  SAME_REFRAME_CONTEXT: "same_reframe_context" // entryMode + feelState combo
});

const getPatternDetectionsFromStorage = () => {
  try {
    const raw = secureRead(PATTERN_DETECTIONS_KEY, []);
    return Array.isArray(raw) ? raw : [];
  } catch { return []; }
};

const writePatternDetections = (detections) => {
  try {
    const trimmed = (Array.isArray(detections) ? detections : []).slice(-PATTERN_DETECTIONS_MAX);
    secureWrite(PATTERN_DETECTIONS_KEY, trimmed);
    return true;
  } catch { return false; }
};

const getDisruptorSessionsFromStorage = () => {
  try {
    const raw = secureRead(DISRUPTOR_SESSIONS_KEY, []);
    return Array.isArray(raw) ? raw : [];
  } catch { return []; }
};

const appendDisruptorSession = (entry) => {
  if (!entry) return null;
  const record = {
    id: entry.id || `ds_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`,
    timestamp: entry.timestamp || new Date().toISOString(),
    patternId: entry.patternId || null,
    dimension: entry.dimension || null,
    durationMs: typeof entry.durationMs === "number" ? entry.durationMs : null,
    completed: entry.completed === true,
    pathway: entry.pathway || "somatic-redirection"
  };
  try {
    const existing = getDisruptorSessionsFromStorage();
    const next = [...existing, record].slice(-DISRUPTOR_SESSIONS_MAX);
    secureWrite(DISRUPTOR_SESSIONS_KEY, next);
    return record;
  } catch { return null; }
};

// Deterministic pre-filter — counts repeats across the 8 dimensions in the
// recent window. Returns array of detected patterns, each with:
//   { dimension, value, count, dataPoints: [session refs] }
// Cheap to run (pure JS over already-loaded session history). AI enrichment
// happens only after this pre-filter trips.
const detectPatternsDeterministic = () => {
  try {
    const sessions = getSessionsFromStorage();
    if (sessions.length < PATTERN_THRESHOLD) return [];

    // Window: most recent N sessions OR last D days, whichever is shorter.
    const windowStart = TimeKeeper.daysAgoMs(PATTERN_WINDOW_DAYS);
    const recent = sessions
      .filter(s => {
        const t = new Date(s.timestamp || 0).getTime();
        return !Number.isNaN(t) && t >= windowStart;
      })
      .slice(-PATTERN_WINDOW_SESSIONS);

    if (recent.length < PATTERN_THRESHOLD) return [];

    // Count repeats per dimension.
    const buckets = {
      [PATTERN_DIMENSIONS.SAME_CHIP]: new Map(),
      [PATTERN_DIMENSIONS.SAME_BIO_FILTER]: new Map(),
      [PATTERN_DIMENSIONS.SAME_FEELSTATE]: new Map(),
      [PATTERN_DIMENSIONS.SAME_TENSION_AREA]: new Map(),
      [PATTERN_DIMENSIONS.SAME_TOOL_PATH]: new Map(),
      [PATTERN_DIMENSIONS.SHIFT_NOT_LANDING]: new Map()
    };

    const recordHit = (dimension, value, sessionRef) => {
      if (!value) return;
      const bucket = buckets[dimension];
      if (!bucket) return;
      const existing = bucket.get(value) || { value, count: 0, dataPoints: [] };
      existing.count += 1;
      existing.dataPoints.push(sessionRef);
      bucket.set(value, existing);
    };

    for (const s of recent) {
      const ref = { timestamp: s.timestamp, sessionId: s.id || null };
      // Same post-state chip
      if (s.postState) recordHit(PATTERN_DIMENSIONS.SAME_CHIP, s.postState, ref);
      // Same bio-filter
      if (s.bioFilter) {
        const tokens = String(s.bioFilter).split(",").map(t => t.trim()).filter(Boolean);
        for (const t of tokens) recordHit(PATTERN_DIMENSIONS.SAME_BIO_FILTER, t, ref);
      }
      // Same entry feel state
      if (s.preState) recordHit(PATTERN_DIMENSIONS.SAME_FEELSTATE, s.preState, ref);
      // Same tool sequence
      if (Array.isArray(s.tools) && s.tools.length > 0) {
        recordHit(PATTERN_DIMENSIONS.SAME_TOOL_PATH, s.tools.join("→"), ref);
      }
      // Body scan tension areas
      if (s.bodyScanTension && typeof s.bodyScanTension === "object") {
        for (const [area, level] of Object.entries(s.bodyScanTension)) {
          if (typeof level === "number" && level >= 3) {
            recordHit(PATTERN_DIMENSIONS.SAME_TENSION_AREA, area, { ...ref, level });
          }
        }
      }
      // Shift not landing — post rate <= pre rate
      if (typeof s.preRate === "number" && typeof s.postRate === "number" && s.postRate <= s.preRate) {
        recordHit(PATTERN_DIMENSIONS.SHIFT_NOT_LANDING, "post_le_pre", ref);
      }
    }

    // Collect any bucket entries that hit threshold.
    const detected = [];
    for (const [dimension, bucket] of Object.entries(buckets)) {
      for (const entry of bucket.values()) {
        if (entry.count >= PATTERN_THRESHOLD) {
          detected.push({
            dimension,
            value: entry.value,
            count: entry.count,
            dataPoints: entry.dataPoints
          });
        }
      }
    }
    // Strongest patterns first.
    detected.sort((a, b) => b.count - a.count);
    return detected;
  } catch { return []; }
};

// Surface state for a pattern detection record. State machine per spec §3.2:
//   "active" → user has not yet responded
//   "dismissed_once" → user dismissed once; will re-fire on next session/day
//   "accepted" → user accepted, routed into disruptor
//   "closed" → two strikes (dismissed twice), pattern instance closed
const PATTERN_STATES = Object.freeze({
  ACTIVE: "active",
  DISMISSED_ONCE: "dismissed_once",
  ACCEPTED: "accepted",
  CLOSED: "closed"
});

// Plain-language label for a pattern dimension — used in the prompt + the
// transparency surface.
const PATTERN_DIMENSION_LABELS = {
  [PATTERN_DIMENSIONS.SAME_CHIP]: "Same closing state",
  [PATTERN_DIMENSIONS.SAME_BIO_FILTER]: "Same hardware state",
  [PATTERN_DIMENSIONS.SAME_FEELSTATE]: "Same entry state",
  [PATTERN_DIMENSIONS.SAME_TENSION_AREA]: "Tension in the same place",
  [PATTERN_DIMENSIONS.SAME_TOOL_PATH]: "Same tool sequence",
  [PATTERN_DIMENSIONS.SHIFT_NOT_LANDING]: "Sessions not landing a shift",
  [PATTERN_DIMENSIONS.SAME_DISTORTION]: "Same thinking distortion",
  [PATTERN_DIMENSIONS.SAME_REFRAME_CONTEXT]: "Same Reframe context"
};

// Find or create an active pattern detection record for a given dimension/value
// pair. If a record exists in CLOSED state, do NOT re-open — fresh accrual of
// 3 new data points opens a new instance per spec §3.2 ("two-strikes-and-drop").
// Returns the upserted record.
const upsertPatternDetection = (detection) => {
  if (!detection || !detection.dimension || !detection.value) return null;
  try {
    const existing = getPatternDetectionsFromStorage();
    // Look for an open instance (not CLOSED) matching dimension + value.
    const openIdx = existing.findIndex(d =>
      d.dimension === detection.dimension &&
      d.value === detection.value &&
      d.state !== PATTERN_STATES.CLOSED
    );
    if (openIdx >= 0) {
      // Update count + dataPoints; preserve state machine + history.
      const updated = {
        ...existing[openIdx],
        count: detection.count,
        dataPoints: detection.dataPoints,
        lastSeenAt: new Date().toISOString()
      };
      const next = [...existing];
      next[openIdx] = updated;
      writePatternDetections(next);
      return updated;
    }
    // New instance.
    const record = {
      id: `pd_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`,
      dimension: detection.dimension,
      value: detection.value,
      count: detection.count,
      dataPoints: detection.dataPoints,
      state: PATTERN_STATES.ACTIVE,
      surfacedAt: null,
      dismissedAt: [],
      acceptedAt: null,
      createdAt: new Date().toISOString(),
      lastSeenAt: new Date().toISOString()
    };
    writePatternDetections([...existing, record]);
    return record;
  } catch { return null; }
};

const markPatternSurfaced = (id) => {
  try {
    const existing = getPatternDetectionsFromStorage();
    const idx = existing.findIndex(d => d.id === id);
    if (idx < 0) return null;
    const updated = { ...existing[idx], surfacedAt: existing[idx].surfacedAt || new Date().toISOString() };
    const next = [...existing];
    next[idx] = updated;
    writePatternDetections(next);
    return updated;
  } catch { return null; }
};

const markPatternDismissed = (id) => {
  try {
    const existing = getPatternDetectionsFromStorage();
    const idx = existing.findIndex(d => d.id === id);
    if (idx < 0) return null;
    const record = existing[idx];
    const dismissedAt = [...(record.dismissedAt || []), new Date().toISOString()];
    // Two strikes → close the pattern instance per spec §3.2.
    const newState = dismissedAt.length >= 2
      ? PATTERN_STATES.CLOSED
      : PATTERN_STATES.DISMISSED_ONCE;
    const updated = { ...record, dismissedAt, state: newState };
    const next = [...existing];
    next[idx] = updated;
    writePatternDetections(next);
    return updated;
  } catch { return null; }
};

const markPatternAccepted = (id) => {
  try {
    const existing = getPatternDetectionsFromStorage();
    const idx = existing.findIndex(d => d.id === id);
    if (idx < 0) return null;
    const updated = { ...existing[idx], acceptedAt: new Date().toISOString(), state: PATTERN_STATES.ACCEPTED };
    const next = [...existing];
    next[idx] = updated;
    writePatternDetections(next);
    return updated;
  } catch { return null; }
};

// Returns an active or dismissed-once pattern detection ready to surface.
// Used by the in-app prompt to decide whether to render. Honors the
// re-fire window per spec §3.2 (Q2): if dismissed_once, re-fire on next
// app open same/next day. Beyond that, drop until next surface attempt.
const getActivePatternForSurfacing = () => {
  try {
    const detections = getPatternDetectionsFromStorage();
    // Active first (never surfaced or recently surfaced), then dismissed_once
    // that's eligible for re-fire.
    const active = detections.filter(d => d.state === PATTERN_STATES.ACTIVE);
    if (active.length > 0) {
      // Strongest count first.
      return [...active].sort((a, b) => (b.count || 0) - (a.count || 0))[0];
    }
    const eligibleRefire = detections.filter(d => {
      if (d.state !== PATTERN_STATES.DISMISSED_ONCE) return false;
      const lastDismiss = d.dismissedAt && d.dismissedAt.length > 0
        ? d.dismissedAt[d.dismissedAt.length - 1]
        : null;
      if (!lastDismiss) return false;
      const lastDismissTime = new Date(lastDismiss).getTime();
      if (Number.isNaN(lastDismissTime)) return false;
      // Re-fire allowed if dismissed within the last 48 hours and at least
      // one app open since (caller is the open path itself, so by virtue
      // of being called we're "since dismissal").
      return (Date.now() - lastDismissTime) < (48 * 60 * 60 * 1000);
    });
    if (eligibleRefire.length > 0) {
      return [...eligibleRefire].sort((a, b) => (b.count || 0) - (a.count || 0))[0];
    }
    return null;
  } catch { return null; }
};

// Convenience: run detection + persist any new patterns. Returns the array
// of upserted records so callers can immediately decide whether to surface.
const runPatternDetection = () => {
  try {
    const detected = detectPatternsDeterministic();
    return detected.map(d => upsertPatternDetection(d)).filter(Boolean);
  } catch { return []; }
};

// ─── PATTERN ENRICHMENT (AI-AWARE LAYER) ──────────────────────────────
// Per PATTERN_DISRUPTION_SPEC.md §4 Q4 — AI runs after deterministic
// pre-filter, not on every data point. Enrichment turns the count-based
// signal into observation-mode reasoning ("the closing state isn't moving
// with the practice" instead of "stuck × 3"). Cached on the pattern record
// so re-fires get the cached version without a second AI call.
//
// Always tolerant of failure: server returns heuristic fallback on any AI
// error, and even if the whole call fails, the modal still surfaces with
// count-based copy. AI-down backup case stays working.

const PATTERN_ENRICHMENT_URL = "/.netlify/functions/pattern-enrichment";

// Build the session excerpt context the AI gets. Keeps payload small —
// 6 most recent sessions, only the fields that matter for loop reasoning.
const buildPatternEnrichmentContext = (pattern) => {
  try {
    const sessions = getSessionsFromStorage().slice(-6);
    const sessionExcerpts = sessions.map(s => ({
      timestamp: s.timestamp,
      preState: s.preState || null,
      postState: s.postState || null,
      preRate: typeof s.preRate === "number" ? s.preRate : null,
      postRate: typeof s.postRate === "number" ? s.postRate : null,
      tools: Array.isArray(s.tools) ? s.tools.slice(0, 5) : [],
      bioFilter: s.bioFilter || null
    }));
    let signalProfile = null;
    let biasProfile = null;
    let bioFilter = null;
    try { signalProfile = JSON.parse(localStorage.getItem("stillform_signal_profile") || "null"); } catch {}
    try { biasProfile = JSON.parse(localStorage.getItem("stillform_bias_profile") || "null"); } catch {}
    try { bioFilter = getActiveBioFilter ? getActiveBioFilter() : null; } catch {}
    return {
      dimension: pattern.dimension,
      dimensionLabel: PATTERN_DIMENSION_LABELS[pattern.dimension] || pattern.dimension,
      value: pattern.value,
      count: pattern.count,
      dataPoints: pattern.dataPoints || [],
      sessionExcerpts,
      bioFilter,
      signalProfile,
      biasProfile
    };
  } catch {
    // On any error building context, return a minimal payload — the
    // server-side heuristic fallback handles missing fields gracefully.
    return {
      dimension: pattern.dimension,
      dimensionLabel: PATTERN_DIMENSION_LABELS[pattern.dimension] || pattern.dimension,
      value: pattern.value,
      count: pattern.count
    };
  }
};

// Fire-and-forget enrichment call. Returns a promise that resolves to the
// reasoning string (or null on failure). Caller uses this to update the
// pattern record + surfaced state.
const enrichPatternWithAI = async (pattern) => {
  if (!pattern || !pattern.id) return null;
  try {
    const payload = buildPatternEnrichmentContext(pattern);
    const response = await fetch(PATTERN_ENRICHMENT_URL, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(payload)
    });
    if (!response.ok) return null;
    const data = await response.json();
    if (typeof data?.reasoning !== "string" || data.reasoning.length === 0) return null;
    return {
      reasoning: data.reasoning,
      confidence: typeof data.confidence === "number" ? data.confidence : null,
      fallback: data.fallback || null,
      enrichedAt: new Date().toISOString()
    };
  } catch { return null; }
};

// Persist enrichment result on the pattern detection record. Idempotent —
// re-running enrichment for the same pattern overwrites prior reasoning.
const updatePatternReasoning = (id, enrichment) => {
  if (!id || !enrichment) return null;
  try {
    const existing = getPatternDetectionsFromStorage();
    const idx = existing.findIndex(d => d.id === id);
    if (idx < 0) return null;
    const updated = {
      ...existing[idx],
      aiReasoning: enrichment.reasoning,
      aiConfidence: enrichment.confidence,
      aiFallback: enrichment.fallback,
      aiEnrichedAt: enrichment.enrichedAt
    };
    const next = [...existing];
    next[idx] = updated;
    writePatternDetections(next);
    return updated;
  } catch { return null; }
};

// ─── BODY SCAN TENSION DATA HELPERS — Phase 0 for My Progress redesign ────
// Per master todo Surface refinements line 145 ("Body Scan tension data →
// My Progress surface"). These read-only helpers normalize the two tension
// data sources (morning check-in + post-Body-Scan session record) into
// shapes that the My Progress redesign can consume directly.
//
// Storage shapes (already shipped, just being surfaced here):
//   stillform_checkin_history: [{ timestamp, energy, bio, tension: { areaName: 1-5 } }]
//   stillform_sessions: [{ timestamp, tools: [...], bodyScanTension: { areaName: 1-5 } | null }]
//
// Area name canonical values (from Body Scan areas array, line ~4939):
//   "Jaw & Face", "Shoulders & Neck", "Chest & Breath", "Hands & Arms",
//   "Gut & Core", "Legs & Feet"
//
// Morning check-in uses lowercase area keys in some user paths; helpers
// normalize to lowercase for matching across sources. Display surface
// can re-cap.
const BODY_SCAN_AREAS = Object.freeze([
  "Jaw & Face", "Shoulders & Neck", "Chest & Breath",
  "Hands & Arms", "Gut & Core", "Legs & Feet"
]);

const normalizeAreaKey = (k) => String(k || "").trim().toLowerCase();

// Get all morning check-in records that have tension data, sorted oldest-first.
// Returns [] if none. Each record: { date, tension: { areaName: 1-5 } }.
const getMorningTensionHistory = () => {
  try {
    const raw = secureRead("stillform_checkin_history", []);
    if (!Array.isArray(raw)) return [];
    return raw
      .filter(c => c?.tension && Object.keys(c.tension).length > 0)
      .map(c => ({
        timestamp: c.timestamp || c.date || null,
        date: c.date || (c.timestamp ? c.timestamp.slice(0, 10) : null),
        energy: c.energy || null,
        tension: c.tension
      }))
      .sort((a, b) => {
        const at = new Date(a.timestamp || a.date || 0).getTime();
        const bt = new Date(b.timestamp || b.date || 0).getTime();
        return at - bt;
      });
  } catch { return []; }
};

// Get all body scan sessions that captured post-practice tension, oldest-first.
// Returns [] if none. Each record: { timestamp, bodyScanTension: { areaName: 1-5 } }.
// Excludes low-demand sessions where tension input was skipped (tensionDataCaptured: false).
const getBodyScanTensionHistory = () => {
  try {
    const raw = secureRead("stillform_sessions", []);
    if (!Array.isArray(raw)) return [];
    return raw
      .filter(s => Array.isArray(s?.tools) && s.tools.includes("body-scan"))
      .filter(s => s?.bodyScanTension && Object.keys(s.bodyScanTension).length > 0)
      .map(s => ({
        timestamp: s.timestamp || null,
        bodyScanTension: s.bodyScanTension,
        durationFormatted: s.durationFormatted || null
      }))
      .sort((a, b) => new Date(a.timestamp || 0).getTime() - new Date(b.timestamp || 0).getTime());
  } catch { return []; }
};

// Get the latest tension level for each area across the most recent N records
// of a chosen source. Source: "morning" or "scan". Returns { areaName: 1-5 }
// using the most recent reading per area within the window.
const getLatestTensionByArea = (source = "morning", limit = 5) => {
  try {
    const records = source === "scan"
      ? getBodyScanTensionHistory()
      : getMorningTensionHistory();
    const recent = records.slice(-limit);
    const latest = {};
    recent.forEach(r => {
      const data = source === "scan" ? r.bodyScanTension : r.tension;
      Object.entries(data || {}).forEach(([area, level]) => {
        if (level > 0) latest[area] = level; // last write wins (chronological order preserved)
      });
    });
    return latest;
  } catch { return {}; }
};

// Get tension trend per area across the last N records of a source.
// Returns { areaName: { first, latest, delta, recordCount } } or null per area
// when there's only one or zero readings for that area in the window.
const getTensionTrend = (source = "morning", limit = 14) => {
  try {
    const records = source === "scan"
      ? getBodyScanTensionHistory()
      : getMorningTensionHistory();
    const recent = records.slice(-limit);
    if (recent.length < 2) return {};

    // Group readings by area
    const perArea = {};
    recent.forEach(r => {
      const data = source === "scan" ? r.bodyScanTension : r.tension;
      Object.entries(data || {}).forEach(([area, level]) => {
        if (level > 0) {
          if (!perArea[area]) perArea[area] = [];
          perArea[area].push({ ts: r.timestamp || r.date || null, level });
        }
      });
    });

    const trend = {};
    Object.entries(perArea).forEach(([area, readings]) => {
      if (readings.length < 2) return;
      const first = readings[0];
      const latest = readings[readings.length - 1];
      trend[area] = {
        first: first.level,
        latest: latest.level,
        delta: latest.level - first.level, // negative = improvement, positive = worsening
        recordCount: readings.length
      };
    });
    return trend;
  } catch { return {}; }
};

// Get morning→scan delta on the same Stillform day. The strongest signal
// Stillform has for proving practice works: tension before vs after a body
// scan, on the same day. Returns array of { date, area, before, after, delta }
// or [] if no same-day pairs exist. delta is post - pre; negative = better.
const getMorningToScanDelta = (limitDays = 30) => {
  try {
    const morning = getMorningTensionHistory();
    const scans = getBodyScanTensionHistory();

    // Index morning by Stillform-day (uses date if available, else timestamp prefix)
    const morningByDay = {};
    morning.forEach(m => {
      const day = m.date || (m.timestamp ? String(m.timestamp).slice(0, 10) : null);
      if (day) morningByDay[day] = m.tension;
    });

    // For each body scan, find same-day morning tension and compute delta per area
    const pairs = [];
    scans.forEach(s => {
      const day = s.timestamp ? String(s.timestamp).slice(0, 10) : null;
      if (!day) return;
      const morningTension = morningByDay[day];
      if (!morningTension) return;
      Object.entries(s.bodyScanTension || {}).forEach(([area, after]) => {
        const before = morningTension[area];
        if (typeof before === "number" && before > 0 && typeof after === "number") {
          pairs.push({ date: day, area, before, after, delta: after - before });
        }
      });
    });

    // Cap at limitDays of same-day pairs (sorted by date desc)
    pairs.sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
    return pairs.slice(0, limitDays * BODY_SCAN_AREAS.length); // generous cap per area
  } catch { return []; }
};

// ─── EOD HISTORY HELPERS — Phase 0 for My Progress redesign ────────────
// EOD records capture: { date, timestamp, energy, composure, word, morningEnergy }
// where:
//   energy:        eod-end-of-day energy reading ("low" | "same" | "high" etc)
//   composure:     self-rated composure that day ("strong" | "mostly" | "rough")
//   word:          optional one-word reflection from user
//   morningEnergy: snapshot of that morning's energy for pre/post compare
//
// Persistence gap fixed May 6, 2026: trackEodComplete now passes the full
// record (was only passing { date, timestamp, composure } before, dropping
// energy, word, and morningEnergy from history). Records before that fix
// will only have the partial shape; helpers handle missing fields gracefully.

// Get all EOD records sorted oldest-first.
const getEodHistory = () => {
  try {
    const raw = JSON.parse(localStorage.getItem("stillform_eod_history") || "[]");
    if (!Array.isArray(raw)) return [];
    return raw
      .map(c => ({
        timestamp: c.timestamp || null,
        date: c.date || null,
        energy: c.energy || null,
        composure: c.composure || null,
        word: c.word || null,
        morningEnergy: c.morningEnergy || null
      }))
      .sort((a, b) => {
        const at = new Date(a.timestamp || a.date || 0).getTime();
        const bt = new Date(b.timestamp || b.date || 0).getTime();
        return at - bt;
      });
  } catch { return []; }
};

// Composure trend across last N EOD records. Returns { strong, mostly, rough,
// total, ratio: { strong: 0-1, mostly: 0-1, rough: 0-1 } } or null if no records.
const getComposureTrend = (limit = 14) => {
  try {
    const recent = getEodHistory().slice(-limit).filter(r => r.composure);
    if (recent.length === 0) return null;
    const counts = { strong: 0, mostly: 0, rough: 0 };
    recent.forEach(r => {
      if (counts[r.composure] !== undefined) counts[r.composure]++;
    });
    const total = recent.length;
    return {
      ...counts,
      total,
      ratio: {
        strong: total > 0 ? counts.strong / total : 0,
        mostly: total > 0 ? counts.mostly / total : 0,
        rough: total > 0 ? counts.rough / total : 0
      }
    };
  } catch { return null; }
};

// Energy delta morning→evening across same-day pairs. Captures whether
// energy *recovered* (morning low → evening high) or *drained* (morning
// high → evening low) on each day. Returns array of { date, morning, evening }
// for each day where both readings exist.
const getEnergyArc = (limitDays = 30) => {
  try {
    const eod = getEodHistory().slice(-limitDays);
    return eod
      .filter(r => r.energy && r.morningEnergy)
      .map(r => ({
        date: r.date,
        morning: r.morningEnergy,
        evening: r.energy
      }))
      .sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  } catch { return []; }
};

// Get all words from EOD reflections (for word-cloud or trend display).
// Returns array of { date, word } or empty if no word reflections exist.
const getEodReflections = (limit = 30) => {
  try {
    return getEodHistory()
      .filter(r => r.word && String(r.word).trim().length > 0)
      .slice(-limit)
      .map(r => ({ date: r.date, word: String(r.word).trim() }))
      .reverse(); // newest first for surfacing
  } catch { return []; }
};

// ─── SAVED REFRAMES INVENTORY HELPERS — Phase 0 for My Progress redesign ───
// Saved reframes record: { text, distortion, timestamp, mode } where mode is
// "calm" | "clarity" | "hype". Stored in stillform_saved_reframes (encrypted).
//
// These helpers normalize the inventory for surfacing in My Progress without
// requiring the screen to know the storage key or shape.

// Get all saved reframes, newest-first (typical surfacing order).
const getSavedReframes = (limit = 50) => {
  try {
    const raw = secureRead("stillform_saved_reframes", []);
    if (!Array.isArray(raw)) return [];
    return [...raw]
      .sort((a, b) => new Date(b.timestamp || 0).getTime() - new Date(a.timestamp || 0).getTime())
      .slice(0, limit);
  } catch { return []; }
};

// Count saved reframes by mode. Returns { calm, clarity, hype, total }.
// Useful for surfacing "you've saved 7 calm reframes, 2 hype" patterns.
const getSavedReframeCounts = () => {
  try {
    const raw = secureRead("stillform_saved_reframes", []);
    if (!Array.isArray(raw)) return { calm: 0, clarity: 0, hype: 0, total: 0 };
    const counts = { calm: 0, clarity: 0, hype: 0, total: raw.length };
    raw.forEach(r => {
      const mode = String(r.mode || "").toLowerCase();
      if (counts[mode] !== undefined) counts[mode]++;
    });
    return counts;
  } catch { return { calm: 0, clarity: 0, hype: 0, total: 0 }; }
};

// Distortion frequency across saved reframes. Returns { distortion: count }
// sorted by count descending. Useful for surfacing user's most-recurring
// thinking patterns ("you've named catastrophizing 12 times this month").
const getSavedReframeDistortions = (limitDays = 90) => {
  try {
    const raw = secureRead("stillform_saved_reframes", []);
    if (!Array.isArray(raw)) return [];
    const cutoff = TimeKeeper.daysAgoMs(limitDays);
    const counts = {};
    raw
      .filter(r => r.distortion && new Date(r.timestamp || 0).getTime() >= cutoff)
      .forEach(r => {
        const d = String(r.distortion).trim();
        if (d) counts[d] = (counts[d] || 0) + 1;
      });
    return Object.entries(counts)
      .map(([distortion, count]) => ({ distortion, count }))
      .sort((a, b) => b.count - a.count);
  } catch { return []; }
};

// ─── SESSIONS INVENTORY HELPERS — Phase 0 for My Progress ─────────────
// computeStreak, countTodaysSessions, getMostRecentSession already exist
// near line 2350 (added earlier in May 6 home-screen feature commits).
// These are the rollup helpers My Progress will need: week/month windows,
// tool distribution, average session duration.

// Count sessions in the last N stillform-days. Includes today.
// Default 7 = "this week" rolling window.
const countSessionsInDays = (days = 7) => {
  try {
    const cutoff = TimeKeeper.daysAgoMs(days);
    return getSessionsFromStorage().filter(s => {
      const ts = new Date(s.timestamp || 0).getTime();
      return ts >= cutoff;
    }).length;
  } catch { return 0; }
};

// Tool usage distribution across last N days. Returns
// { breathe, scan, reframe, metacognition, ground, total } where each value
// is the count of sessions that included that tool. (Sessions can include
// multiple tools — e.g. breathe + ground.) Default 30 days.
const getToolDistribution = (days = 30) => {
  try {
    const cutoff = TimeKeeper.daysAgoMs(days);
    const sessions = getSessionsFromStorage().filter(s => {
      const ts = new Date(s.timestamp || 0).getTime();
      return ts >= cutoff;
    });
    const counts = { breathe: 0, "body-scan": 0, reframe: 0, metacognition: 0, ground: 0, total: sessions.length };
    sessions.forEach(s => {
      const tools = Array.isArray(s.tools) ? s.tools : [];
      tools.forEach(t => {
        if (counts[t] !== undefined) counts[t]++;
      });
    });
    return counts;
  } catch { return { breathe: 0, "body-scan": 0, reframe: 0, metacognition: 0, ground: 0, total: 0 }; }
};

// Average session duration (in seconds) across last N sessions. Returns null
// if no sessions or no duration data. Used for "your average session is N
// minutes" surface.
const getAverageSessionDuration = (limit = 30) => {
  try {
    const recent = getSessionsFromStorage()
      .filter(s => typeof s.duration === "number" && s.duration > 0)
      .slice(-limit);
    if (!recent.length) return null;
    const total = recent.reduce((sum, s) => sum + s.duration, 0);
    return Math.round(total / recent.length);
  } catch { return null; }
};

// Sessions per stillform-day across last N days. Returns array of
// { date, count } sorted oldest-first. Surfaces practice rhythm — does
// the user practice consistently, in bursts, or sporadically? Default 30.
const getSessionsPerDay = (days = 30) => {
  try {
    const cutoff = TimeKeeper.daysAgoMs(days);
    const sessions = getSessionsFromStorage().filter(s => {
      const ts = new Date(s.timestamp || 0).getTime();
      return ts >= cutoff;
    });
    const byDay = {};
    sessions.forEach(s => {
      const day = TimeKeeper.stillformDayOf(s.timestamp);
      if (day) byDay[day] = (byDay[day] || 0) + 1;
    });
    return Object.entries(byDay)
      .map(([date, count]) => ({ date, count }))
      .sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime());
  } catch { return []; }
};

// ─── FOCUS CHECK HISTORY HELPERS — Phase 0 for My Progress ────────────
// Focus check (Composure Check) records: { timestamp, trials, accuracy,
// inhibition, avgReactionMs, falseAlarms }. 20-record cap (acknowledged
// in master todo as sufficient for trend analysis but capped depth).
//
// Storage: stillform_focus_check_history (encrypted).
//
// These helpers expose the trend My Progress will need to surface:
// recognition speed and inhibition both improving over time is direct
// evidence of the cognitive function the practice trains.

// Get focus check history sorted oldest-first.
const getFocusCheckHistory = () => {
  try {
    const raw = secureRead("stillform_focus_check_history", []);
    if (!Array.isArray(raw)) return [];
    return [...raw].sort((a, b) => {
      const at = new Date(a.timestamp || 0).getTime();
      const bt = new Date(b.timestamp || 0).getTime();
      return at - bt;
    });
  } catch { return []; }
};

// Trend across focus check history. Returns { first, latest, deltaAccuracy,
// deltaInhibition, deltaReactionMs, recordCount } or null if fewer than 2.
// Negative deltaReactionMs = faster (improvement). Positive deltaAccuracy/
// deltaInhibition = improvement. Used for surfacing "your composure check
// reaction time has dropped from X to Y" (the spec language explicitly
// called out as a recognition-through-evidence framing).
const getFocusCheckTrend = (limit = 10) => {
  try {
    const records = getFocusCheckHistory().slice(-limit);
    if (records.length < 2) return null;
    const first = records[0];
    const latest = records[records.length - 1];
    return {
      first,
      latest,
      recordCount: records.length,
      deltaAccuracy: typeof first.accuracy === "number" && typeof latest.accuracy === "number"
        ? latest.accuracy - first.accuracy
        : null,
      deltaInhibition: typeof first.inhibition === "number" && typeof latest.inhibition === "number"
        ? latest.inhibition - first.inhibition
        : null,
      deltaReactionMs: typeof first.avgReactionMs === "number" && typeof latest.avgReactionMs === "number"
        ? latest.avgReactionMs - first.avgReactionMs
        : null
    };
  } catch { return null; }
};

const appendCommunicationEvent = (entry, maxItems = COMMUNICATION_EVENTS_MAX_ITEMS) => {
  if (!entry) return 0;
  const events = readArrayFromStorage(COMMUNICATION_EVENTS_KEY);
  events.push(entry);
  const bounded = events.slice(-maxItems);
  try { secureWrite(COMMUNICATION_EVENTS_KEY, bounded); } catch {}
  return bounded.length;
};

// ═══════════════════════════════════════════════════════════════════════
// ENGAGEMENT ARCHITECTURE — STAGE DEFINITIONS (Phase 0 — May 7, 2026)
// ═══════════════════════════════════════════════════════════════════════
//
// Five-stage developmental architecture for self-mastery through
// metacognition that stabilizes composure. Stages build sequentially —
// each capacity prerequisites the next.
//
// Spec source of truth: STILLFORM_ENGAGEMENT_ARCHITECTURE.md §3.1
// Stage NAMES locked May 7, 2026.
// THRESHOLD VALUES first-pass — tunable post-launch against cohort data.
// Markers attach to existing data sources where shipped; deferred markers
// flagged with status:"deferred" until their data source ships.
//
// What ships in this Phase 0: data layer ONLY. No UI. The Mirror surface
// (home), Achievement micro-credits (close moments), and Roadmap screen
// (My Progress) all consume getCurrentStage() — they ship in subsequent
// phases per STILLFORM_ENGAGEMENT_ARCHITECTURE.md §10 shipping order.
//
// Honest adaptations from spec where data isn't available today:
//   - Stage 1 "autonomous exits" marker requires new instrumentation
//     (no current data trail for "user named state but didn't run a
//     tool"). Marked status:"deferred". Other Stage 1 markers ship.
//   - Stage 1 "active state entry" marker needs bio-filter persisted
//     ON each session entry. Today only the latest bio-filter is in
//     localStorage. Marked status:"deferred" pending instrumentation.
//   - Stage 2 affect-labeling latency + accuracy markers depended on
//     Practice Signals data. Practice Signals reverted entirely on
//     May 7. Marked status:"deferred" until Practice Signals rebuilds.
//   - Stage 3 markers gated on Trigger Profile (Build #2) and
//     Pre-event Brief (Build #7). Until those ship, all Stage 3
//     markers return met:false. By design — sequential build order.
//   - Stage 4 "user-flagged pattern preceding AI detection" requires
//     a new flag in journal/EOD entries. Marked status:"deferred".
//   - Stage 5 "high-load sessions" + "delta on high-load" markers
//     need bio-filter on session entries. Same instrumentation gap
//     as Stage 1 active-state. Marked status:"deferred".
//
// Drift behavior: getCurrentStage() reflects CURRENT capacity. If a
// user's data regresses (stops body-area chips, falls below check-in
// frequency, etc.), highestStageMet drops. Honest reflection of present
// state. Stage permanence is not granted; it is maintained.
//
// Stage gating: a stage is fully achieved when ALL its shipped markers
// are met AND no deferred markers gate the stage. If any markers are
// status:"deferred", the stage cannot be fully crossed yet — by design.
// Display surfaces should show deferred markers as "system still
// building" rather than as failures by the user.

// — TUNABLE THRESHOLDS — sign-off pending; first-pass values from spec —
const STAGE_THRESHOLDS = Object.freeze({
  // Stage 1 — NOTICING
  S1_BODY_AREA_SESSIONS_MIN: 5,
  S1_BODY_AREA_WINDOW_DAYS: 90,

  // Stage 2 — NAMING
  S2_DISTINCT_CHIPS_MIN: 5,
  S2_DISTINCT_CHIPS_WINDOW_DAYS: 30,
  S2_CHECKINS_PER_WEEK_MIN: 2,
  S2_CHECKINS_SUSTAINED_WEEKS: 2,

  // Stage 3 — ANTICIPATING (gated on Trigger Profile + Pre-event Brief)
  S3_TRIGGERS_NAMED_MIN: 3,
  S3_PRE_EVENT_BRIEFS_MIN: 1,
  S3_PRE_EVENT_WINDOW_DAYS: 14,
  S3_DELTA_ON_TRIGGER_SESSIONS_MIN: 1.5,

  // Stage 4 — RECOGNIZING
  S4_PATTERN_ACCEPTANCE_RATE_MIN: 0.5,
  S4_PATTERN_ACCEPTANCE_LOOKBACK: 5,
  S4_SELF_INITIATED_DISRUPTOR_MIN: 1,
  S4_SELF_INITIATED_WINDOW_DAYS: 30,

  // Stage 5 — HOLDING
  S5_HIGH_LOAD_SESSIONS_MIN: 5,
  S5_HIGH_LOAD_WINDOW_DAYS: 60,
  S5_HIGH_LOAD_DELTA_MIN: 2.0,
  S5_RECOVERY_TREND_LOOKBACK_DAYS: 30,
});

// — Marker computation helpers — pure functions, all read-only —

// Helper: count sessions in last N days where bodyScanTension is non-null
// AND specific (between 1 and BODY_SCAN_AREAS.length - 1 areas tagged).
// "Specific" excludes both the no-tap path (null) and the all-areas case
// (which functions as "everywhere" — the opposite of specificity).
const _s1CountSpecificBodyAreaSessions = (windowDays = STAGE_THRESHOLDS.S1_BODY_AREA_WINDOW_DAYS) => {
  try {
    const sessions = getSessionsFromStorage();
    const cutoff = TimeKeeper.daysAgoMs(windowDays);
    return sessions.filter(s => {
      const t = new Date(s.timestamp || 0).getTime();
      if (Number.isNaN(t) || t < cutoff) return false;
      const tension = s.bodyScanTension;
      if (!tension || typeof tension !== "object") return false;
      const areaCount = Object.keys(tension).length;
      // Specific = at least 1 area, fewer than all 6. "All 6" reads as
      // "everywhere" which is the opposite of the noticing-specificity
      // signal Stage 1 is measuring.
      return areaCount >= 1 && areaCount < BODY_SCAN_AREAS.length;
    }).length;
  } catch { return 0; }
};

// Helper: count distinct preState chip values across sessions in last N days.
// Reframe + Body Scan + Breathe sessions all persist preState when the user
// selected a chip at session start.
const _s2CountDistinctChips = (windowDays = STAGE_THRESHOLDS.S2_DISTINCT_CHIPS_WINDOW_DAYS) => {
  try {
    const sessions = getSessionsFromStorage();
    const cutoff = TimeKeeper.daysAgoMs(windowDays);
    const chips = new Set();
    sessions.forEach(s => {
      const t = new Date(s.timestamp || 0).getTime();
      if (Number.isNaN(t) || t < cutoff) return;
      if (s.preState && typeof s.preState === "string") chips.add(s.preState.trim().toLowerCase());
    });
    return chips.size;
  } catch { return 0; }
};

// Helper: compute the longest run of consecutive weeks where the user did
// at least N check-ins per week. Used for Stage 2 sustained-consistency.
// Returns the length of that run in weeks (e.g., 2 means "2+ check-ins per
// week for the last 2 consecutive weeks").
const _s2LongestSustainedCheckinRun = (perWeekMin = STAGE_THRESHOLDS.S2_CHECKINS_PER_WEEK_MIN) => {
  try {
    const raw = JSON.parse(localStorage.getItem("stillform_checkin_history") || "[]");
    if (!Array.isArray(raw) || raw.length === 0) return 0;
    // Group by ISO week (sunday-anchored). Use ISO date string normalized to
    // a week-start key: monday of the week containing the timestamp.
    const weekKey = (ts) => {
      const d = new Date(ts);
      if (Number.isNaN(d.getTime())) return null;
      const day = d.getDay(); // 0=Sun..6=Sat
      const mondayOffset = day === 0 ? -6 : 1 - day;
      const monday = new Date(d);
      monday.setDate(d.getDate() + mondayOffset);
      monday.setHours(0, 0, 0, 0);
      // Use TimeKeeper.clockDayOf to extract local date — never .toISOString().slice
      // (which would silently extract UTC and bleed across timezone boundaries).
      return TimeKeeper.clockDayOf(monday);
    };
    const weekCounts = new Map();
    raw.forEach(r => {
      const k = weekKey(r.timestamp || r.date);
      if (k) weekCounts.set(k, (weekCounts.get(k) || 0) + 1);
    });
    // Sort weeks chronologically and walk for longest consecutive run.
    const weeks = [...weekCounts.keys()].sort();
    let longest = 0, current = 0;
    let prevWeek = null;
    for (const w of weeks) {
      const meets = weekCounts.get(w) >= perWeekMin;
      if (!meets) { current = 0; prevWeek = w; continue; }
      if (prevWeek) {
        const prevDate = new Date(prevWeek);
        const thisDate = new Date(w);
        const diffWeeks = Math.round((thisDate.getTime() - prevDate.getTime()) / (7 * 24 * 60 * 60 * 1000));
        current = diffWeeks === 1 ? current + 1 : 1;
      } else {
        current = 1;
      }
      if (current > longest) longest = current;
      prevWeek = w;
    }
    return longest;
  } catch { return 0; }
};

// Helper: pattern acceptance rate over the last N surfaced patterns.
// "Surfaced" = state ever transitioned out of new (was prompted to user).
// Acceptance = state === ACCEPTED. Dismiss = DISMISSED_ONCE or CLOSED.
const _s4PatternAcceptanceRate = (lookback = STAGE_THRESHOLDS.S4_PATTERN_ACCEPTANCE_LOOKBACK) => {
  try {
    const detections = getPatternDetectionsFromStorage();
    if (!Array.isArray(detections) || detections.length === 0) return { rate: 0, count: 0 };
    // Most recent surfaced detections — those with state past initial.
    const surfaced = detections
      .filter(d => d && d.state && d.state !== "active" || (d && d.surfacedAt))
      .slice(-lookback);
    if (surfaced.length === 0) return { rate: 0, count: 0 };
    const accepted = surfaced.filter(d => d.state === PATTERN_STATES.ACCEPTED).length;
    return { rate: accepted / surfaced.length, count: surfaced.length };
  } catch { return { rate: 0, count: 0 }; }
};

// Helper: count Disruptor sessions launched WITHOUT a prompted pattern
// (patternId === null means user hit Disruptor self-initiated).
const _s4SelfInitiatedDisruptorCount = (windowDays = STAGE_THRESHOLDS.S4_SELF_INITIATED_WINDOW_DAYS) => {
  try {
    const sessions = getDisruptorSessionsFromStorage();
    if (!Array.isArray(sessions)) return 0;
    const cutoff = TimeKeeper.daysAgoMs(windowDays);
    return sessions.filter(s => {
      if (!s || s.patternId) return false;
      const t = new Date(s.timestamp || 0).getTime();
      return !Number.isNaN(t) && t >= cutoff;
    }).length;
  } catch { return 0; }
};

// Helper: recovery trend — does pre→post delta improve over time on
// sessions where the user has rated both pre and post? Stage 5 marker
// for "recovery time trending downward." Operationalized as "average
// delta in last half of window > average delta in first half" — improving.
const _s5RecoveryTrendImproving = (lookbackDays = STAGE_THRESHOLDS.S5_RECOVERY_TREND_LOOKBACK_DAYS) => {
  try {
    const sessions = getSessionsFromStorage();
    const cutoff = TimeKeeper.daysAgoMs(lookbackDays);
    const rated = sessions
      .filter(s => {
        const t = new Date(s.timestamp || 0).getTime();
        if (Number.isNaN(t) || t < cutoff) return false;
        return typeof s.preRate === "number" && typeof s.postRate === "number";
      })
      .sort((a, b) => new Date(a.timestamp || 0).getTime() - new Date(b.timestamp || 0).getTime());
    if (rated.length < 4) return null; // not enough data
    const half = Math.floor(rated.length / 2);
    const firstHalf = rated.slice(0, half);
    const secondHalf = rated.slice(half);
    const avgDelta = arr => arr.reduce((sum, s) => sum + (s.postRate - s.preRate), 0) / arr.length;
    const firstAvg = avgDelta(firstHalf);
    const secondAvg = avgDelta(secondHalf);
    return { improving: secondAvg > firstAvg, firstAvg, secondAvg };
  } catch { return null; }
};

// — Stage definitions — names locked May 7, 2026 —
const STAGE_DEFINITIONS = Object.freeze({
  1: Object.freeze({
    id: 1,
    name: "NOTICING",
    capacity: "catching what's happening in your body before thought",
    science: ["Farb 2015 (interoceptive awareness)", "van der Kolk 2014", "Porges polyvagal theory"],
  }),
  2: Object.freeze({
    id: 2,
    name: "NAMING",
    capacity: "language for what's present, fast and accurate",
    science: ["Lieberman 2007 (affect labeling reduces amygdala activity)", "Barrett 2017 (emotional granularity)"],
  }),
  3: Object.freeze({
    id: 3,
    name: "ANTICIPATING",
    capacity: "pre-loading composure for known triggers",
    science: ["Gollwitzer 1999 (implementation intentions)", "Meichenbaum stress inoculation", "Gross 1998 (antecedent-focused regulation)"],
  }),
  4: Object.freeze({
    id: 4,
    name: "RECOGNIZING",
    capacity: "seeing your own loops as they form",
    science: ["Wells 2009 (Metacognitive Therapy)", "Kross 2014 (self-distancing)", "Kabat-Zinn (decentering)"],
  }),
  5: Object.freeze({
    id: 5,
    name: "HOLDING",
    capacity: "composure under maximum load",
    science: ["Meichenbaum stress inoculation outcomes", "McEwen allostatic load", "Porges vagal tone"],
  }),
});

// computeStageMarkers(stageId) → array of marker results.
// Each marker: { id, label, value, threshold, met, status, deferReason? }
// status: "shipped" (data source live, met reflects reality) or
//         "deferred" (data source not yet live; met:false by definition).
const computeStageMarkers = (stageId) => {
  if (stageId === 1) {
    const bioFilterSet = (() => { try { return !!localStorage.getItem("stillform_bio_filter"); } catch { return false; } })();
    const specificSessionsCount = _s1CountSpecificBodyAreaSessions();
    return [
      { id: "bio-filter-setup", label: "Bio-filter setup completed", value: bioFilterSet, threshold: true, met: bioFilterSet, status: "shipped" },
      { id: "body-area-specificity", label: "Sessions with specific body-area tags", value: specificSessionsCount, threshold: STAGE_THRESHOLDS.S1_BODY_AREA_SESSIONS_MIN, met: specificSessionsCount >= STAGE_THRESHOLDS.S1_BODY_AREA_SESSIONS_MIN, status: "shipped" },
      { id: "active-state-entry", label: "Sessions entered during an active state", value: 0, threshold: 1, met: false, status: "deferred", deferReason: "bio-filter not persisted on session entries; instrumentation pending" },
      { id: "autonomous-exits", label: "Times you saw it and chose without a tool", value: 0, threshold: 1, met: false, status: "deferred", deferReason: "no data trail for chip-without-tool today; instrumentation pending" },
    ];
  }
  if (stageId === 2) {
    const distinctChips = _s2CountDistinctChips();
    const sustainedWeeks = _s2LongestSustainedCheckinRun();
    return [
      { id: "distinct-chips", label: "Different feel-state chips used in last 30 days", value: distinctChips, threshold: STAGE_THRESHOLDS.S2_DISTINCT_CHIPS_MIN, met: distinctChips >= STAGE_THRESHOLDS.S2_DISTINCT_CHIPS_MIN, status: "shipped" },
      { id: "checkin-consistency", label: "Consecutive weeks with 2+ check-ins", value: sustainedWeeks, threshold: STAGE_THRESHOLDS.S2_CHECKINS_SUSTAINED_WEEKS, met: sustainedWeeks >= STAGE_THRESHOLDS.S2_CHECKINS_SUSTAINED_WEEKS, status: "shipped" },
      { id: "affect-label-latency", label: "Median affect-labeling latency", value: null, threshold: 4000, met: false, status: "deferred", deferReason: "Practice Signals reverted May 7; rebuild pending" },
      { id: "affect-label-accuracy", label: "Affect-labeling accuracy", value: null, threshold: 0.6, met: false, status: "deferred", deferReason: "Practice Signals reverted May 7; rebuild pending" },
    ];
  }
  if (stageId === 3) {
    return [
      { id: "triggers-named", label: "Triggers named in your profile", value: 0, threshold: STAGE_THRESHOLDS.S3_TRIGGERS_NAMED_MIN, met: false, status: "deferred", deferReason: "Trigger Profile not yet shipped (Build #2 in spec shipping order)" },
      { id: "pre-event-briefs", label: "Pre-event Briefs used in last 14 days", value: 0, threshold: STAGE_THRESHOLDS.S3_PRE_EVENT_BRIEFS_MIN, met: false, status: "deferred", deferReason: "Pre-event Brief not yet shipped (Build #7 in spec shipping order)" },
      { id: "trigger-session-delta", label: "Pre-to-post rate delta on named-trigger sessions", value: 0, threshold: STAGE_THRESHOLDS.S3_DELTA_ON_TRIGGER_SESSIONS_MIN, met: false, status: "deferred", deferReason: "Trigger tagging on sessions requires Trigger Profile" },
    ];
  }
  if (stageId === 4) {
    const acceptance = _s4PatternAcceptanceRate();
    const selfInitiated = _s4SelfInitiatedDisruptorCount();
    return [
      { id: "pattern-acceptance-rate", label: "Pattern Disruption acceptance rate over last 5 surfaced", value: acceptance.count >= 3 ? acceptance.rate : null, threshold: STAGE_THRESHOLDS.S4_PATTERN_ACCEPTANCE_RATE_MIN, met: acceptance.count >= 3 && acceptance.rate >= STAGE_THRESHOLDS.S4_PATTERN_ACCEPTANCE_RATE_MIN, status: "shipped" },
      { id: "self-initiated-disruptor", label: "Self-initiated Disruptor sessions in last 30 days", value: selfInitiated, threshold: STAGE_THRESHOLDS.S4_SELF_INITIATED_DISRUPTOR_MIN, met: selfInitiated >= STAGE_THRESHOLDS.S4_SELF_INITIATED_DISRUPTOR_MIN, status: "shipped" },
      { id: "user-flagged-pattern", label: "Self-flagged patterns preceding system detection", value: 0, threshold: 1, met: false, status: "deferred", deferReason: "user-flag instrumentation in journal/EOD pending" },
    ];
  }
  if (stageId === 5) {
    const recovery = _s5RecoveryTrendImproving();
    return [
      { id: "high-load-sessions", label: "Sessions completed under high-load hardware", value: 0, threshold: STAGE_THRESHOLDS.S5_HIGH_LOAD_SESSIONS_MIN, met: false, status: "deferred", deferReason: "bio-filter not persisted on session entries; same instrumentation gap as Stage 1 active-state" },
      { id: "high-load-delta", label: "Pre-to-post delta on high-load sessions", value: 0, threshold: STAGE_THRESHOLDS.S5_HIGH_LOAD_DELTA_MIN, met: false, status: "deferred", deferReason: "bio-filter not persisted on session entries" },
      { id: "recovery-trend", label: "Recovery trending in the right direction", value: recovery ? recovery.improving : null, threshold: true, met: !!(recovery && recovery.improving), status: "shipped" },
    ];
  }
  return [];
};

// getCurrentStage() → snapshot of where the user is in the architecture.
// Returns:
//   { currentStageId, highestStageMet, stage, markers, progress, nextStage }
//   - currentStageId: stage user is currently working toward (1-5).
//   - highestStageMet: highest stage where ALL shipped markers met AND
//     no deferred markers gate it. 0 means no stage fully crossed yet.
//   - stage: full STAGE_DEFINITIONS entry for currentStageId.
//   - markers: computeStageMarkers(currentStageId) — what's in flight.
//   - progress: { metCount, totalCount, percent } for current stage's
//     SHIPPED markers only (deferred ones don't count against progress).
//   - nextStage: STAGE_DEFINITIONS[currentStageId + 1] or null at top.
const getCurrentStage = () => {
  let highestStageMet = 0;
  for (let id = 1; id <= 5; id++) {
    const markers = computeStageMarkers(id);
    const hasDeferred = markers.some(m => m.status === "deferred");
    const allShippedMet = markers.filter(m => m.status === "shipped").every(m => m.met);
    if (!hasDeferred && allShippedMet && markers.length > 0) {
      highestStageMet = id;
    } else {
      break; // sequential — must cross each stage before the next
    }
  }
  const currentStageId = highestStageMet === 5 ? 5 : Math.min(5, highestStageMet + 1);
  const stage = STAGE_DEFINITIONS[currentStageId];
  const markers = computeStageMarkers(currentStageId);
  const shippedMarkers = markers.filter(m => m.status === "shipped");
  const metCount = shippedMarkers.filter(m => m.met).length;
  const totalCount = shippedMarkers.length;
  const percent = totalCount > 0 ? Math.round((metCount / totalCount) * 100) : 0;
  const nextStage = currentStageId < 5 ? STAGE_DEFINITIONS[currentStageId + 1] : null;
  return {
    currentStageId,
    highestStageMet,
    stage,
    markers,
    progress: { metCount, totalCount, percent },
    nextStage,
  };
};

// ─── ACHIEVEMENT MICRO-CREDITS — engagement architecture Build #5 ──────
//
// Per STILLFORM_ENGAGEMENT_ARCHITECTURE.md §3.1: ONE specific number per
// meaningful close, picked by relevance. Embedded in the moment. The
// credit IS the close. NOT a dashboard.
//
// Phase 1 of this build ships Body Scan only. Reframe + Breathe + EOD
// integrations follow in subsequent builds (each independently shippable).
//
// Anti-pattern guards from spec §2:
//   - No "ACHIEVEMENT" label (sounds gamified). Use "PRACTICE TREND."
//   - No streaks, badges, or count-up dopamine.
//   - No "you missed X" failure framing — return null on sparse data
//     instead of saying "no data."
//   - Operator-tier voice. No therapy-coded language.
//
// Returns: { headline, context } | null
//   - headline: glanceable specific number (e.g., "Jaw 4 → 2")
//   - context: optional trend statement (e.g., "Down from 4.1 average")
//   - null when data is too sparse for an honest credit. Better silence
//     than fabricated proof.

const computeAchievementForBodyScan = (sessionEntry) => {
  if (!sessionEntry?.bodyScanTension) return null;
  const tensionEntries = Object.entries(sessionEntry.bodyScanTension);
  if (tensionEntries.length === 0) return null;

  // Primary area = highest tension reported in this session — the area
  // the user MOST noticed. That's the area whose change is most relevant.
  const sorted = [...tensionEntries].sort((a, b) => b[1] - a[1]);
  const [primaryArea, primaryLevel] = sorted[0];
  if (typeof primaryLevel !== "number") return null;

  // Look for same-day morning tension reading in this area for headline delta.
  // Source-of-truth verification (audit philosophy v1.3 Layer 2.37):
  //   getMorningTensionHistory at line ~3037 returns { timestamp, date, energy, tension }.
  //   The tension data lives at the `tension` field — NOT `tensionByArea`.
  // The original v1.0 of this code read `sameDay.tensionByArea` which was
  // always undefined → morning-delta line never fired in production.
  // Fixed in v1.3 audit pass.
  let morningLevel = null;
  try {
    const morningHistory = getMorningTensionHistory();
    const today = TimeKeeper.stillformDay();
    const sameDay = morningHistory.find(h => h.date === today);
    if (sameDay?.tension) {
      const matchKey = Object.keys(sameDay.tension).find(
        k => k.toLowerCase() === primaryArea.toLowerCase()
      );
      if (matchKey && typeof sameDay.tension[matchKey] === "number") {
        morningLevel = sameDay.tension[matchKey];
      }
    }
  } catch {}

  // Average tension in this area across last 14 days of body-scan sessions.
  // Source-of-truth verification (audit philosophy v1.3 Layer 2.37):
  //   getBodyScanTensionHistory at line ~3060 returns { timestamp, bodyScanTension, durationFormatted }.
  //   The tension-by-area map lives at the `bodyScanTension` field — NOT `tensionByArea`.
  // The original v1.0 of this code read `h.tensionByArea` which was always
  // undefined → readings array always empty → trend-context line never
  // fired in production. Fixed in v1.3 audit pass.
  // Excludes the current session if it's already saved (the sort below leaves
  // most-recent at the end; we slice off the latest entry to avoid
  // self-referential trend).
  let avgPriorTension = null;
  let priorCount = 0;
  try {
    const scanHistory = getBodyScanTensionHistory();
    const recent = scanHistory.slice(-15, -1); // last 14 PRIOR sessions, excluding current
    const readings = recent
      .map(h => {
        if (!h.bodyScanTension) return null;
        const matchKey = Object.keys(h.bodyScanTension).find(
          k => k.toLowerCase() === primaryArea.toLowerCase()
        );
        return matchKey && typeof h.bodyScanTension[matchKey] === "number"
          ? h.bodyScanTension[matchKey]
          : null;
      })
      .filter(v => v !== null);
    priorCount = readings.length;
    if (readings.length >= 3) {
      avgPriorTension = readings.reduce((a, b) => a + b, 0) / readings.length;
    }
  } catch {}

  // Build headline — use morning→post delta when available (most informative),
  // otherwise just current level.
  const headline = morningLevel !== null && morningLevel > primaryLevel
    ? `${primaryArea}: ${morningLevel} → ${primaryLevel}`
    : `${primaryArea}: ${primaryLevel}`;

  // Build context — only when there's enough history to be meaningful.
  // Better to omit than fabricate.
  let context = null;
  if (avgPriorTension !== null) {
    const delta = primaryLevel - avgPriorTension;
    if (delta < -0.3) {
      context = `Down from ${avgPriorTension.toFixed(1)} average across last ${priorCount} sessions.`;
    } else if (delta > 0.3) {
      context = `Above your ${avgPriorTension.toFixed(1)} average — system noticing.`;
    } else {
      context = `Holding near your ${avgPriorTension.toFixed(1)} average.`;
    }
  }
  // Sparse-data path: no context line (returns null instead of fabricated text).
  // Headline alone is still a real reading.

  return { headline, context };
};

// computeAchievement(sessionEntry) → { headline, context } | null
// Dispatches to the right per-tool computer based on session entry shape.
// Phase 1: Body Scan only. Other tools return null until their handlers
// ship in subsequent builds.
const computeAchievementForReframe = (sessionEntry) => {
  if (!sessionEntry) return null;
  const tools = Array.isArray(sessionEntry.tools) ? sessionEntry.tools : [];
  if (!tools.includes("reframe")) return null;

  const { preState, postState, delta } = sessionEntry;

  // No post-state means user skipped the rating — no honest credit to claim.
  // Don't fabricate a headline; this is the "better silence" path.
  if (!preState || !postState) return null;

  // Build headline. Same chip = "held the state" (still real work, often
  // harder than transitioning). Different chips = the transition itself.
  // Append delta when meaningful (positive shift in numeric score).
  let headline;
  if (preState === postState) {
    headline = `Held ${preState}`;
  } else {
    headline = `${preState} → ${postState}`;
  }
  if (typeof delta === "number" && delta > 0) {
    headline = `${headline} · +${delta}`;
  }

  // Context — frequency of this exact pre→post pattern in the last 7 days.
  // Counts the user's own repeated patterns of regulation. Heider 1958
  // attribution: when users repeat the same shift, Stillform names it as
  // a pattern they own. Only surfaces when there's at least one prior
  // similar shift this week (otherwise no context line — fabricated
  // "1st time" framing rings as "you've never done this before" which
  // is a hostile read).
  let context = null;
  try {
    const sessions = getSessionsFromStorage();
    const weekAgo = TimeKeeper.daysAgoMs(7);
    const currentTs = sessionEntry.timestamp || null;
    const similar = sessions.filter(s => {
      if (!s) return false;
      const t = new Date(s.timestamp || 0).getTime();
      if (Number.isNaN(t) || t < weekAgo) return false;
      // Exclude the current session if it's already persisted (post-save call).
      // Live (pre-save) calls have currentTs === null, so no exclusion needed.
      if (currentTs && s.timestamp === currentTs) return false;
      return s.preState === preState && s.postState === postState;
    });
    if (similar.length >= 1) {
      const total = similar.length + 1; // include current
      const ordinal = total === 2 ? "2nd"
        : total === 3 ? "3rd"
        : total === 21 ? "21st"
        : total === 22 ? "22nd"
        : total === 23 ? "23rd"
        : `${total}th`;
      context = `${ordinal} time this week.`;
    }
  } catch {}

  return { headline, context };
};

const computeAchievement = (sessionEntry) => {
  if (!sessionEntry) return null;
  const tools = Array.isArray(sessionEntry.tools) ? sessionEntry.tools : [];
  if (tools.includes("body-scan")) return computeAchievementForBodyScan(sessionEntry);
  if (tools.includes("reframe")) return computeAchievementForReframe(sessionEntry);
  if (tools.includes("breathe")) return computeAchievementForBreathe(sessionEntry);
  if (tools.includes("eod")) return computeAchievementForEod(sessionEntry);
  return null;
};

// Phase 4 — EOD close composure-frequency claim.
//
// EOD entries have a different shape than tool sessions (no `tools` field
// in storage). Callers construct a synthetic { tools: ["eod"], composure,
// date, timestamp } shape from live state at credit-display time. Same
// pattern as Phase 2 + 3 live-state computation.
//
// Hard guards:
//   - composure must be "solid" or "mixed". Skips "rough" (no failure
//     framing per spec §2 — closing a hard day rough is real work but
//     the credit moment isn't the time to compare; the existing close
//     UI accepts the rating without judgment, this stays silent).
//   - composure === "mostly" returns null. "mostly" is the saveEod
//     fallback when user submits without selecting a chip, AND is a
//     legacy value from the old "Strong/Mostly/Rough" chip schema.
//     Crediting it would fabricate (fallback case) or conflate
//     schemas (legacy case). Cleanest path: silent.
//   - frequency must be >= 2 distinct prior days in last 7 days.
//     First-of-kind is silent (no fabricated "1st time" claim,
//     same precedent as Reframe + Breathe handlers).
//
// Frequency computation dedupes by date — same EOD record can appear
// multiple times in history if user updated their close, but that's
// still ONE day toward the count.
const computeAchievementForEod = (sessionEntry) => {
  if (!sessionEntry) return null;
  const tools = Array.isArray(sessionEntry.tools) ? sessionEntry.tools : [];
  if (!tools.includes("eod")) return null;

  const { composure, date, timestamp } = sessionEntry;
  if (composure !== "solid" && composure !== "mixed") return null;

  // Distinct prior days in last 7 days where composure matched, excluding today.
  let priorMatchingDays = 0;
  try {
    const history = getEodHistory();
    const weekAgoMs = TimeKeeper.daysAgoMs(7);
    const currentDate = date || null;
    const matchingDates = new Set();
    history.forEach(e => {
      if (!e || e.composure !== composure) return;
      if (currentDate && e.date === currentDate) return; // same-day = same EOD
      const t = new Date(e.timestamp || e.date || 0).getTime();
      if (Number.isNaN(t) || t < weekAgoMs) return;
      if (e.date) matchingDates.add(e.date);
    });
    priorMatchingDays = matchingDates.size;
  } catch {}

  const total = priorMatchingDays + 1; // +1 for today (just-saved EOD)
  if (total < 2) return null;

  const ordinal = total === 2 ? "2nd"
    : total === 3 ? "3rd"
    : total === 21 ? "21st"
    : total === 22 ? "22nd"
    : total === 23 ? "23rd"
    : `${total}th`;

  return {
    headline: `${ordinal} ${composure} close this week.`,
    context: null
  };
};

// Phase 3 — Breathe close longitudinal context.
// Different scope from Body Scan / Reframe handlers because Breathe close
// ALREADY has a per-session credit display (48px Cormorant "+N" + tag +
// drift %) at lines ~6148-6171. That display IS the headline. This handler
// only contributes a single context line (frequency of similar +N shifts
// this week), rendered below the existing surface.
//
// Hard guards:
//   - delta must be > 0 (negative-shift sessions show "Holding"/"Run again"
//     in the existing surface; adding longitudinal stat would read as
//     "today didn't work but yesterday did" — spec §2 failure-framing
//     anti-pattern)
//   - frequency must be >= 2 in last 7 days (no fabricated "1st time"
//     framing — would read as "you've never done this before")
//   - Otherwise returns null (silent path)
//
// Returned shape: { headline: null, context: string }
//   - headline is intentionally null because the existing 48px +N is
//     already the headline. JSX renders only the context line.
const computeAchievementForBreathe = (sessionEntry) => {
  if (!sessionEntry) return null;
  const tools = Array.isArray(sessionEntry.tools) ? sessionEntry.tools : [];
  if (!tools.includes("breathe")) return null;

  const { delta, timestamp } = sessionEntry;
  // Strict positive-delta gate. Existing surface handles non-positive
  // cases with appropriate tonal calibration; we don't compete with it.
  if (typeof delta !== "number" || delta <= 0) return null;

  // Count similar +N breathe shifts in last 7 days (excludes self by ts).
  let total = 1; // include current
  try {
    const sessions = getSessionsFromStorage();
    const weekAgo = TimeKeeper.daysAgoMs(7);
    const similar = sessions.filter(s => {
      if (!s) return false;
      const t = new Date(s.timestamp || 0).getTime();
      if (Number.isNaN(t) || t < weekAgo) return false;
      if (timestamp && s.timestamp === timestamp) return false;
      const stools = Array.isArray(s.tools) ? s.tools : [];
      // Match any session that included breathe and had the same delta.
      // breathe+ground combined sessions count too — same physiological
      // shift mechanism per Brown 2005, Balban 2023.
      return stools.includes("breathe") && s.delta === delta;
    });
    total = similar.length + 1;
  } catch {}

  // First instance — silent (no fabricated "1st time" claim).
  if (total < 2) return null;

  const ordinal = total === 2 ? "2nd"
    : total === 3 ? "3rd"
    : total === 21 ? "21st"
    : total === 22 ? "22nd"
    : total === 23 ? "23rd"
    : `${total}th`;

  return {
    headline: null,
    context: `${ordinal} +${delta} shift this week.`
  };
};

// ─── TRIGGER PROFILE — engagement architecture Build #2 Phase 1 ────────
//
// Per STILLFORM_ENGAGEMENT_ARCHITECTURE.md §3.3, Trigger Profile is the
// third diagnostic layer alongside Signal Profile (where intensity
// activates in body) and Bias Profile (cognitive distortions).
//
// CRITICAL DISTINCTION FROM SIGNAL PROFILE TRIGGERS:
// Signal Profile already has a `triggers` field — a chip-picker selecting
// from a predefined 30+ option taxonomy (work pressure, family dynamics,
// sensory overload, etc). That's TYPE-level data: which categories of
// trigger affect this user.
//
// Trigger Profile is INSTANCE-level data: specific named people, contexts,
// kinds of moments. "My boss Mike" not "work pressure." "Mom's Sunday
// dinners" not "family dynamics." "Quarterly OKR reviews" not "deadlines."
//
// Per Heider 1958 attribution theory and Lazarus 1991 cognitive appraisal:
// naming specific external causes binds internal experience to external
// triggers, enabling appraisal-focused regulation. Without instance-level
// attribution, users self-attribute ("I'm just anxious") and miss the
// causal pattern.
//
// PHASE 1 SCOPE: data layer only.
//   - Schema, helpers, AI formatter, SYNC_KEYS membership
//   - NO UI yet (Phase 2)
//   - NO encounter tracking from session content (Phase 3)
//
// Schema:
//   stillform_trigger_profile = {
//     triggers: [
//       { id, label, category, createdAt, lastSeen, encounterCount }
//     ],
//     updatedAt
//   }

const TRIGGER_PROFILE_CATEGORIES = Object.freeze([
  "work",            // power dynamics, deadlines, performance
  "relational",      // specific people, family dynamics
  "financial",       // money pressure, scarcity
  "health",          // medical stress, chronic conditions
  "cross-cultural",  // code-switching, identity navigation
  "current-events",  // news cycles, collective stress
  "other"            // user-defined catch-all
]);

const _generateTriggerId = () => {
  // Best-effort unique id; collision astronomically unlikely
  // for a profile that stays under ~50 triggers (spec's practical ceiling).
  return `trig_${Date.now().toString(36)}_${Math.random().toString(36).slice(2, 8)}`;
};

const _emptyTriggerProfile = () => ({ triggers: [], updatedAt: null });

const getTriggerProfile = () => {
  try {
    const raw = secureRead("stillform_trigger_profile", null);
    if (!raw || typeof raw !== "object") return _emptyTriggerProfile();
    const triggers = Array.isArray(raw.triggers) ? raw.triggers : [];
    return {
      triggers: triggers.filter(t => t && typeof t === "object" && t.id && t.label),
      updatedAt: raw.updatedAt || null
    };
  } catch {
    return _emptyTriggerProfile();
  }
};

const saveTriggerProfile = (profile) => {
  try {
    const safe = {
      triggers: Array.isArray(profile?.triggers) ? profile.triggers : [],
      updatedAt: new Date().toISOString()
    };
    secureWrite("stillform_trigger_profile", safe);
    return safe;
  } catch { return null; }
};

const addTrigger = ({ label, category }) => {
  const trimmed = typeof label === "string" ? label.trim() : "";
  if (!trimmed) return null;
  const validCategory = TRIGGER_PROFILE_CATEGORIES.includes(category) ? category : "other";
  const profile = getTriggerProfile();
  const now = new Date().toISOString();
  // Deduplicate by case-insensitive label match (don't add the same name twice)
  const exists = profile.triggers.find(
    t => t.label.toLowerCase().trim() === trimmed.toLowerCase()
  );
  if (exists) return exists;
  const newTrigger = {
    id: _generateTriggerId(),
    label: trimmed,
    category: validCategory,
    createdAt: now,
    lastSeen: now,
    encounterCount: 0
  };
  profile.triggers.push(newTrigger);
  saveTriggerProfile(profile);
  return newTrigger;
};

const updateTrigger = (id, updates) => {
  if (!id || !updates || typeof updates !== "object") return null;
  const profile = getTriggerProfile();
  const idx = profile.triggers.findIndex(t => t.id === id);
  if (idx === -1) return null;
  const existing = profile.triggers[idx];
  // Whitelist updatable fields. id, createdAt, encounterCount are immutable
  // through this path (encounterCount has its own incrementer).
  const allowed = {};
  if (typeof updates.label === "string" && updates.label.trim()) {
    allowed.label = updates.label.trim();
  }
  if (TRIGGER_PROFILE_CATEGORIES.includes(updates.category)) {
    allowed.category = updates.category;
  }
  const updated = { ...existing, ...allowed };
  profile.triggers[idx] = updated;
  saveTriggerProfile(profile);
  return updated;
};

const deleteTrigger = (id) => {
  if (!id) return false;
  const profile = getTriggerProfile();
  const next = profile.triggers.filter(t => t.id !== id);
  if (next.length === profile.triggers.length) return false;
  profile.triggers = next;
  saveTriggerProfile(profile);
  return true;
};

const incrementTriggerEncounter = (id) => {
  if (!id) return null;
  const profile = getTriggerProfile();
  const idx = profile.triggers.findIndex(t => t.id === id);
  if (idx === -1) return null;
  const existing = profile.triggers[idx];
  const updated = {
    ...existing,
    lastSeen: new Date().toISOString(),
    encounterCount: (existing.encounterCount || 0) + 1
  };
  profile.triggers[idx] = updated;
  saveTriggerProfile(profile);
  return updated;
};

// AI context formatter for Reframe API integration.
// Returns null when no triggers (so Reframe context block can omit cleanly).
// Otherwise returns a string formatted for AI consumption — top N triggers
// by encounter count, labeled with category and frequency.
const formatTriggerProfileForAI = (limit = 8) => {
  try {
    const profile = getTriggerProfile();
    if (!profile.triggers.length) return null;
    // Sort by encounter count desc, then by lastSeen recency.
    // The triggers the user has named AND has surfaced most often
    // are the most cognitively load-bearing.
    const sorted = [...profile.triggers].sort((a, b) => {
      const ec = (b.encounterCount || 0) - (a.encounterCount || 0);
      if (ec !== 0) return ec;
      const at = new Date(a.lastSeen || a.createdAt || 0).getTime();
      const bt = new Date(b.lastSeen || b.createdAt || 0).getTime();
      return bt - at;
    });
    const top = sorted.slice(0, limit);
    const formatted = top.map(t => {
      const count = t.encounterCount || 0;
      const countLabel = count === 0 ? "" : ` (${count} encounter${count === 1 ? "" : "s"})`;
      return `"${t.label}" [${t.category}]${countLabel}`;
    }).join(", ");
    return `User's named external triggers: ${formatted}`;
  } catch { return null; }
};

// ─── Async storage helpers — encrypted siblings of the sync helpers above ─────
// Phase 2 of encryption extension. These read/write from the encrypted store
// (secureSet/secureGet via readJSON/writeJSON). Call sites are converted from
// the sync helpers to these async siblings one at a time. Once all call sites
// are migrated, the sync helpers above will be deleted.
//
// readJSON falls back to plain localStorage during the migration window, so
// data that hasn't been written yet through the encrypted path still reads
// correctly. After full migration, the plain-text fallback in readJSON is
// removed and the sync helpers are deleted.

const readArrayFromStorageAsync = async (key) => {
  const value = await readJSON(key, []);
  return Array.isArray(value) ? value : [];
};

const getSessionsFromStorageAsync = () => readArrayFromStorageAsync(SESSION_STORAGE_KEY);

const setSessionsInStorageAsync = async (sessions) => {
  await writeJSON(SESSION_STORAGE_KEY, Array.isArray(sessions) ? sessions : []);
};

const appendSessionToStorageAsync = async (entry) => {
  if (!entry) {
    const existing = await getSessionsFromStorageAsync();
    return existing.length;
  }
  const sessions = await getSessionsFromStorageAsync();
  sessions.push(entry);
  await setSessionsInStorageAsync(sessions);
  return sessions.length;
};

const appendCommunicationEventAsync = async (entry, maxItems = COMMUNICATION_EVENTS_MAX_ITEMS) => {
  if (!entry) return 0;
  const events = await readArrayFromStorageAsync(COMMUNICATION_EVENTS_KEY);
  events.push(entry);
  const bounded = events.slice(-maxItems);
  await writeJSON(COMMUNICATION_EVENTS_KEY, bounded);
  return bounded.length;
};

const getSessionCountFromStorageAsync = async () => {
  const sessions = await getSessionsFromStorageAsync();
  return sessions.length;
};

const updateSessionByTimestampAsync = async (sessionTimestamp, updater) => {
  if (!sessionTimestamp || typeof updater !== "function") return null;
  const sessions = await getSessionsFromStorageAsync();
  const index = sessions.findIndex((session) => session?.timestamp === sessionTimestamp);
  if (index < 0) return null;
  const current = sessions[index];
  const updated = updater(current);
  if (!updated || typeof updated !== "object") return null;
  sessions[index] = updated;
  await setSessionsInStorageAsync(sessions);
  return updated;
};

const updateSessionByTimestamp = (sessionTimestamp, updater) => {
  if (!sessionTimestamp || typeof updater !== "function") return null;
  const sessions = getSessionsFromStorage();
  const index = sessions.findIndex((session) => session?.timestamp === sessionTimestamp);
  if (index < 0) return null;
  const current = sessions[index];
  const updated = updater(current);
  if (!updated || typeof updated !== "object") return null;
  sessions[index] = updated;
  setSessionsInStorage(sessions);
  return updated;
};

const saveSessionNextMove = (sessionTimestamp, nextMove) => {
  if (!sessionTimestamp || !nextMove || typeof nextMove !== "object") return null;
  return updateSessionByTimestamp(sessionTimestamp, (session) => {
    const actionId = String(nextMove.actionId || "").trim();
    if (!actionId) return session;
    const customText = String(nextMove.customText || "").trim().slice(0, 180);
    const fallbackLabel = NEXT_MOVE_ACTION_LABELS[actionId] || "Custom action";
    const label = String(nextMove.label || (actionId === "custom" ? customText : fallbackLabel)).trim() || fallbackLabel;
    const createdAt = String(nextMove.createdAt || new Date().toISOString());
    const dueAt = String(nextMove?.followUp?.dueAt || new Date(Date.now() + NEXT_MOVE_FOLLOW_UP_DELAY_MS).toISOString());
    return {
      ...session,
      nextMove: {
        id: String(nextMove.id || `nextmove_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`),
        actionId,
        label,
        customText: actionId === "custom" ? customText : null,
        createdAt,
        followUp: {
          status: "pending",
          dueAt,
          promptedAt: null,
          answeredAt: null,
          didIt: null,
          helped: null
        }
      }
    };
  });
};

const getNextMoveLabel = (nextMove) => {
  if (!nextMove || typeof nextMove !== "object") return "";
  const customText = String(nextMove.customText || "").trim();
  if (nextMove.actionId === "custom" && customText) return customText;
  const fallback = NEXT_MOVE_ACTION_LABELS[String(nextMove.actionId || "").trim()] || "";
  return String(nextMove.label || fallback).trim();
};

const getPendingNextMoveFollowUpSession = (sessions = getSessionsFromStorage()) => {
  const list = Array.isArray(sessions) ? sessions : [];
  const now = Date.now();
  for (let i = list.length - 1; i >= 0; i -= 1) {
    const session = list[i];
    if (!session || typeof session !== "object") continue;
    const nextMove = session?.nextMove;
    if (!nextMove || typeof nextMove !== "object") continue;
    const followUp = nextMove?.followUp || {};
    if (followUp?.status && followUp.status !== "pending") continue;
    const dueAtMs = new Date(followUp?.dueAt || 0).getTime();
    const dueAt = Number.isFinite(dueAtMs) ? dueAtMs : 0;
    if (dueAt > now) continue;
    const tools = Array.isArray(session?.tools) ? session.tools : [];
    const includesSupportedTool = tools.some((toolId) => {
      const normalized = normalizeSessionToolId(toolId);
      return normalized === "reframe" || normalized === "breathe" || normalized === "scan";
    });
    if (!includesSupportedTool) continue;
    return session;
  }
  return null;
};

const saveSessionNextMoveFollowUp = (sessionTimestamp, { didIt, helped } = {}) => {
  const didItCompleted = didIt === true;
  const didItDeferred = didIt === null;
  const didItRejected = didIt === false;
  if (!sessionTimestamp || (!didItCompleted && !didItDeferred && !didItRejected)) return null;
  return updateSessionByTimestamp(sessionTimestamp, (session) => {
    const existingNextMove = session?.nextMove;
    if (!existingNextMove || typeof existingNextMove !== "object") return session;
    const stamp = new Date().toISOString();
    const existingFollowUp = existingNextMove.followUp || {};
    if (didItDeferred) {
      return {
        ...session,
        nextMove: {
          ...existingNextMove,
          followUp: {
            ...existingFollowUp,
            status: "pending",
            dueAt: new Date(Date.now() + NEXT_MOVE_FOLLOW_UP_DELAY_MS).toISOString(),
            promptedAt: existingFollowUp.promptedAt || stamp,
            answeredAt: null,
            didIt: null,
            helped: null
          }
        }
      };
    }
    return {
      ...session,
      nextMove: {
        ...existingNextMove,
        followUp: {
          ...existingFollowUp,
          status: "answered",
          promptedAt: existingFollowUp.promptedAt || stamp,
          answeredAt: stamp,
          didIt: didItCompleted ? true : false,
          helped: didItCompleted && typeof helped === "boolean" ? helped : null
        }
      }
    };
  });
};

const getToolDebriefsFromStorage = () => {
  try {
    const parsed = secureRead(TOOL_DEBRIEF_STORAGE_KEY, []);
    return Array.isArray(parsed) ? parsed.filter((entry) => entry && typeof entry === "object") : [];
  } catch {
    return [];
  }
};

const appendToolDebriefToStorage = (entry, maxItems = TOOL_DEBRIEF_MAX_ITEMS) => {
  if (!entry) return getToolDebriefsFromStorage();
  const existing = getToolDebriefsFromStorage();
  const next = [entry, ...existing].slice(0, maxItems);
  try { secureWrite(TOOL_DEBRIEF_STORAGE_KEY, next); } catch {}
  return next;
};

// ─────────────────────────────────────────────────────────────────────────────
// SHIFT CLASSIFIER — Russell circumplex three-category framework
// Russell 1980 (J. Pers. Soc. Psychol. 39:1161-1178), confirmed Watson 2024.
// Per THREE_CATEGORY_DATA_FEED_SPEC.md.
// Category A — Regulated shift (the tool worked)
// Category B — Persistent state (no shift detected, sometimes the work is holding)
// Category C — Concerning shift (per-session: any→Distant; pattern: ≥5 sustained Flat or HAN in 14 days)
// ─────────────────────────────────────────────────────────────────────────────

const SHIFT_CHIP_QUADRANTS = {
  excited:  { valence: "+", arousal: "high", quadrant: "HAP" },
  focused:  { valence: "+", arousal: "high", quadrant: "HAP" },
  settled:  { valence: "+", arousal: "low",  quadrant: "LAP" },
  anxious:  { valence: "-", arousal: "high", quadrant: "HAN" },
  angry:    { valence: "-", arousal: "high", quadrant: "HAN" },
  flat:     { valence: "-", arousal: "low",  quadrant: "LAN" },
  distant:  { valence: "-", arousal: "low",  quadrant: "LAN-distant" },
  stuck:    { valence: "-", arousal: "mid",  quadrant: "cognitive" },
  mixed:    { valence: "mixed", arousal: "mid", quadrant: "undifferentiated" }
};

const SHIFT_CATEGORY_PATTERN_THRESHOLD = 5;
const SHIFT_CATEGORY_PATTERN_WINDOW_DAYS = 14;
const SHIFT_SCHEMA_VERSION = 1;
const SHIFT_EVENT_STORAGE_KEY = "stillform_shift_events";
const SHIFT_EVENT_MAX_ITEMS = 2000;

const getShiftEventsFromStorage = () => {
  try {
    const parsed = JSON.parse(localStorage.getItem(SHIFT_EVENT_STORAGE_KEY) || "[]");
    return Array.isArray(parsed) ? parsed.filter((e) => e && typeof e === "object") : [];
  } catch { return []; }
};

const appendShiftEventToStorage = (entry, maxItems = SHIFT_EVENT_MAX_ITEMS) => {
  if (!entry) return getShiftEventsFromStorage();
  const existing = getShiftEventsFromStorage();
  const next = [entry, ...existing].slice(0, maxItems);
  try { localStorage.setItem(SHIFT_EVENT_STORAGE_KEY, JSON.stringify(next)); } catch {}
  return next;
};

// Reads recent shift events to compute pattern context (sustained Flat / sustained HAN)
function getRecentSustainedPatterns(shiftEvents) {
  const cutoff = TimeKeeper.daysAgoMs(SHIFT_CATEGORY_PATTERN_WINDOW_DAYS);
  const recent = (shiftEvents || [])
    .filter(e => e && e.timestamp && new Date(e.timestamp).getTime() > cutoff)
    .filter(e => e.postState)
    .sort((a, b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime());

  let sustainedFlat = 0;
  let sustainedHAN = 0;
  let breakingFlat = false;
  let breakingHAN = false;

  for (const event of recent) {
    if (!breakingFlat) {
      if (event.postState === "flat") sustainedFlat++;
      else breakingFlat = true;
    }
    if (!breakingHAN) {
      if (event.postState === "anxious" || event.postState === "angry") sustainedHAN++;
      else breakingHAN = true;
    }
    if (breakingFlat && breakingHAN) break;
  }
  return { recentSustainedFlat: sustainedFlat, recentSustainedHAN: sustainedHAN };
}

// Pure classifier — same inputs always produce same output. Easy to test.
function classifyShiftDirection(preState, postState, sessionContext = {}) {
  if (!preState && !postState) return { category: null, nullReason: "no-pre-state" };
  if (!preState) return { category: null, nullReason: "no-pre-state" };
  if (!postState) return { category: null, nullReason: "skipped" };
  // User explicitly said they don't know — distinct from skipped (no engagement)
  // and from unknown-chip (chip outside the canonical set). Preserves the signal
  // that the user completed the session but the post-state isn't legible yet.
  if (postState === "unsure") return { category: null, nullReason: "user-unsure" };

  const pre = SHIFT_CHIP_QUADRANTS[preState];
  const post = SHIFT_CHIP_QUADRANTS[postState];
  if (!pre || !post) return { category: null, nullReason: "unknown-chip" };

  // CATEGORY C — concerning (per-session: post-state Distant)
  if (post.quadrant === "LAN-distant") {
    return { category: "concerning", subcategory: "distant-post-state" };
  }

  // CATEGORY C — concerning (pattern: sustained Flat or HAN)
  const recentFlat = sessionContext.recentSustainedFlat || 0;
  const recentHAN = sessionContext.recentSustainedHAN || 0;
  if (recentFlat >= SHIFT_CATEGORY_PATTERN_THRESHOLD &&
      post.quadrant === "LAN" && postState === "flat") {
    return { category: "concerning", subcategory: "sustained-flat" };
  }
  if (recentHAN >= SHIFT_CATEGORY_PATTERN_THRESHOLD && post.quadrant === "HAN") {
    return { category: "concerning", subcategory: "sustained-HAN" };
  }

  // CATEGORY A — regulated shift
  if ((pre.quadrant === "HAN" || pre.quadrant === "LAN") &&
      (post.quadrant === "HAP" || post.quadrant === "LAP")) {
    return { category: "regulated", subcategory: "negative-to-positive" };
  }
  if (pre.quadrant === "HAN" && post.quadrant === "LAN" && postState !== "distant") {
    return { category: "regulated", subcategory: "high-arousal-down" };
  }
  if (preState === "stuck" && (post.quadrant === "HAP" || post.quadrant === "LAP")) {
    return { category: "regulated", subcategory: "stuck-to-clarity" };
  }
  if (preState === "mixed" && (post.quadrant === "HAP" || post.quadrant === "LAP") &&
      postState !== "mixed") {
    return { category: "regulated", subcategory: "mixed-to-positive" };
  }

  // CATEGORY B — persistent
  if (pre.quadrant === post.quadrant) {
    return { category: "persistent", subcategory: "same-quadrant" };
  }
  if (preState === postState) {
    return { category: "persistent", subcategory: "same-chip" };
  }
  if (preState === "mixed" && post.valence === "-") {
    return { category: "persistent", subcategory: "mixed-to-negative-differentiation" };
  }

  // Edge case: regulated → non-pattern negative
  if ((pre.quadrant === "HAP" || pre.quadrant === "LAP") &&
      (post.quadrant === "HAN" || post.quadrant === "LAN")) {
    return { category: null, nullReason: "regulated-to-negative-non-pattern" };
  }

  // Final fallback (should rarely hit; logs as persistent for data continuity)
  return { category: "persistent", subcategory: "unmatched-rule" };
}

// Helper — build full shift event for storage. Used by both Reframe and Body Scan.
function buildShiftEvent({ source, toolId, toolMode, preState, postState, shiftLabel, sessionTimestamp, regulationType }) {
  const allEvents = getShiftEventsFromStorage();
  const patternContext = getRecentSustainedPatterns(allEvents);
  let bioFilter = [];
  try {
    const stored = secureRead("stillform_bio_filter", null);
    if (Array.isArray(stored)) bioFilter = stored;
  } catch {}
  const sessionCount = (() => {
    try { return getSessionCountFromStorage(); } catch { return 0; }
  })();
  const { category, subcategory, nullReason } = classifyShiftDirection(preState, postState, patternContext);
  const cleanLabel = String(shiftLabel || "").trim();
  return {
    id: `shift_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`,
    schemaVersion: SHIFT_SCHEMA_VERSION,
    timestamp: new Date().toISOString(),
    date: TimeKeeper.clockDay(),
    stillformDate: TimeKeeper.stillformDay(),
    source,
    sessionTimestamp: sessionTimestamp || null,
    toolId,
    toolMode: toolMode || null,
    preState: preState || null,
    postState: postState || null,
    category,
    subcategory: subcategory || null,
    nullReason: nullReason || null,
    shiftLabel: cleanLabel || null,
    hasLabel: cleanLabel.length > 0,
    bioFilter,
    sessionCount,
    regulationType: regulationType || null,
    recentSustainedFlat: patternContext.recentSustainedFlat,
    recentSustainedHAN: patternContext.recentSustainedHAN
  };
}

// ─────────────────────────────────────────────────────────────────────────────
// Unified text context aggregator
// ─────────────────────────────────────────────────────────────────────────────
// Purpose: pull the recent user-written text from EVERY persistence store on the
// device into a single structured context that AI can read at session start.
//
// AI-down resilience: this function is read-only and synchronous. It does not
// touch the network. Whatever the user wrote during an AI outage (What Shifted
// labels in shift events, Self Mode responses on session records, grounding
// writes, Signal Log entries) is captured locally regardless of AI status. When
// AI returns, this function naturally surfaces that text — no special "catch up"
// path needed because the data layer was never AI-dependent in the first place.
//
// Storage stores it reads from:
//   - stillform_shift_events  → shiftLabel free-text from Body Scan + Reframe What Shifted
//   - stillform_sessions      → responses{} from Self Mode 5-step protocol
//   - stillform_grounding_data → text from grounding 5-senses writes
//   - stillform_journal       → existing Signal Log entries (already fed via journalContext)
//
// Output shape: a structured string the AI prompt template can include verbatim.
// Each entry tagged with origin + relative date so the AI can reason about
// recency. Hard cap on length to keep token budget bounded.
function buildUnifiedTextContext({ maxEntries = 20, dayLookback = 14 } = {}) {
  const cutoff = TimeKeeper.daysAgoMs(dayLookback);
  const all = [];

  // 1. Shift events with non-empty shiftLabel (post-Reframe + post-Body-Scan What Shifted)
  try {
    const events = getShiftEventsFromStorage();
    for (const e of events) {
      if (!e || !e.shiftLabel) continue;
      const ts = e.timestamp ? new Date(e.timestamp).getTime() : 0;
      if (ts < cutoff) continue;
      const tool = e.toolId === "scan" ? "Body Scan" : "Reframe";
      all.push({
        ts,
        date: e.date || "",
        origin: `What Shifted (${tool})`,
        text: String(e.shiftLabel).trim(),
        preState: e.preState || null,
        postState: e.postState || null
      });
    }
  } catch {}

  // 2. Self Mode session responses (the 5-step protocol: Notice / Name / Recognize / Perspective / Choose)
  try {
    const sessions = getSessionsFromStorage();
    for (const s of sessions) {
      if (!s || !s.responses || typeof s.responses !== "object") continue;
      const ts = s.timestamp ? new Date(s.timestamp).getTime() : 0;
      if (ts < cutoff) continue;
      const labels = ["Notice", "Name", "Recognize", "Perspective", "Choose"];
      const filled = [];
      for (let i = 0; i < labels.length; i++) {
        const v = String(s.responses[i] || "").trim();
        if (v) filled.push(`${labels[i]}: ${v}`);
      }
      if (filled.length === 0) continue;
      all.push({
        ts,
        date: TimeKeeper.clockDayOf(s.timestamp) || "",
        origin: "Self Mode",
        text: filled.join(" | "),
        preState: s.preState || null,
        postState: null
      });
    }
  } catch {}

  // 3. Grounding writes (5-senses)
  try {
    const grounding = secureRead("stillform_grounding_data", []);
    if (Array.isArray(grounding)) {
      for (const g of grounding) {
        if (!g || !Array.isArray(g.steps)) continue;
        const ts = g.timestamp ? new Date(g.timestamp).getTime() : 0;
        if (ts < cutoff) continue;
        const written = g.steps.filter(st => st && st.text && String(st.text).trim().length > 0);
        if (written.length === 0) continue;
        const summary = written.map(st => `${st.sense}: ${String(st.text).trim()}`).join(" | ");
        all.push({
          ts,
          date: TimeKeeper.clockDayOf(g.timestamp) || "",
          origin: "Grounding",
          text: summary,
          preState: null,
          postState: null
        });
      }
    }
  } catch {}

  // 4. Signal Log entries with trigger text (manually authored, not auto-logged)
  // Already partially covered by journalContext, but consolidating here gives AI a single
  // unified text feed. The reframe.js prompt can deduplicate naturally.
  try {
    const journal = secureRead("stillform_journal", []);
    if (Array.isArray(journal)) {
      for (const j of journal) {
        if (!j || j.source === "reframe-auto") continue;
        const trig = String(j.trigger || "").trim();
        if (!trig) continue;
        const ts = j.timestamp ? new Date(j.timestamp).getTime() : (j.date ? new Date(j.date).getTime() : 0);
        if (ts < cutoff) continue;
        const emo = Array.isArray(j.emotions) && j.emotions.length ? ` (${j.emotions.join(", ")})` : "";
        const out = j.outcome ? ` → ${j.outcome}` : "";
        all.push({
          ts,
          date: j.date || "",
          origin: "Signal Log",
          text: `${trig}${emo}${out}`,
          preState: null,
          postState: null
        });
      }
    }
  } catch {}

  // Sort newest first, cap to maxEntries
  all.sort((a, b) => b.ts - a.ts);
  const capped = all.slice(0, maxEntries);
  if (capped.length === 0) return null;

  // Format for AI prompt: tagged origin + date + text. Keep compact.
  // Header tells the AI what this is and how to treat it (pattern recognition only,
  // do not quote back unless the user asks; do reference patterns naturally).
  const lines = capped.map(e => {
    const stateTag = (e.preState || e.postState)
      ? ` [${e.preState || "?"}→${e.postState || "?"}]`
      : "";
    const dateTag = e.date ? `[${e.date}] ` : "";
    return `${dateTag}${e.origin}${stateTag}: ${e.text}`;
  });
  return [
    "RECENT REFLECTIONS (text the user has written across all tools in the last " + dayLookback + " days, for pattern recognition — do not quote back unless the user explicitly asks):",
    ...lines
  ].join("\n");
}


const normalizeSessionToolId = (toolId) => {
  const id = String(toolId || "").trim().toLowerCase();
  if (!id) return null;
  if (id === "body-scan") return "scan";
  if (id === "ground" || id === "sigh") return "breathe";
  if (id === "metacognition") return "metacognition";
  return id;
};

const getPrimarySessionToolId = (session) => {
  const tools = Array.isArray(session?.tools) ? session.tools : [];
  for (const raw of tools) {
    const normalized = normalizeSessionToolId(raw);
    if (!normalized) continue;
    if (normalized === "reframe" || normalized === "breathe" || normalized === "scan") {
      return normalized;
    }
  }
  return null;
};

const getToolFamily = (normalizedToolId) => {
  if (normalizedToolId === "reframe") return "cognitive";
  if (normalizedToolId === "breathe" || normalizedToolId === "scan") return "somatic";
  return null;
};

const getToolEntryPrimer = (toolId, regulationType) => {
  const normalizedTool = toolId === "body-scan" ? "scan" : toolId;
  if (!["reframe", "breathe", "scan"].includes(normalizedTool)) return null;
  const normalizedType = regulationType === "thought-first" || regulationType === "body-first" ? regulationType : "thought-first";
  return TOOL_ENTRY_PRIMER_COPY?.[normalizedType]?.[normalizedTool] || null;
};

const getToolDebriefPromptSet = (toolId, regulationType) => {
  const normalizedTool = toolId === "body-scan" ? "scan" : toolId;
  const config = TOOL_DEBRIEF_COPY[normalizedTool] || TOOL_DEBRIEF_COPY.reframe;
  const normalizedType = regulationType === "thought-first" || regulationType === "body-first" ? regulationType : "thought-first";
  return {
    prompt: config.prompt,
    options: Array.isArray(config[normalizedType]) && config[normalizedType].length
      ? config[normalizedType]
      : config["thought-first"]
  };
};

const getCommunicationDraftSignals = (value) => {
  const text = String(value || "").trim();
  const wordCount = text ? text.split(/\s+/).filter(Boolean).length : 0;
  const textLength = text.length;
  const meaningful = textLength >= COMMUNICATION_MEANINGFUL_CHARS_MIN || wordCount >= COMMUNICATION_MEANINGFUL_WORDS_MIN;
  return { textLength, wordCount, meaningful };
};

const getUatFeedbackDraft = () => {
  try {
    const parsed = JSON.parse(localStorage.getItem(UAT_FEEDBACK_DRAFT_KEY) || "null");
    if (!parsed || typeof parsed !== "object") return { questionId: UAT_QUESTION_OPTIONS[0]?.id || "confusing", text: "" };
    const fallbackQuestionId = UAT_QUESTION_OPTIONS[0]?.id || "confusing";
    const questionId = UAT_QUESTION_OPTIONS.some((item) => item.id === parsed.questionId)
      ? parsed.questionId
      : fallbackQuestionId;
    const text = String(parsed.text || "").slice(0, UAT_FEEDBACK_TEXT_MAX);
    return { questionId, text };
  } catch {
    return { questionId: UAT_QUESTION_OPTIONS[0]?.id || "confusing", text: "" };
  }
};

const getUatFeedbackHistoryFromStorage = () => {
  try {
    const parsed = JSON.parse(localStorage.getItem(UAT_FEEDBACK_HISTORY_KEY) || "[]");
    if (!Array.isArray(parsed)) return [];
    return parsed
      .map((entry) => normalizeUatFeedbackHistoryEntry(entry))
      .filter(Boolean)
      .slice(0, UAT_FEEDBACK_HISTORY_MAX_ITEMS);
  } catch {
    return [];
  }
};

const normalizeUatFeedbackHistoryEntry = (entry) => {
  if (!entry || typeof entry !== "object") return null;
  const id = String(entry.id || "");
  const submittedAt = String(entry.submittedAt || entry.submitted_at || "");
  const questionId = String(entry.questionId || entry.question_id || "");
  const text = String(entry.text || entry.feedback_text || "");
  if (!submittedAt || !text) return null;
  return {
    id: id || `${submittedAt}_${questionId || "feedback"}`,
    submittedAt,
    questionId,
    text
  };
};

const mergeUatFeedbackHistoryEntries = (entries, maxItems = UAT_FEEDBACK_HISTORY_MAX_ITEMS) => {
  const byKey = new Map();
  for (const raw of Array.isArray(entries) ? entries : []) {
    const entry = normalizeUatFeedbackHistoryEntry(raw);
    if (!entry) continue;
    const dedupeKey = `${entry.id}|${entry.submittedAt}|${entry.questionId}|${entry.text}`;
    if (!byKey.has(dedupeKey)) byKey.set(dedupeKey, entry);
  }
  return [...byKey.values()]
    .sort((a, b) => new Date(b.submittedAt || 0).getTime() - new Date(a.submittedAt || 0).getTime())
    .slice(0, maxItems);
};

const appendUatFeedbackHistory = (entry, maxItems = UAT_FEEDBACK_HISTORY_MAX_ITEMS) => {
  if (!entry) return getUatFeedbackHistoryFromStorage();
  const current = getUatFeedbackHistoryFromStorage();
  const next = mergeUatFeedbackHistoryEntries([
    normalizeUatFeedbackHistoryEntry(entry),
    ...current
  ], maxItems);
  try { localStorage.setItem(UAT_FEEDBACK_HISTORY_KEY, JSON.stringify(next)); } catch {}
  return next;
};

const getSessionCountFromStorage = () => getSessionsFromStorage().length;

const toDayKey = (value) => {
  if (!value) return null;
  try {
    const dt = new Date(value);
    if (Number.isNaN(dt.getTime())) return null;
    return TimeKeeper.clockDayOf(dt);
  } catch {
    return null;
  }
};

const withinDays = (value, days) => {
  if (!value) return false;
  try {
    const dt = new Date(value);
    if (Number.isNaN(dt.getTime())) return false;
    const cutoff = TimeKeeper.daysAgoMs(days);
    return dt.getTime() >= cutoff;
  } catch {
    return false;
  }
};

const recentDaySet = (items, days = 14) => new Set(
  (Array.isArray(items) ? items : [])
    .filter((entry) => withinDays(entry?.date || entry?.timestamp, days))
    .map((entry) => toDayKey(entry?.date || entry?.timestamp))
    .filter(Boolean)
);

const toRate = (value) => {
  if (!Number.isFinite(value)) return null;
  const clamped = Math.max(0, Math.min(1, value));
  return Number(clamped.toFixed(4));
};

const buildPerformanceMetricsSnapshot = ({ appVersion, packageVersion, isSubscribed }) => {
  const sessions = readArrayFromStorage("stillform_sessions");
  const pulseEntries = readArrayFromStorage("stillform_journal");
  const savedReframes = readArrayFromStorage("stillform_saved_reframes");
  const morningOpenHistory = readArrayFromStorage(LOOP_HISTORY_KEYS.morningStart);
  const morningHistory = readArrayFromStorage(LOOP_HISTORY_KEYS.morning);
  const eodOpenHistory = readArrayFromStorage(LOOP_HISTORY_KEYS.eodStart);
  const eodHistory = readArrayFromStorage(LOOP_HISTORY_KEYS.eod);
  const loopNudgeEvents = readArrayFromStorage(LOOP_NUDGE_EVENTS_KEY);

  const ratedSessions = sessions.filter((session) => {
    const pre = Number(session?.preRating);
    const post = Number(session?.postRating);
    return Number.isFinite(pre) && Number.isFinite(post);
  });
  const avgDelta = ratedSessions.length
    ? Number((ratedSessions.reduce((sum, session) => (
      sum + (Number(session.postRating) - Number(session.preRating))
    ), 0) / ratedSessions.length).toFixed(4))
    : null;
  const positiveShiftRate = ratedSessions.length
    ? toRate(ratedSessions.filter((session) => (
      Number(session.postRating) - Number(session.preRating) > 0
    )).length / ratedSessions.length)
    : null;
  const protocolRunsTotal = sessions.filter((session) => (
    session?.entryMode && String(session.entryMode).startsWith("protocol-")
  )).length;
  const activeDaysTotal = new Set(
    sessions
      .map((session) => toDayKey(session?.timestamp))
      .filter(Boolean)
  ).size;
  const activeDays14d = new Set(
    sessions
      .filter((session) => withinDays(session?.timestamp, 14))
      .map((session) => toDayKey(session?.timestamp))
      .filter(Boolean)
  ).size;
  const toolUsage = {};
  sessions.forEach((session) => {
    const tools = Array.isArray(session?.tools) ? session.tools : [];
    tools.forEach((tool) => {
      const key = String(tool || "").trim().toLowerCase();
      if (!key) return;
      toolUsage[key] = (toolUsage[key] || 0) + 1;
    });
  });

  const morningOpen14dDays = recentDaySet(morningOpenHistory, 14);
  const morningDone14dDays = recentDaySet(morningHistory, 14);
  const eodOpen14dDays = recentDaySet(eodOpenHistory, 14);
  const eodDone14dDays = recentDaySet(eodHistory, 14);
  const morning14dCount = morningHistory.filter((entry) => withinDays(entry?.date || entry?.timestamp, 14)).length;
  const eod14dCount = eodHistory.filter((entry) => withinDays(entry?.date || entry?.timestamp, 14)).length;
  const loopCompletionRate14d = toRate((morning14dCount + eod14dCount) / (14 * 2));
  const morningCompletionRate14d = toRate(morning14dCount / 14);
  const eodCompletionRate14d = toRate(eod14dCount / 14);

  const loopNudgeShown14d = loopNudgeEvents.filter(
    (entry) => entry?.event === "shown" && withinDays(entry?.date || entry?.timestamp, 14)
  );
  const loopNudgeActioned14d = loopNudgeEvents.filter(
    (entry) => entry?.event === "actioned" && withinDays(entry?.date || entry?.timestamp, 14)
  );
  const loopNudgeDismissed14d = loopNudgeEvents.filter(
    (entry) => entry?.event === "dismissed" && withinDays(entry?.date || entry?.timestamp, 14)
  );
  const recoveredNudges14d = loopNudgeShown14d.filter((entry) => (
    entry?.type === "morning"
      ? morningDone14dDays.has(entry?.date)
      : eodDone14dDays.has(entry?.date)
  )).length;
  const nudgeRecoveryRate14d = loopNudgeShown14d.length
    ? toRate(recoveredNudges14d / loopNudgeShown14d.length)
    : null;

  // Read most-recent crash record (written by ErrorBoundary's componentDidCatch).
  // Cleared after a successful diagnostics push so the next snapshot is clean.
  const lastCrash = (() => {
    try {
      const raw = localStorage.getItem("stillform_last_error");
      if (!raw) return null;
      const parsed = JSON.parse(raw);
      if (!parsed || !parsed.timestamp) return null;
      return {
        timestamp: parsed.timestamp,
        message: parsed.message || "unknown",
        stack: parsed.stack || "",
        component_stack: parsed.componentStack || ""
      };
    } catch { return null; }
  })();

  return {
    schema_version: METRICS_SCHEMA_VERSION,
    generated_at: new Date().toISOString(),
    app_version: appVersion,
    package_version: packageVersion,
    sessions_total: sessions.length,
    rated_sessions: ratedSessions.length,
    avg_delta: avgDelta,
    positive_shift_rate: positiveShiftRate,
    active_days_total: activeDaysTotal,
    active_days_14d: activeDays14d,
    pulse_entries_total: pulseEntries.length,
    saved_reframes_total: savedReframes.length,
    protocol_runs_total: protocolRunsTotal,
    morning_completion_rate_14d: morningCompletionRate14d,
    eod_completion_rate_14d: eodCompletionRate14d,
    loop_completion_rate_14d: loopCompletionRate14d,
    nudge_shown_14d: loopNudgeShown14d.length,
    nudge_actioned_14d: loopNudgeActioned14d.length,
    nudge_dismissed_14d: loopNudgeDismissed14d.length,
    nudge_recovery_rate_14d: nudgeRecoveryRate14d,
    subscription_active_local: isSubscribed === true,
    tool_usage: toolUsage,
    last_crash: lastCrash
  };
};

const appendDailyLoopHistory = (storageKey, entry, maxItems = 120) => {
  try {
    const current = JSON.parse(localStorage.getItem(storageKey) || "[]");
    const base = Array.isArray(current) ? current.filter((item) => item?.date !== entry?.date) : [];
    base.push(entry);
    const trimmed = base.slice(-maxItems);
    localStorage.setItem(storageKey, JSON.stringify(trimmed));
  } catch {}
};

const trackMorningStart = (entry) => appendDailyLoopHistory(LOOP_HISTORY_KEYS.morningStart, entry, LOOP_HISTORY_MAX_ITEMS);
const trackMorningComplete = (entry) => appendDailyLoopHistory(LOOP_HISTORY_KEYS.morning, entry, LOOP_HISTORY_MAX_ITEMS);
const trackEodStart = (entry) => appendDailyLoopHistory(LOOP_HISTORY_KEYS.eodStart, entry, LOOP_HISTORY_MAX_ITEMS);
const trackEodComplete = (entry) => appendDailyLoopHistory(LOOP_HISTORY_KEYS.eod, entry, LOOP_HISTORY_MAX_ITEMS);

const appendLoopNudgeEvent = (entry, maxItems = LOOP_NUDGE_EVENTS_MAX_ITEMS) => {
  try {
    const current = JSON.parse(localStorage.getItem(LOOP_NUDGE_EVENTS_KEY) || "[]");
    const list = Array.isArray(current) ? current : [];
    const exists = list.some((item) => (
      item?.event === entry?.event &&
      item?.type === entry?.type &&
      item?.date === entry?.date
    ));
    if (exists) return false;
    const next = [...list, entry].slice(-maxItems);
    localStorage.setItem(LOOP_NUDGE_EVENTS_KEY, JSON.stringify(next));
    return true;
  } catch {
    return false;
  }
};

const trackLoopNudgeTelemetry = (eventName, payload) => {
  try {
    window.plausible(eventName, { props: payload });
  } catch {}
};

const EMPTY_INTEGRATION_CONTEXT = Object.freeze({
  calendar: null,
  health: null,
  calendarConsent: "pending",
  healthConsent: "pending",
  calendarError: null,
  healthError: null,
  calendarLastRetryAt: null,
  healthLastRetryAt: null,
  calendarContext: null,
  healthContext: null,
  upcomingPressure: null,
  hasAny: false,
  hasStale: false,
  calendarSource: null,
  healthSource: null,
  calendarFreshness: null,
  healthFreshness: null
});

// Pre-meeting notification scheduler
const scheduleMeetingNotifications = async () => {
  try {
    if (!isNative()) return;
    const enabled = localStorage.getItem(PRE_MEETING_NOTIF_KEY) !== "off";
    if (!enabled) return;
    const firstMins = parseInt(localStorage.getItem(PRE_MEETING_NOTIF_FIRST_KEY) || "30", 10);
    const secondMins = parseInt(localStorage.getItem(PRE_MEETING_NOTIF_SECOND_KEY) || "15", 10);
    const events = JSON.parse(localStorage.getItem("stillform_calendar_events") || "[]");
    if (!Array.isArray(events) || events.length === 0) return;
    const { LocalNotifications } = await import("@capacitor/local-notifications");
    const perm = await LocalNotifications.requestPermissions();
    if (perm.display !== "granted") return;
    // Cancel existing pre-meeting notifications
    await LocalNotifications.cancel({ notifications: [{ id: 8800 }, { id: 8801 }, { id: 8802 }, { id: 8803 }] }).catch(() => {});
    const now = new Date();
    let notifId = 8800;
    for (const event of events.slice(0, 4)) {
      if (!event.start) continue;
      const eventTime = new Date(event.start);
      if (isNaN(eventTime.getTime()) || eventTime <= now) continue;
      const title = event.title || "Upcoming event";
      // First notification
      const firstAt = new Date(eventTime.getTime() - firstMins * 60 * 1000);
      if (firstAt > now) {
        await LocalNotifications.schedule({ notifications: [{
          id: notifId++,
          title: "Prepare with Stillform",
          body: `${title} in ${firstMins} minutes. Open Reframe to prepare.`,
          schedule: { at: firstAt },
          extra: { screen: "reframe", eventTitle: title }
        }]});
      }
      // Second notification
      const secondAt = new Date(eventTime.getTime() - secondMins * 60 * 1000);
      if (secondAt > now && secondAt > firstAt) {
        await LocalNotifications.schedule({ notifications: [{
          id: notifId++,
          title: "Prepare with Stillform",
          body: `${title} in ${secondMins} minutes. Still time to prepare.`,
          schedule: { at: secondAt },
          extra: { screen: "reframe", eventTitle: title }
        }]});
      }
    }
  } catch {}
};

// Integration context adapter
// Single source of truth for calendar/health context across the app.
const getIntegrationContext = () => {
  const readConsent = (key) => {
    try {
      const v = localStorage.getItem(key);
      return (v === "granted" || v === "revoked") ? v : "pending";
    } catch {
      return "pending";
    }
  };
  const readString = (key) => {
    try {
      return localStorage.getItem(key) || null;
    } catch {
      return null;
    }
  };
  const parseIsoTime = (v) => {
    if (!v) return null;
    try {
      const d = new Date(v);
      return Number.isNaN(d.getTime()) ? null : d;
    } catch {
      return null;
    }
  };
  const formatFreshness = (updatedAt) => {
    if (!updatedAt) return { label: "Unknown", stale: false };
    const ageMs = Date.now() - updatedAt.getTime();
    const ageHours = ageMs / (1000 * 60 * 60);
    if (ageHours <= 6) return { label: "Fresh", stale: false };
    if (ageHours <= 24) return { label: "Today", stale: false };
    if (ageHours <= 72) return { label: "Aging", stale: false };
    return { label: "Stale", stale: true };
  };
  const calendarConsent = readConsent(INTEGRATION_STORAGE_KEYS.calendar.consent);
  const healthConsent = readConsent(INTEGRATION_STORAGE_KEYS.health.consent);
  const calendarError = readString(INTEGRATION_STORAGE_KEYS.calendar.error);
  const healthError = readString(INTEGRATION_STORAGE_KEYS.health.error);
  const calendarLastRetryAt = parseIsoTime(readString(INTEGRATION_STORAGE_KEYS.calendar.retryAt));
  const healthLastRetryAt = parseIsoTime(readString(INTEGRATION_STORAGE_KEYS.health.retryAt));
  const calendar = (() => {
    try {
      if (calendarConsent === "revoked") return null;
      const summary = localStorage.getItem("stillform_calendar_summary");
      const events = JSON.parse(localStorage.getItem("stillform_calendar_events") || "[]");
      const next = Array.isArray(events) && events.length > 0 ? events[0] : null;
      const updatedAt = parseIsoTime(localStorage.getItem("stillform_calendar_updated_at") || next?.updatedAt || null);
      const freshness = formatFreshness(updatedAt);
      if (summary) {
        return {
          summary,
          source: "summary",
          updatedAt,
          freshness: freshness.label,
          stale: freshness.stale
        };
      }
      if (next?.title) {
        const when = next.start ? ` at ${next.start}` : "";
        return {
          summary: `Upcoming: ${next.title}${when}`,
          source: "event",
          updatedAt,
          freshness: freshness.label,
          stale: freshness.stale
        };
      }
      return null;
    } catch { return null; }
  })();

  const health = (() => {
    try {
      if (healthConsent === "revoked") return null;
      const summary = localStorage.getItem("stillform_health_summary");
      const snap = JSON.parse(localStorage.getItem("stillform_health_snapshot") || "null");
      const updatedAt = parseIsoTime(localStorage.getItem("stillform_health_updated_at") || snap?.updatedAt || null);
      const freshness = formatFreshness(updatedAt);
      if (summary) {
        return {
          summary,
          source: "summary",
          updatedAt,
          freshness: freshness.label,
          stale: freshness.stale
        };
      }
      if (!snap) return null;
      const parts = [];
      if (snap.sleepHours != null) parts.push(`${snap.sleepHours}h sleep`);
      if (snap.hrv != null) parts.push(`HRV ${snap.hrv}`);
      if (snap.restingHr != null) parts.push(`resting HR ${snap.restingHr}`);
      if (snap.readiness) parts.push(`readiness ${snap.readiness}`);
      if (!parts.length) return null;
      return {
        summary: parts.join(", "),
        source: "snapshot",
        updatedAt,
        freshness: freshness.label,
        stale: freshness.stale
      };
    } catch { return null; }
  })();

  const calendarContext = (() => {
    if (!calendar?.summary) return null;
    if (calendar.stale) return `STALE CALENDAR CONTEXT: ${calendar.summary}`;
    return `CALENDAR CONTEXT: ${calendar.summary}`;
  })();
  const healthContext = (() => {
    if (!health?.summary) return null;
    if (health.stale) return `STALE HEALTH CONTEXT: ${health.summary}`;
    return `HEALTH CONTEXT: ${health.summary}`;
  })();

  return {
    calendar,
    health,
    calendarConsent,
    healthConsent,
    calendarError,
    healthError,
    calendarLastRetryAt,
    healthLastRetryAt,
    calendarContext,
    healthContext,
    upcomingPressure: calendar && !calendar.stale ? calendar.summary : null,
    hasAny: !!(calendar || health),
    hasStale: !!(calendar?.stale || health?.stale),
    calendarSource: calendar?.source || null,
    healthSource: health?.source || null,
    calendarFreshness: calendar?.freshness || null,
    healthFreshness: health?.freshness || null
  };
};

// Defensive resolver used at call sites so integration context remains safe
// even if local storage, parsing, or future adapter changes regress.
const resolveIntegrationContext = () => {
  try {
    const ctx = getIntegrationContext();
    if (!ctx || typeof ctx !== "object") return { ...EMPTY_INTEGRATION_CONTEXT };
    return {
      ...EMPTY_INTEGRATION_CONTEXT,
      ...ctx
    };
  } catch {
    return { ...EMPTY_INTEGRATION_CONTEXT };
  }
};

const setPendingSessionEntryContext = (entryMode, entryProtocolId) => {
  try {
    const payload = {
      entryMode: entryMode || null,
      entryProtocolId: entryProtocolId || null,
      createdAt: Date.now()
    };
    secureWrite("stillform_session_entry_context", payload);
  } catch {}
};

const consumePendingSessionEntryContext = (maxAgeMs = 2 * 60 * 60 * 1000) => {
  try {
    const parsed = secureRead("stillform_session_entry_context", null);
    if (!parsed) return null;
    secureDelete("stillform_session_entry_context");
    if (typeof parsed !== "object") return null;
    if (!parsed.createdAt || (Date.now() - Number(parsed.createdAt)) > maxAgeMs) return null;
    return {
      entryMode: parsed.entryMode || null,
      entryProtocolId: parsed.entryProtocolId || null
    };
  } catch {
    try { secureDelete("stillform_session_entry_context"); } catch {}
    return null;
  }
};

const launchScenarioProtocolById = async ({
  protocolId,
  setPathway,
  setActiveTool,
  setScreen,
  gateBiometric
}) => {
  const id = String(protocolId || "");
  const setEntry = (mode, protocol) => {
    setPendingSessionEntryContext(mode, protocol);
    try {
      localStorage.setItem("stillform_reframe_entry_mode", mode);
      localStorage.setItem("stillform_reframe_entry_protocol", protocol);
    } catch {}
  };

  // Reframe clarity path
  if (id === "hard-conversation") {
    if (gateBiometric && !(await gateBiometric())) return false;
    setPathway("clarity");
    setEntry("protocol-clarity", id);
    setActiveTool({ id: "reframe", name: "Reframe", mode: "clarity" });
    setScreen("tool");
    return true;
  }
  // Body-first reset
  if (id === "physiological-spike") {
    setPathway("calm");
    setPendingSessionEntryContext("protocol-body-reset", id);
    setActiveTool({ id: "breathe", quickStart: true });
    setScreen("tool");
    return true;
  }
  // Reframe hype path
  if (id === "winning-locked-in") {
    if (gateBiometric && !(await gateBiometric())) return false;
    setPathway("hype");
    setEntry("protocol-hype", id);
    setActiveTool({ id: "reframe", name: "Reframe", mode: "hype" });
    setScreen("tool");
    return true;
  }
  // Conflict reset
  if (id === "after-conflict-reset") {
    setPathway("calm");
    setPendingSessionEntryContext("protocol-body-scan", id);
    setActiveTool({ id: "scan", name: "Body Scan" });
    setScreen("tool");
    return true;
  }
  return false;
};




// Check display preferences
function useDisplayPrefs() {
  const screenLight = (() => { try { return localStorage.getItem("stillform_screenlight") === "on"; } catch { return false; } })();
  const reducedMotion = (() => { try { return localStorage.getItem("stillform_reducedmotion") === "on"; } catch { return false; } })();
  return { screenLight, reducedMotion };
}

function PhysiologicalSighTool({ onComplete }) {
  const totalReps = 3;
  const [rep, setRep] = useState(1);
  const [phase, setPhase] = useState("inhale1");
  const [count, setCount] = useState(2);
  const [running, setRunning] = useState(false);
  const contextEntryRef = useRef(consumePendingSessionEntryContext());

  // TIME-TO-REGULATION
  const startTime = useRef(Date.now());
  const saveSession = () => {
    const elapsed = Date.now() - startTime.current;
    const fmt = (ms) => { const s = Math.round(ms / 1000); const m = Math.floor(s / 60); return m > 0 ? `${m}m ${s % 60}s` : `${s % 60}s`; };
    try {
      const ctx = contextEntryRef.current || {};
      appendSessionToStorage({
        timestamp: new Date().toISOString(),
        duration: elapsed,
        durationFormatted: fmt(elapsed),
        tools: ["sigh"],
        exitPoint: "sigh-complete",
        source: "sigh",
        entryMode: ctx.entryMode || null,
        entryProtocolId: ctx.entryProtocolId || null
      });
      try { window.plausible("Breathing Completed", { props: { duration: fmt(elapsed) } }); } catch {}
    } catch {}
    return elapsed;
  };

  const phases = {
    inhale1: { label: "Inhale", sub: "In through your nose.", next: "inhale2", duration: 2 },
    inhale2: { label: "Inhale again", sub: "One more. Top it off.", next: "exhale", duration: 2 },
    exhale: { label: "Exhale slowly", sub: "Out through your mouth. Slow. All of it.", next: "rest", duration: 6 },
    rest: { label: "Rest", sub: "Rest.", next: null, duration: 2 }
  };

  useEffect(() => {
    if (!running) return;
    if (count === 0) {
      const current = phases[phase];
      if (current.next) {
        setPhase(current.next);
        setCount(phases[current.next].duration);
      } else {
        // Completed a rep
        if (rep < totalReps) {
          setRep(r => r + 1);
          setPhase("inhale1");
          setCount(phases.inhale1.duration);
        } else {
          setRunning(false);
          setPhase("done");
        }
      }
    } else {
      const t = setTimeout(() => setCount(c => c - 1), 1000);
      return () => clearTimeout(t);
    }
  }, [count, running, phase, rep]);

  const sighSavedRef = useRef(false);
  const sighElapsedRef = useRef(0);
  if (phase === "done") {
    if (!sighSavedRef.current) { sighSavedRef.current = true; sighElapsedRef.current = saveSession(); }
    const elapsed = sighElapsedRef.current;
    const fmt = (ms) => { const s = Math.round(ms / 1000); const m = Math.floor(s / 60); return m > 0 ? `${m}m ${s % 60}s` : `${s % 60}s`; };
    const count = getSessionCountFromStorage();
    return (
      <div className="complete">
        <div className="complete-icon">✓</div>
        <h2>Reset complete.</h2>
        <p style={{ marginBottom: 8 }}>Three deep sighs. Your head is clearer than it was {fmt(elapsed)} ago.</p>
        {count > 1 && <div className="t-body-sm faint" style={{ marginBottom: 16 }}>Session #{count}.</div>}
        <button className="btn btn-primary" style={{ width: "100%" }} onClick={() => onComplete("reframe")}>
          Talk through what's happening →
        </button>
        <button className="btn btn-ghost" style={{ marginTop: 10, width: "100%" }} onClick={onComplete}>
          Done
        </button>
        
      </div>
    );
  }

  return (
    <div>
      <div style={{ textAlign: "center", marginBottom: 8 }}>
        <div style={{ fontSize: 11, letterSpacing: "0.14em", textTransform: "uppercase", color: "var(--text-dim)", marginBottom: 4 }}>
          Physiological sigh
        </div>
        <div className="t-body-sm quiet">
          {rep} of {totalReps}
        </div>
      </div>

      <div className="breath-container">
        <div className="breath-circle-wrap">
          <svg className="breath-svg-ring" viewBox="0 0 280 280">
            <g stroke="rgba(255,255,255,0.06)" strokeWidth="1" transform="rotate(90 140 140)">
              <line x1="140" y1="5" x2="140" y2="18"/>
              <line x1="275" y1="140" x2="262" y2="140"/>
              <line x1="140" y1="275" x2="140" y2="262"/>
              <line x1="5" y1="140" x2="18" y2="140"/>
            </g>
            <g stroke="rgba(255,255,255,0.03)" strokeWidth="0.5" transform="rotate(90 140 140)">
              {[30,60,120,150,210,240,300,330].map(deg => {
                const rad = (deg * Math.PI) / 180;
                return <line key={deg} x1={140 + 131*Math.cos(rad)} y1={140 + 131*Math.sin(rad)} x2={140 + 122*Math.cos(rad)} y2={140 + 122*Math.sin(rad)}/>;
              })}
            </g>
            <circle className="breath-ring-track" cx="140" cy="140" r="125"/>
            <circle
              className="breath-ring-arc"
              cx="140" cy="140" r="125"
              style={{
                strokeDasharray: 785,
                strokeDashoffset: phase === "exhale" ? 785 : phase === "rest" ? 196 : 0,
                '--breath-duration': `${phases[phase]?.duration || 2}s`
              }}
            />
            <circle cx="140" cy="140" r="106" fill="none" stroke="rgba(255,255,255,0.025)" strokeWidth="0.5"/>
          </svg>
          <div className="breath-inner">
            <span className="breath-count">{count}</span>
            <span className="breath-phase">{phases[phase]?.label}</span>
          </div>
        </div>

        {running && phase !== "done" ? (
          <>
            <div className="breath-instruction">{phases[phase]?.sub}</div>
            <div style={{ height: 32 }} />
          </>
        ) : (
          <>
            <div className="breath-instruction" style={{ marginBottom: 24 }}>
              The fastest way to reset your nervous system. Three times.
            </div>
            <button
              className="btn btn-primary"
              style={{ fontSize: 16, padding: "14px 40px" }}
              onClick={() => { setRunning(true); }}
            >
              Begin
            </button>
          </>
        )}
      </div>
    </div>
  );
}

const BREATHING_PATTERNS = [
  { id: "quick", name: "Quick Reset", desc: "60 seconds. Slows your system down fast.", phases: [
    { name: "Inhale", duration: 4, instruction: "In through your nose." },
    { name: "Hold", duration: 4, instruction: "Hold." },
    { name: "Exhale", duration: 6, instruction: "Out through your mouth." }
  ]},
  { id: "deep", name: "Deep Regulate", desc: "3 minutes. Deeper reset. Extended exhale.", phases: [
    { name: "Inhale", duration: 4, instruction: "In through your nose." },
    { name: "Hold", duration: 4, instruction: "Hold." },
    { name: "Exhale", duration: 8, instruction: "Out through your mouth. Long and slow." },
    { name: "Rest", duration: 2, instruction: "Rest." }
  ]},
  // Cyclic sighing — Balban et al. 2023 (Cell Reports Medicine 4:100895). RCT n=111.
  // Two consecutive nasal inhales, then long oral exhale. 1:2 inhale-to-exhale ratio.
  // Outperformed mindfulness meditation, box breathing, and cyclic hyperventilation
  // for mood improvement and physiological arousal reduction.
  { id: "cyclic_sigh", name: "Cyclic Sighing", desc: "5 minutes. The most-studied breath for downregulation.", phases: [
    { name: "Inhale", duration: 4, instruction: "Deep breath in through your nose." },
    { name: "Inhale", duration: 1, instruction: "Small top-off — fill your lungs completely." },
    { name: "Exhale", duration: 8, instruction: "Slow, complete exhale through your mouth." }
  ]}
];

// Shared completion screen for low-demand sessions across Breathe, Body Scan, and (future) Reframe.
// Renders a soft pulsing dot + minimal "Tap anywhere to close" copy. The 1.5s grace period prevents
// stray taps during the practice-to-completion transition from accidentally dismissing the screen.
// The caller is responsible for having already auto-saved the session — this component does NOT
// save anything; it only handles the close gesture. See LOW_DEMAND_PHASE_2_SPEC.md.
function LowDemandComplete({ onClose }) {
  const graceOverRef = useRef(false);
  useEffect(() => {
    graceOverRef.current = false;
    const timer = setTimeout(() => { graceOverRef.current = true; }, 1500);
    return () => clearTimeout(timer);
  }, []);
  return (
    <div
      onClick={() => {
        if (!graceOverRef.current) return;
        onClose();
      }}
      style={{
        position: "fixed",
        inset: 0,
        display: "flex",
        flexDirection: "column",
        alignItems: "center",
        justifyContent: "center",
        background: "var(--bg)",
        cursor: "pointer",
        padding: 24
      }}>
      <div style={{
        width: 80, height: 80, borderRadius: "50%",
        background: "var(--amber-glow)",
        border: "0.5px solid var(--amber-dim)",
        animation: "pulse 3s ease-in-out infinite",
        marginBottom: 32
      }} />
      <div style={{
        fontFamily: "'IBM Plex Mono', monospace",
        fontSize: 9,
        letterSpacing: "0.18em",
        textTransform: "uppercase",
        color: "var(--text-muted)",
        opacity: 0.6
      }}>
        Tap anywhere to close
      </div>
    </div>
  );
}

function BreatheGroundTool({ onComplete, pathway, quickStart = false, setInfoModal }) {
  // LOW-DEMAND MODE — when bioFilter signals cognitive impairment, the tool renders
  // a stripped variant: no chip rows, no pre/post rating, no bio-filter screen,
  // no Reframe handoff. Audio force-enabled. Per master todo "Low-demand mode"
  // (cognitive-bandwidth-limited population: SSRI users, post-anesthesia, sleep aids,
  // chemo, recreational, sleep-deprived parents, migraine, dissociative episodes, etc).
  // Trigger: isLowDemandBioFilter() — see helper near line 2174 for the full flag set.
  // Architecture: state-of-existing-tool, not separate tool.
  const isLowDemand = (() => {
    try {
      const bf = getActiveBioFilter();
      return isLowDemandBioFilter(bf);
    } catch { return false; }
  })();

  // In low-demand: skip pre-rate (no number to pick), skip bio-filter (already known),
  // jump straight to breathe phase regardless of quickStart.
  const [phase, setPhase] = useState(
    isLowDemand ? "breathe" : (quickStart ? "breathe" : "pre-rate")
  );
  const [preRating, setPreRating] = useState(null);
  const [postRating, setPostRating] = useState(null);
  // May 7, 2026 — closes the asymmetry where Body Scan + Reframe kept the post-state
  // chip for low-demand users (May 7 fixes) but Breathe still short-circuited past it.
  // Set true after the chip is captured (or skip-without-rating) to render
  // <LowDemandComplete>. Mirrors Reframe's pattern at line 8518.
  const [showLowDemandComplete, setShowLowDemandComplete] = useState(false);
  const [bioFilter, setBioFilter] = useState((() => {
    // Pre-select last bio-filter answer if from today's Stillform-day.
    // In low-demand mode we still want the *actual* flag the user marked
    // (pain, sleep, depleted, etc) — not hardcoded "medicated" — so analytics
    // and downstream displays stay accurate.
    // getActiveBioFilter returns "" if stale or missing, otherwise the stored value
    // (which may be a single id like "pain" or a comma-joined string like "depleted,sleep"
    // from morning check-in). The screen below uses single-id state, so pick the first
    // token that matches one of the screen's options.
    try {
      const stored = getActiveBioFilter();
      if (!stored) return isLowDemand ? "medicated" : null; // safety fallback
      const SCREEN_OPTIONS = ["clear", "activated", "depleted", "gut", "sleep", "hormonal", "pain", "medicated"];
      const tokens = String(stored).split(",").map(t => t.trim());
      // Prefer non-clear flags first (they're the clinically meaningful signals).
      const nonClear = tokens.find(t => SCREEN_OPTIONS.includes(t) && t !== "clear");
      if (nonClear) return nonClear;
      const anyMatch = tokens.find(t => SCREEN_OPTIONS.includes(t));
      return anyMatch || (isLowDemand ? "medicated" : null);
    } catch { return isLowDemand ? "medicated" : null; }
  })());
  const [feelState, setFeelState] = useState(() => {
    // Infer from today's check-in if available — user can always override via chips
    try {
      const checkin = JSON.parse(localStorage.getItem("stillform_checkin_today") || "null");
      if (!checkin || checkin.date !== TimeKeeper.stillformDay()) return null;
      const mood = (checkin.mood || "").toLowerCase();
      if (mood.match(/anxious|anxiety|nervous|worried|scared|dread|panic/)) return "anxious";
      if (mood.match(/angry|rage|furious|frustrated|irritat/)) return "angry";
      if (mood.match(/excit|hyped|pumped|happy|joy|great|amazing|wired/)) return "excited";
      return null;
    } catch { return null; }
  });
  const contextEntryRef = useRef(consumePendingSessionEntryContext());
  const [debriefTarget, setDebriefTarget] = useState(null);
  const [scienceCardShown, setScienceCardShown] = useState(false);
  const [nextMoveTarget, setNextMoveTarget] = useState(null);
  const regulationType = (() => {
    try {
      const value = localStorage.getItem("stillform_regulation_type");
      return value === "thought-first" || value === "body-first" ? value : "thought-first";
    } catch {
      return "thought-first";
    }
  })();

  // TIME-TO-REGULATION
  const startTime = useRef(Date.now());
  const latestSessionTimestampRef = useRef(null);
  const formatTime = (ms) => {
    const totalSec = Math.round(ms / 1000);
    const min = Math.floor(totalSec / 60);
    const sec = totalSec % 60;
    return min > 0 ? `${min}m ${sec}s` : `${sec}s`;
  };
  const saveSession = (tools, exitPoint) => {
    const elapsed = Date.now() - startTime.current;
    const timestamp = new Date().toISOString();
    try {
      const ctx = contextEntryRef.current || {};
      appendSessionToStorage({
        timestamp,
        duration: elapsed,
        durationFormatted: formatTime(elapsed),
        tools,
        exitPoint,
        source: "breathe-ground",
        entryMode: ctx.entryMode || null,
        entryProtocolId: ctx.entryProtocolId || null
      });
    } catch {}
    return { elapsed, timestamp };
  };
  const getSessionCount = () => getSessionCountFromStorage();
  const queueDebriefAndCompleteNow = (redirectTo = null, source = "breathe-ground") => {
    setScienceCardShown(false);
    setDebriefTarget({ redirectTo: redirectTo || null, source });
  };
  const queueDebriefAndComplete = (redirectTo = null, source = "breathe-ground") => {
    setNextMoveTarget({ redirectTo: redirectTo || null, source });
  };
  const handleNextMoveConfirm = (nextMove) => {
    const target = nextMoveTarget;
    if (!target) return;
    if (latestSessionTimestampRef.current) {
      saveSessionNextMove(latestSessionTimestampRef.current, nextMove);
    }
    setNextMoveTarget(null);
    queueDebriefAndCompleteNow(target.redirectTo || null, target.source || "breathe-ground-next-move");
  };
  const handleNextMoveSkip = () => {
    const target = nextMoveTarget;
    if (!target) return;
    setNextMoveTarget(null);
    queueDebriefAndCompleteNow(target.redirectTo || null, target.source || "breathe-ground-next-move-skip");
  };
  const completeDebriefGate = (reflectionText) => {
    const skipped = reflectionText === null;
    appendToolDebriefToStorage({
      id: `debrief_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`,
      timestamp: new Date().toISOString(),
      date: TimeKeeper.clockDay(),
      toolId: "breathe",
      toolFamily: getToolFamily("breathe"),
      regulationType,
      source: debriefTarget?.source || "breathe-ground",
      reflectionText: String(reflectionText || "").trim(),
      skipped,
      preState: feelState || null,
      route: debriefTarget?.redirectTo || null
    });
    try { window.plausible("Tool Debrief Completed", { props: { tool: "breathe", skipped: skipped ? "yes" : "no" } }); } catch {}
    const nextRoute = debriefTarget?.redirectTo || undefined;
    setDebriefTarget(null);
    onComplete(nextRoute);
  };

  // --- BREATHE ---
  const savedPatternId = (() => { try { return localStorage.getItem("stillform_breath_pattern") || "quick"; } catch { return "quick"; } })();
  const [patternId] = useState(savedPatternId);
  const pattern = BREATHING_PATTERNS.find(p => p.id === patternId) || BREATHING_PATTERNS[0];
  const phases = pattern.phases;

  const [started, setStarted] = useState(false);

  const totalCycles = 3; // 3 cycles then check in — don't force more
  const [phaseIdx, setPhaseIdx] = useState(0);
  const [count, setCount] = useState(phases[0].duration);
  const [cycle, setCycle] = useState(1);
  const [running, setRunning] = useState(false);
  const [breatheDone, setBreatheDone] = useState(false);

  const [keepGoing, setKeepGoing] = useState(false);

  // Audio
  const [audioOn, setAudioOn] = useState(() => {
    // Low-demand mode force-enables audio (paced auditory cueing is mechanism, not preference).
    if (isLowDemand) return true;
    try { return localStorage.getItem("stillform_audio") === "on"; } catch { return false; }
  });
  const audioCtx = useRef(null);
  const activeOsc = useRef(null);

  useEffect(() => {
    try {
      audioCtx.current = new (window.AudioContext || window.webkitAudioContext)();
      if (audioCtx.current.state === "suspended") audioCtx.current.resume();
    } catch {}
    return () => {
      try {
        if (activeOsc.current) { activeOsc.current.stop(); activeOsc.current = null; }
        if (audioCtx.current) audioCtx.current.close();
      } catch {}
    };
  }, []);

  const toggleAudio = () => {
    const next = !audioOn;
    setAudioOn(next);
    try { localStorage.setItem("stillform_audio", next ? "on" : "off"); } catch {}
    if (next && audioCtx.current?.state === "suspended") audioCtx.current.resume();
  };

  useEffect(() => {
    if (!running || breatheDone || !audioCtx.current || !audioOn) return;
    const ctx = audioCtx.current;
    if (ctx.state === "suspended") ctx.resume();
    try { if (activeOsc.current) { activeOsc.current.stop(); activeOsc.current = null; } } catch {}

    const p = phases[phaseIdx];
    if (p.name === "Rest") return;

    try {
      const osc = ctx.createOscillator();
      const gain = ctx.createGain();
      osc.type = "sine";
      osc.connect(gain);
      gain.connect(ctx.destination);
      const now = ctx.currentTime;
      const dur = p.duration;

      if (p.name === "Inhale") {
        osc.frequency.setValueAtTime(180, now);
        osc.frequency.linearRampToValueAtTime(280, now + dur);
        gain.gain.setValueAtTime(0, now);
        gain.gain.linearRampToValueAtTime(0.08, now + 0.5);
        gain.gain.setValueAtTime(0.08, now + dur - 0.3);
        gain.gain.linearRampToValueAtTime(0, now + dur);
      } else if (p.name === "Hold") {
        osc.frequency.setValueAtTime(280, now);
        gain.gain.setValueAtTime(0, now);
        gain.gain.linearRampToValueAtTime(0.05, now + 0.3);
        gain.gain.setValueAtTime(0.05, now + dur - 0.3);
        gain.gain.linearRampToValueAtTime(0, now + dur);
      } else if (p.name === "Exhale") {
        osc.frequency.setValueAtTime(280, now);
        osc.frequency.linearRampToValueAtTime(140, now + dur);
        gain.gain.setValueAtTime(0, now);
        gain.gain.linearRampToValueAtTime(0.08, now + 0.3);
        gain.gain.linearRampToValueAtTime(0.02, now + dur - 0.5);
        gain.gain.linearRampToValueAtTime(0, now + dur);
      }
      osc.start(now);
      osc.stop(now + dur);
      activeOsc.current = osc;
    } catch {}
  }, [phaseIdx, running, breatheDone, audioOn]);

  useEffect(() => {
    if (!running) return;
    if (count === 0) {
      const next = (phaseIdx + 1) % phases.length;
      if (next === 0) {
        const newCycle = cycle + 1;
        if (!keepGoing && newCycle > totalCycles) {
          setBreatheDone(true);
          setRunning(false);
          haptic.complete();
          // May 7, 2026 — Low-demand: route directly to post-rate in the same React
          // batch as setBreatheDone(true) so the chip-capture screen renders without
          // a flash of empty UI between breath-complete and post-rate. Skips the
          // 3-option "Three rounds done — Ground / Keep going / Stop here" screen
          // (cognitive demand the cohort doesn't have). Mirrors Body Scan + Reframe
          // May 7 close-flow fixes. Session saved here so post-rate has the timestamp.
          if (isLowDemand) {
            const saved = saveSession(["breathe"], "low-demand-complete");
            if (saved?.timestamp) latestSessionTimestampRef.current = saved.timestamp;
            setPhase("post-rate");
          }
          return;
        }
        if (keepGoing && newCycle > totalCycles + 3) {
          setBreatheDone(true);
          setRunning(false);
          haptic.complete();
          // Same low-demand auto-route in the keepGoing path.
          if (isLowDemand) {
            const saved = saveSession(["breathe"], "low-demand-complete");
            if (saved?.timestamp) latestSessionTimestampRef.current = saved.timestamp;
            setPhase("post-rate");
          }
          return;
        }
        setCycle(newCycle);
      }
      haptic.tick();
      setPhaseIdx(next);
      setCount(phases[next].duration);
    } else {
      const t = setTimeout(() => setCount(c => c - 1), 1000);
      return () => clearTimeout(t);
    }
  }, [count, running, phaseIdx, cycle, keepGoing, isLowDemand]);

  // --- GROUND ---
  const steps = [
    { num: 5, sense: "See", label: "5 things you can see", prompt: "Look around. Name them quietly." },
    { num: 4, sense: "Touch", label: "4 things you can touch", prompt: "Feel what's around you right now." },
    { num: 3, sense: "Hear", label: "3 things you can hear", prompt: "Listen. What sounds are there?" },
    { num: 2, sense: "Smell", label: "2 things you can smell", prompt: "What scents are here, even faint?" },
    { num: 1, sense: "Taste", label: "1 thing you can taste", prompt: "What do you taste right now?" }
  ];
  const [current, setCurrent] = useState(0);
  const [answers, setAnswers] = useState({});
  const [groundDone, setGroundDone] = useState(false);
  const [groundStepStart, setGroundStepStart] = useState(Date.now());
  const [groundData, setGroundData] = useState([]);
  const [showGroundWrite, setShowGroundWrite] = useState(false);

  const progress = ((cycle - 1) * phases.length + phaseIdx) / (totalCycles * phases.length);
  const bgtBreathScale = (phaseIdx === 0 || phaseIdx === 1) ? 1 : 0;
  const bgtVisualGrounding = (() => { try { return localStorage.getItem("stillform_visual_grounding") !== "off"; } catch { return true; } })();

  const groundSavedRef = useRef(false);
  const groundElapsedRef = useRef(0);
  const groundAutoRef = useRef(false);
  if (nextMoveTarget) {
    return (
      <NextMoveStep
        description="Choose one concrete action while this reset is still fresh."
        onConfirm={handleNextMoveConfirm}
        onSkip={handleNextMoveSkip}
      />
    );
  }
  if (debriefTarget) {
    if (!scienceCardShown) {
      return (
        <ScienceCard
          toolId="breathe"
          lastBreathPattern={breathPattern || null}
          feelStateBefore={debriefTarget.preState || feelState || null}
          feelStateAfter={debriefTarget.postState || null}
          sessionCount={getSessionCountFromStorage()}
          onContinue={() => setScienceCardShown(true)}
        />
      );
    }
    return (
      <ToolDebriefGate
        toolId="breathe"
        regulationType={regulationType}
        onContinue={completeDebriefGate}
      />
    );
  }
  if (groundDone) {
    if (!groundSavedRef.current) {
      groundSavedRef.current = true;
      const saved = saveSession(["breathe", "ground"], "grounding-complete");
      groundElapsedRef.current = saved?.elapsed || 0;
      latestSessionTimestampRef.current = saved?.timestamp || null;
    }
    if (!groundAutoRef.current) {
      groundAutoRef.current = true;
    }
    const elapsed = groundElapsedRef.current;
    const count = getSessionCount();
    const signalProfile = (() => { try { return secureRead("stillform_signal_profile", null); } catch { return null; } })();
    const lastShift = (() => { try { return JSON.parse(localStorage.getItem("stillform_last_shift") || "null"); } catch { return null; } })();
    return (
      <div className="complete">
        <div className="complete-icon" style={{ animation: "pulse 1.2s ease-in-out 3" }}>✓</div>
        <h2>Composure restored.</h2>
        <div className="t-mono-xs" style={{ marginBottom: 16 }}>
          System calibrated · {formatTime(elapsed)}
        </div>
        {signalProfile?.firstAreas?.length > 0 && (
          <div style={{ background: "var(--surface)", border: "0.5px solid var(--amber-dim)", borderRadius: "var(--r)", padding: "12px 16px", marginBottom: 16, textAlign: "left" }}>
            <div style={{ fontFamily: "'IBM Plex Mono', monospace", fontSize: 8, letterSpacing: "0.2em", textTransform: "uppercase", color: "var(--amber)", marginBottom: 8 }}>Signal Shift</div>
            {signalProfile.firstAreas.slice(0, 3).map(area => (
              <div key={area} style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 5 }}>
                <span className="t-mono-sm">{area}</span>
                <span style={{ fontFamily: "'IBM Plex Mono', monospace", fontSize: 10, color: "var(--amber)" }}>Protocol complete</span>
              </div>
            ))}
            {lastShift !== null && lastShift > 0 && (
              <div className="t-mono-xs" style={{ marginTop: 8, paddingTop: 8, borderTop: "0.5px solid var(--border)", color: "var(--amber)", letterSpacing: "0.1em" }}>
                STATE SHIFT +{lastShift} · FUNCTIONAL
              </div>
            )}
          </div>
        )}
        {count > 1 && <div className="t-mono-xs" style={{ letterSpacing: "0.1em", marginBottom: 16 }}>SESSION {count}</div>}
        {count === 1 && (
          <div style={{ background: "var(--surface)", border: "0.5px solid var(--amber-dim)", borderRadius: "var(--r)", padding: "14px 18px", marginBottom: 16, textAlign: "center" }}>
            <div className="t-mono-xs" style={{ color: "var(--amber)", marginBottom: 6 }}>First calibration</div>
            <div className="t-body-sm quiet" style={{ lineHeight: 1.5 }}>System is learning you. Each session sharpens the read.</div>
          </div>
        )}
        {/* Physiology naming — names what happened in the nervous system.
            Per May 5 prelaunch gap audit: session-1 retention hinges on users
            feeling something specific happened. Brief, science-grounded. */}
        <div style={{
          fontSize: 12,
          color: "var(--text-muted)",
          lineHeight: 1.6,
          marginBottom: 16,
          textAlign: "center",
          maxWidth: 360,
          margin: "0 auto 16px"
        }}>
          You engaged your parasympathetic nervous system through paced breathing and somatic grounding. Practice strengthens the pathway.
        </div>
        <div style={{ display: "flex", flexDirection: "column", gap: 8, width: "100%" }}>
          <button className="btn btn-primary" onClick={() => queueDebriefAndComplete("reframe-calm", "grounding-complete-continue")}>
            Continue to Reframe →
          </button>
          <button className="btn btn-ghost" style={{ fontSize: 12 }} onClick={() => queueDebriefAndComplete(undefined, "grounding-complete-exit")}>
            Exit session
          </button>
        </div>
        
      </div>
    );
  }

  const confirmGroundStep = () => {
    const timeOnStep = Date.now() - groundStepStart;
    const entry = {
      step: current + 1,
      sense: steps[current].sense,
      timeMs: timeOnStep,
      wrote: !!(answers[current] || "").trim(),
      text: (answers[current] || "").trim() || null
    };
    const updated = [...groundData, entry];
    setGroundData(updated);
    setShowGroundWrite(false);

    if (current < steps.length - 1) {
      setCurrent(c => c + 1);
      setGroundStepStart(Date.now());
    } else {
      // Save grounding engagement data
      try {
        const gd = secureRead("stillform_grounding_data", []);
        gd.push({ timestamp: new Date().toISOString(), steps: updated, skipped: false, totalMs: updated.reduce((s, e) => s + e.timeMs, 0) });
        secureWrite("stillform_grounding_data", gd);
      } catch {}
      setGroundDone(true);
    }
  };

  const skipGrounding = () => {
    const timeOnStep = Date.now() - groundStepStart;
    try {
      const gd = secureRead("stillform_grounding_data", []);
      gd.push({ timestamp: new Date().toISOString(), steps: [...groundData, { step: current + 1, sense: steps[current].sense, timeMs: timeOnStep, wrote: false, text: null }], skipped: true, skippedAt: current + 1, totalMs: groundData.reduce((s, e) => s + e.timeMs, 0) + timeOnStep });
      secureWrite("stillform_grounding_data", gd);
    } catch {}
    setGroundDone(true);
  };

  if (phase === "ground") return (
    <div>
      <div style={{ fontSize: 11, letterSpacing: "0.14em", textTransform: "uppercase", color: "var(--amber)", marginBottom: 24, textAlign: "center" }}>
        Grounding — step {current + 1} of 5
      </div>
      <div style={{ background: "var(--surface)", borderRadius: "var(--r-lg)", padding: "24px 20px", marginBottom: 20, textAlign: "center" }}>
        <div style={{ fontSize: 36, color: "var(--amber)", marginBottom: 8 }}>{steps[current].num}</div>
        <div style={{ fontSize: 20, color: "var(--text)", fontWeight: 500, marginBottom: 8 }}>
          {steps[current].label}
        </div>
        <div className="t-body-md quiet" style={{ marginBottom: 20 }}>
          {steps[current].prompt}
        </div>

        <button
          className="btn btn-primary"
          style={{ width: "100%", fontSize: 15, padding: "14px 0", marginBottom: 10 }}
          onClick={confirmGroundStep}
        >
          {current < steps.length - 1 ? `Found ${steps[current].num} ✓` : "Done ✓"}
        </button>

        {!showGroundWrite ? (
          <button onClick={() => setShowGroundWrite(true)} style={{
            background: "none", border: "none", color: "var(--text-muted)", fontSize: 11,
            cursor: "pointer", fontFamily: "'DM Sans', sans-serif"
          }}>
            I want to write them down
          </button>
        ) : (
          <div style={{ marginTop: 12 }}>
            <div style={{ display: "flex", gap: 6 }}>
              <textarea
                className="ground-input"
                rows={2}
                placeholder="Write or speak what you noticed..."
                value={answers[current] || ""}
                onChange={e => setAnswers(a => ({ ...a, [current]: e.target.value }))}
                style={{ flex: 1, fontSize: 13 }}
                autoFocus
              />
              <MicButton onTranscript={t => setAnswers(a => ({ ...a, [current]: (a[current] || "") + (a[current] ? " " : "") + t }))} />
            </div>
          </div>
        )}
      </div>

      {current < steps.length - 1 && (
        <button onClick={skipGrounding} style={{
          background: "none", border: "none", color: "var(--text-muted)", fontSize: 12,
          cursor: "pointer", fontFamily: "'DM Sans', sans-serif", width: "100%", textAlign: "center"
        }}>
          Skip grounding
        </button>
      )}

      <div style={{ display: "flex", gap: 4, justifyContent: "center", marginTop: 16 }}>
        {steps.map((_, i) => (
          <div key={i} style={{ width: 8, height: 8, borderRadius: "50%", background: i <= current ? "var(--amber)" : "var(--border)", transition: "all 0.3s" }} />
        ))}
      </div>
    </div>
  );

  // Pre-rate: quick 1-5 tap
  if (phase === "pre-rate") return (
    <div style={{ maxWidth: 400, margin: "0 auto", textAlign: "center" }}>
      <h2 className="t-display-lg" style={{ marginBottom: 8 }}>
        How steady are you?
      </h2>
      {(() => { try { const s = JSON.parse(localStorage.getItem("stillform_last_shift") || "null"); if (s) return <div style={{ fontSize: 13, color: s > 0 ? "var(--amber)" : "var(--text-muted)", marginBottom: 16, fontWeight: s > 0 ? 500 : 400 }}>Last session: {s > 0 ? "+" : ""}{s}</div>; } catch {} return null; })()}
      <div style={{ display: "flex", justifyContent: "space-between", marginBottom: 8, padding: "0 6px" }}>
        <span style={{ fontSize: 10, color: "var(--text-muted)", letterSpacing: "0.06em", textTransform: "uppercase" }}>Reactive</span>
        <span style={{ fontSize: 10, color: "var(--text-muted)", letterSpacing: "0.06em", textTransform: "uppercase" }}>Composed</span>
      </div>
      <div style={{ display: "flex", gap: 12, justifyContent: "center", marginBottom: 24 }}>
        {[1, 2, 3, 4, 5].map(n => (
          <button key={n} onClick={() => { setPreRating(n); setPhase("bio-filter"); }} style={{
            width: 56, height: 56, borderRadius: "50%", border: "1px solid var(--border)",
            background: "var(--surface)", color: "var(--text)", fontSize: 20, fontWeight: 500,
            cursor: "pointer", fontFamily: "'DM Sans', sans-serif", transition: "all 0.15s",
            WebkitTapHighlightColor: "transparent"
          }}>{n}</button>
        ))}
      </div>
      {/* Pre-regulation chips removed per Nook 2021 + 2024-2025 replications:
          emotion labeling before regulation crystallizes affective state and impedes
          subsequent reappraisal/mindful acceptance. Affect labeling now lives post-regulation only. */}
    </div>
  );

  // Bio-filter — physical state check before session
  // Decision 4 (May 2): required gate — Skip removed. Pre-selection from getActiveBioFilter
  // honors today's prior reading so the user confirms in one tap rather than re-entering.
  // Decision 5b: when Pain is selected, route to "bio-filter-suggest-scan" sub-phase
  // showing the BioFilterSuggestion-style soft suggestion to switch to Body Scan
  // (Eccleston & Crombez 1999 — pain demands attentional resources before cognition lands).
  if (phase === "bio-filter-suggest-scan") return (
    <div style={{ maxWidth: 400, margin: "0 auto" }}>
      <h2 className="t-display-md" style={{ marginBottom: 6 }}>
        Quick check before Breathe.
      </h2>
      <div className="t-mono-xs" style={{ marginBottom: 16 }}>
        Pain present
      </div>
      <div className="t-body-sm quiet" style={{ lineHeight: 1.7, marginBottom: 20 }}>
        Pain pulls cognitive resources before you can think clearly. A short body scan locates and softens it first — that's the most effective sequence the research supports. You opened Breathe, but Body Scan is the closer fit right now.
      </div>
      <button onClick={() => onComplete("scan")} style={{
        width: "100%", padding: "14px 18px",
        background: "var(--surface)", border: "0.5px solid var(--amber-dim)",
        borderRadius: "var(--r)", cursor: "pointer",
        fontFamily: "'DM Sans', sans-serif", textAlign: "left",
        WebkitTapHighlightColor: "transparent", marginBottom: 8
      }}>
        <div style={{ fontSize: 14, fontWeight: 500, color: "var(--amber)", marginBottom: 2 }}>Body Scan first</div>
        <div style={{ fontSize: 11, color: "var(--text-muted)", letterSpacing: "0.04em" }}>Locate the signal, then breathe.</div>
      </button>
      <button onClick={() => setPhase("breathe")} style={{
        width: "100%", padding: "10px 18px",
        background: "transparent", border: "0.5px solid var(--border)",
        borderRadius: "var(--r)", cursor: "pointer",
        fontFamily: "'DM Sans', sans-serif", textAlign: "left",
        color: "var(--text-muted)", fontSize: 13,
        WebkitTapHighlightColor: "transparent", marginBottom: 12
      }}>
        Continue to Breathe anyway
      </button>
      <button onClick={() => setInfoModal({
        title: "Why Body Scan first?",
        body: "Pain demands attentional resources before cognition can do its work (Eccleston & Crombez, 1999). A short body scan is the most-researched intervention — Kabat-Zinn (1982) MBSR, Reiner et al. (2013) showed measurable pain reduction from a 10-minute scan, and Farb et al. (2013) showed it shifts processing from cognitive evaluation to bottom-up sensing. This is a state-based suggestion. Your processing type is unchanged."
      })} style={{
        background: "none", border: "none", color: "var(--text-muted)", fontSize: 11, cursor: "pointer",
        fontFamily: "'IBM Plex Mono', monospace", letterSpacing: "0.1em", textTransform: "uppercase"
      }}>
        ⓘ Why
      </button>
    </div>
  );

  // Bio-filter — physical state check before session
  if (phase === "bio-filter") return (
    <div style={{ maxWidth: 400, margin: "0 auto" }}>
      <h2 style={{ fontFamily: "'Cormorant Garamond', serif", fontSize: 32, fontWeight: 300, marginBottom: 6 }}>
        State read.
      </h2>
      <div className="t-mono-xs" style={{ marginBottom: 20 }}>
        <span>Bio-filter · What is your hardware running right now?</span> <button aria-label="Why the bio-filter?" onClick={() => setInfoModal({ title: "Why the bio-filter?", body: "Physical state directly alters emotional perception. Sleep debt amplifies threat detection. Pain demands attentional resources. Hormonal shifts change affective baseline. This check prevents the system from misreading a biological signal as an emotional one.\n\nThe deeper mechanism: the brain runs on prediction. It takes interoceptive signals from the body and uses them to predict what's happening — emotion is partly the brain's interpretation of those signals (Seth 2013; Barrett & Simmons 2015). When you mark depleted, in pain, sleep-deprived, the system carries that hardware state into how your input is read. The same situation interpreted through a depleted body is a different prediction than the same situation interpreted through a rested body. Bio-filter doesn't just filter responses — it updates the brain's working model of itself." })} style={{ background: "none", border: "none", color: "var(--text-muted)", cursor: "pointer", fontSize: 13, padding: "0 4px", lineHeight: 1 }}>ⓘ</button>
      </div>
      <div className="t-body-sm quiet" style={{ lineHeight: 1.6, marginBottom: 20 }}>
        Physical state colors perception. The AI filters your input through this — so the read is accurate, not assumed.{bioFilter && <span style={{ display: "block", marginTop: 8, fontSize: 11, color: "var(--text-muted)", fontFamily: "'IBM Plex Mono', monospace", letterSpacing: "0.04em" }}>Your last reading is highlighted — confirm or update.</span>}
      </div>
      <div style={{ display: "flex", flexDirection: "column", gap: 6, marginBottom: 20 }}>
        {[
          { id: "clear", label: "Baseline", desc: "System nominal — no flags", icon: "◎" },
          { id: "activated", label: "Activated", desc: "Adrenaline, butterflies, energy surging", icon: "⚡" },
          { id: "depleted", label: "Low capacity", desc: "Fatigue, low energy, heavy body", icon: "◌" },
          { id: "gut", label: "Gut signal", desc: "Digestive noise — gut-brain axis active", icon: "◉" },
          { id: "sleep", label: "Under-rested", desc: "Your brain is running slower than usual", icon: "◐" },
          { id: "hormonal", label: "Hormonal shift", desc: "Cycle, inflammation, or hormonal fluctuation", icon: "◑" },
          { id: "pain", label: "Pain active", desc: "Chronic or acute — affecting state", icon: "◈" },
          { id: "medicated", label: "Substance active", desc: "Caffeine, meds, alcohol, or other input", icon: "◇" },
        ].map(opt => (
          <button key={opt.id} onClick={() => {
            setBioFilter(opt.id);
            setActiveBioFilter(opt.id);
            // Decision 5b: Pain inside Breathe → suggest Body Scan instead.
            // User can switch (clinical fit) or continue to Breathe (autonomy preserved).
            if (opt.id === "pain") {
              setPhase("bio-filter-suggest-scan");
            } else {
              setPhase("breathe");
            }
          }} style={{
            width: "100%", background: bioFilter === opt.id ? "var(--amber-glow)" : "var(--surface)",
            border: `0.5px solid ${bioFilter === opt.id ? "var(--amber-dim)" : "var(--border)"}`,
            borderRadius: "var(--r)", padding: "12px 16px", cursor: "pointer",
            display: "flex", alignItems: "center", gap: 12, textAlign: "left",
            boxShadow: "inset 0 1px 0 rgba(255,255,255,0.025)",
            WebkitTapHighlightColor: "transparent"
          }}>
            <span style={{ fontFamily: "'IBM Plex Mono', monospace", fontSize: 14, color: "var(--amber)", flexShrink: 0 }}>{opt.icon}</span>
            <div>
              <div style={{ fontSize: 13, fontWeight: 500, color: "var(--text)", marginBottom: 2 }}>{opt.label}</div>
              <div style={{ fontFamily: "'IBM Plex Mono', monospace", fontSize: 9, color: "var(--text-muted)", letterSpacing: "0.08em" }}>{opt.desc}</div>
            </div>
          </button>
        ))}
      </div>
      {/* Skip button removed — Decision 4 (May 2): bio-filter is now required.
          Pre-selection from today's prior reading reduces friction; the gate is on engagement,
          not on a specific answer. User can still confirm "Baseline" with one tap if accurate. */}
    </div>
  );

  // Breathe phase
  if (!started && phase === "breathe") {
    setStarted(true);
    setRunning(true);
    watchBridge.startBreathing(patternId);
    return null;
  }

  // May 7, 2026 — Low-demand close: after the user taps a post-rate chip (or
  // skips rating), this branch fires and renders the shared tap-to-close screen.
  // No debrief, no Next Move, no Lock-in. The chip is captured (affect labeling
  // mechanism preserved per Lieberman 2007); everything downstream is dropped.
  // Mirrors Reframe's early-return at line 9557.
  if (showLowDemandComplete) {
    return <LowDemandComplete onClose={() => onComplete(undefined)} />;
  }

  return (
    <div>
      {!breatheDone ? (
        <div className="breath-container" style={{ position: "relative", overflow: "hidden" }}>
          {bgtVisualGrounding && <FractalBreathCanvas breathScale={bgtBreathScale} />}
          <div className="breath-circle-wrap">
            <svg className="breath-svg-ring" viewBox="0 0 280 280">
              {/* Tick marks — cardinal */}
              <g stroke="rgba(255,255,255,0.06)" strokeWidth="1" transform="rotate(90 140 140)">
                <line x1="140" y1="5" x2="140" y2="18"/>
                <line x1="275" y1="140" x2="262" y2="140"/>
                <line x1="140" y1="275" x2="140" y2="262"/>
                <line x1="5" y1="140" x2="18" y2="140"/>
              </g>
              {/* Micro ticks every 30deg */}
              <g stroke="rgba(255,255,255,0.03)" strokeWidth="0.5" transform="rotate(90 140 140)">
                {[30,60,120,150,210,240,300,330].map(deg => {
                  const rad = (deg * Math.PI) / 180;
                  const x1 = 140 + 131 * Math.cos(rad);
                  const y1 = 140 + 131 * Math.sin(rad);
                  const x2 = 140 + 122 * Math.cos(rad);
                  const y2 = 140 + 122 * Math.sin(rad);
                  return <line key={deg} x1={x1} y1={y1} x2={x2} y2={y2}/>;
                })}
              </g>
              <circle className="breath-ring-track" cx="140" cy="140" r="125"/>
              <circle
                className="breath-ring-arc"
                cx="140" cy="140" r="125"
                style={{
                  strokeDasharray: 785,
                  strokeDashoffset: phase === "exhale" ? 785 : phase === "rest" ? 196 : 0,
                  '--breath-duration': `${phases[phase]?.duration || 4}s`
                }}
              />
              <circle cx="140" cy="140" r="106" fill="none" stroke="rgba(255,255,255,0.025)" strokeWidth="0.5"/>
            </svg>
            <div className="breath-inner">
              <span className="breath-count">{count}</span>
              <span className="breath-phase">{phases[phase]?.label}</span>
            </div>
          </div>
          <div className="breath-instruction" style={{ marginTop: 8 }}>{phases[phaseIdx].instruction}</div>
          <div className="t-body-sm quiet" style={{ marginTop: 4, marginBottom: 12 }}>
            Round {cycle} of {totalCycles}
          </div>
          <button onClick={toggleAudio} style={{
            background: audioOn ? "var(--amber-glow)" : "var(--surface)",
            border: `1px solid ${audioOn ? "var(--amber-dim)" : "var(--border)"}`,
            borderRadius: 20, padding: "6px 14px", fontSize: 11, cursor: "pointer",
            color: audioOn ? "var(--amber)" : "var(--text-dim)", fontFamily: "'DM Sans', sans-serif",
            marginBottom: 12, transition: "all 0.2s"
          }}>
            {audioOn ? "♪ Sound on" : "♪ Sound off"}
          </button>
          {/* Pattern name shown, no mid-session change — user picks at start */}
          <div style={{ fontSize: 11, color: "var(--text-muted)", marginBottom: 16, letterSpacing: "0.04em", fontFamily: "'DM Sans', sans-serif" }}>
            {pattern.name}
          </div>
          {!running ? (
            <button className="btn btn-primary" style={{ fontSize: 16, padding: "14px 40px" }} onClick={() => setRunning(true)}>
              Begin
            </button>
          ) : (
            <button className="btn btn-ghost" style={{ fontSize: 13 }} onClick={() => setRunning(false)}>
              Pause
            </button>
          )}
        </div>
      ) : (
        // Normal-mode "Three rounds done" choice screen.
        // Low-demand users never see this — the auto-route useEffect transitions
        // them straight from breatheDone → post-rate, skipping the choice screen
        // (which is itself cognitive demand the cohort doesn't have).
        // The useEffect fires before this JSX has a chance to render for low-demand
        // users; this branch is gated on !isLowDemand as belt-and-suspenders.
        !isLowDemand && (
        <div className="complete">
          <div className="complete-icon">✓</div>
          <h2>Three rounds done.</h2>
          <p style={{ marginBottom: 24 }}>Nervous system recalibrating. Continue or move on.</p>
          <div style={{ display: "flex", flexDirection: "column", gap: 10 }}>
            <button className="btn btn-primary" onClick={() => setPhase("ground")}>
              Ground now →
            </button>
            <button className="btn btn-ghost" onClick={() => {
              setKeepGoing(true);
              setBreatheDone(false);
              setRunning(true);
            }}>
              Keep going
            </button>
            <button className="btn btn-ghost" onClick={() => {
              const saved = saveSession(["breathe"], "breathing-only");
              latestSessionTimestampRef.current = saved?.timestamp || null;
              setPhase("post-rate");
            }} style={{ color: "var(--text-dim)", fontSize: 13 }}>
              Stop here
            </button>
          </div>
        </div>
        )
      )}

      {/* POST-RATE */}
      {phase === "post-rate" && (
        <div style={{ maxWidth: 400, margin: "0 auto", textAlign: "center" }}>
          <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 8 }}>
            <h2 className="t-display-lg" style={{ margin: 0 }}>
              Where are you now?
            </h2>
            <button aria-label="Why track this?" onClick={() => setInfoModal({ title: "Why track this?", body: "Tracking your state after a session measures the shift. The difference between how you came in and how you leave is the data point that builds your composure pattern over time." })} style={{ background: "none", border: "none", color: "var(--text-muted)", cursor: "pointer", fontSize: 13, padding: "0 4px", lineHeight: 1 }}>ⓘ</button>
          </div>
          <div style={{ display: "flex", justifyContent: "space-between", marginBottom: 8, padding: "0 6px" }}>
            <span style={{ fontSize: 10, color: "var(--text-muted)", letterSpacing: "0.06em", textTransform: "uppercase" }}>Reactive</span>
            <span style={{ fontSize: 10, color: "var(--text-muted)", letterSpacing: "0.06em", textTransform: "uppercase" }}>Composed</span>
          </div>
          <div style={{ display: "flex", gap: 12, justifyContent: "center", marginBottom: 24 }}>
            {[1, 2, 3, 4, 5].map(n => (
              <button key={n} onClick={() => {
                setPostRating(n);
                const delta = n - (preRating || n);
                try {
                  localStorage.setItem("stillform_last_shift", JSON.stringify(delta));
                  // Save ratings back into the most recent session record
                  const sessions = getSessionsFromStorage();
                  if (sessions.length > 0) {
                    sessions[sessions.length - 1].preRating = preRating || null;
                    sessions[sessions.length - 1].postRating = n;
                    sessions[sessions.length - 1].delta = delta;
                    setSessionsInStorage(sessions);
                  }
                } catch {}
              }} style={{
                width: 56, height: 56, borderRadius: "50%",
                border: `2px solid ${postRating === n ? "var(--amber)" : "var(--border)"}`,
                background: postRating === n ? "var(--amber-glow)" : "var(--surface)",
                color: postRating === n ? "var(--amber)" : "var(--text)", fontSize: 20, fontWeight: 500,
                cursor: "pointer", fontFamily: "'DM Sans', sans-serif", transition: "all 0.15s",
                WebkitTapHighlightColor: "transparent"
              }}>{n}</button>
            ))}
          </div>
          {postRating && preRating && (() => {
            const delta = postRating - preRating;
            const driftPct = preRating > 0 ? Math.round((delta / preRating) * 100) : 0;
            return (
              <div style={{ marginBottom: 24, animation: delta > 0 ? "deltaFlash 0.5s ease-out" : "none" }}>
                <div style={{
                  fontSize: 48, fontFamily: "'Cormorant Garamond', serif", fontWeight: 300,
                  color: delta > 0 ? "var(--amber)" : delta === 0 ? "var(--text-dim)" : "var(--text-muted)",
                  marginBottom: 4, lineHeight: 1,
                  animation: delta > 0 ? "deltaGlow 0.8s ease-out forwards" : "none"
                }}>
                  {delta > 0 ? `+${delta}` : delta === 0 ? "0" : `${delta}`}
                </div>
                <div style={{ fontSize: 12, color: "var(--text-muted)", letterSpacing: "0.08em", textTransform: "uppercase", marginBottom: delta > 0 ? 8 : 0 }}>
                  {delta >= 3 ? "Significant shift" : delta === 2 ? "Composure increased" : delta === 1 ? "Slight improvement" : delta === 0 ? "Baseline held" : delta === -1 ? "Holding" : "Run again"}
                </div>
                {delta > 0 && (
                  <div style={{ fontFamily: "'IBM Plex Mono', monospace", fontSize: 11, color: "var(--amber)", letterSpacing: "0.14em" }}>
                    SIGNAL DRIFT: -{driftPct}%
                  </div>
                )}
              </div>
            );
          })()}
          {/* Build #5 Phase 3 — Breathe close longitudinal context. ONE line,
              not a full PRACTICE TREND block, because the existing 48px +N
              display above already serves as the per-session credit headline.
              This adds the weekly-frequency claim that the existing surface
              doesn't have. Renders only on positive shifts with frequency >= 2.
              Returns null in all other paths (sparse data, negative delta,
              first-of-kind shift) — silent rather than fabricated. */}
          {postRating && preRating && (() => {
            try {
              const delta = postRating - preRating;
              if (delta <= 0) return null;
              const liveSession = {
                tools: ["breathe"],
                preRating,
                postRating,
                delta,
                timestamp: null
              };
              const credit = computeAchievement(liveSession);
              if (!credit?.context) return null;
              return (
                <div className="t-mono-xs" style={{
                  color: "var(--text-muted)",
                  letterSpacing: "0.08em",
                  textAlign: "center",
                  marginBottom: 16,
                  fontSize: 10
                }}>
                  {credit.context}
                </div>
              );
            } catch { return null; }
          })()}
          {postRating && (() => {
            const delta = postRating - preRating;
            // May 7, 2026 — auto-advance to ground only for normal-mode positive shifts.
            // Low-demand users skip the grounding flow entirely (it's another tool;
            // the cohort came in to do ONE thing and is done). They go to LowDemandComplete
            // via the Done button below.
            if (delta > 0 && !isLowDemand) {
              setTimeout(() => setPhase("ground"), 1500);
            }
            // Low-demand close — single "Done" tap → LowDemandComplete. No Try again
            // (cognitive demand: would the user evaluate whether to repeat?), no Skip
            // to Reframe (separate tool routing decision), no Exit session (different
            // copy for the same outcome). One button, one outcome. Mirrors the spec
            // intent: lowest-demand metacognitive act preserved as one tap.
            if (isLowDemand) {
              return (
                <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>
                  <button className="btn btn-primary" onClick={() => setShowLowDemandComplete(true)}>
                    Done
                  </button>
                </div>
              );
            }
            return (
              <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>
                {delta <= 0 ? (
                  <>
                    <button className="btn btn-primary" onClick={() => { setPhase("breathe"); setStarted(false); setBreatheDone(false); setPostRating(null); }}>Try again</button>
                    <button className="btn btn-ghost" onClick={() => queueDebriefAndComplete(undefined, "post-rate-done-for-now")}>Done for now</button>
                  </>
                ) : (
                  <>
                    <div className="t-mono-sm" style={{ color: "var(--amber)", marginBottom: 8 }}>Stabilized</div>
                    <div className="t-body-sm faint" style={{ textAlign: "center", animation: "pulse 1s ease-in-out infinite" }}>
                      Moving to grounding…
                    </div>
                    <button className="btn btn-ghost" onClick={() => queueDebriefAndComplete("reframe-calm", "post-rate-skip-to-reframe")} style={{ fontSize: 13 }}>Skip to Reframe instead</button>
                    <button className="btn btn-ghost" onClick={() => queueDebriefAndComplete(undefined, "post-rate-exit")} style={{ color: "var(--text-muted)", fontSize: 12 }}>Exit session</button>
                  </>
                )}
              </div>
            );
          })()}
        </div>
      )}
    </div>
  );
}

function BodyScanTool({ onComplete, setInfoModal }) {
  // LOW-DEMAND MODE — when bioFilter signals cognitive impairment, the tool renders
  // a stripped variant: no intro screen, no tension dot input, no What Shifted gate,
  // no ToolDebriefGate, no Next Move. Audio force-enabled. See LOW_DEMAND_PHASE_2_SPEC.md.
  // Trigger broadened May 6, 2026 — see isLowDemandBioFilter helper near line 2174.
  const isLowDemand = (() => {
    try {
      const bf = getActiveBioFilter();
      return isLowDemandBioFilter(bf);
    } catch { return false; }
  })();
  // TIME-TO-REGULATION
  const startTime = useRef(Date.now());
  const latestSessionTimestampRef = useRef(null);
  const contextEntryRef = useRef(consumePendingSessionEntryContext());
  const [debriefTarget, setDebriefTarget] = useState(null);
  const [scienceCardShown, setScienceCardShown] = useState(false);
  const [nextMoveTarget, setNextMoveTarget] = useState(null);
  // What Shifted post-completion moment (BODY_SCAN_WHAT_SHIFTED_SPEC.md)
  const [showWhatShifted, setShowWhatShifted] = useState(false);
  const [showBodyScanLowDemandComplete, setShowBodyScanLowDemandComplete] = useState(false); // May 7, 2026 — flag flipped by What Shifted handlers in low-demand to render LowDemandComplete after save (replaces the old straight-return short-circuit that stripped the chip picker entirely).
  const [postStateChip, setPostStateChip] = useState(null);
  const [shiftLabel, setShiftLabel] = useState("");
  const [shiftLabelExpanded, setShiftLabelExpanded] = useState(false);
  const [shiftSkipReason, setShiftSkipReason] = useState(null);
  const [feelState, setFeelState] = useState(() => {
    // Infer from today's check-in if available — user can always override via chips
    try {
      const checkin = JSON.parse(localStorage.getItem("stillform_checkin_today") || "null");
      if (!checkin || checkin.date !== TimeKeeper.stillformDay()) return null;
      const mood = (checkin.mood || "").toLowerCase();
      if (mood.match(/anxious|anxiety|nervous|worried|scared|dread|panic/)) return "anxious";
      if (mood.match(/angry|rage|furious|frustrated|irritat/)) return "angry";
      if (mood.match(/excit|hyped|pumped|happy|joy|great|amazing|wired/)) return "excited";
      return null;
    } catch { return null; }
  });
  const regulationType = (() => {
    try {
      const value = localStorage.getItem("stillform_regulation_type");
      return value === "thought-first" || value === "body-first" ? value : "thought-first";
    } catch {
      return "thought-first";
    }
  })();
  const formatTime = (ms) => {
    const totalSec = Math.round(ms / 1000);
    const min = Math.floor(totalSec / 60);
    const sec = totalSec % 60;
    return min > 0 ? `${min}m ${sec}s` : `${sec}s`;
  };
  const saveSession = () => {
    const elapsed = Date.now() - startTime.current;
    const timestamp = new Date().toISOString();
    try {
      const ctx = contextEntryRef.current || {};
      // Serialize tension data keyed by area name (not index) so My Progress can
      // surface it readably without joining against the areas array. Empty when
      // the user didn't tap any tension dots (low-demand skips the input entirely;
      // normal-mode users may also leave it untouched). Stored as { areaName: 1-5 }.
      // First persistence of post-practice tension data — fixes data gap surfaced
      // May 4, 2026 during low-demand Phase 2 build (tension was being captured
      // in React state but never written to the session record).
      const tensionByArea = {};
      Object.entries(tension || {}).forEach(([idx, level]) => {
        const area = areas[Number(idx)];
        if (area && area.name && level > 0) tensionByArea[area.name] = level;
      });
      const tensionAreasCount = Object.keys(tensionByArea).length;
      appendSessionToStorage({
        timestamp,
        duration: elapsed,
        durationFormatted: formatTime(elapsed),
        tools: ["body-scan"],
        exitPoint: isLowDemand ? "low-demand-body-scan-complete" : "scan-complete",
        source: isLowDemand ? "low-demand-body-scan" : "body-scan",
        entryMode: ctx.entryMode || null,
        entryProtocolId: ctx.entryProtocolId || null,
        bodyScanTension: tensionAreasCount > 0 ? tensionByArea : null,
        tensionDataCaptured: !isLowDemand
      });
      try {
        window.plausible(isLowDemand ? "Body Scan Completed (low-demand)" : "Body Scan Completed", {
          props: { tension_areas: tensionAreasCount }
        });
      } catch {}
    } catch {}
    return { elapsed, timestamp };
  };
  const getSessionCount = () => getSessionCountFromStorage();
  const queueDebriefAndCompleteNow = (redirectTo = null, source = "body-scan") => {
    setScienceCardShown(false);
    setDebriefTarget({ redirectTo: redirectTo || null, source });
  };
  const queueDebriefAndComplete = (redirectTo = null, source = "body-scan") => {
    setNextMoveTarget({ redirectTo: redirectTo || null, source });
  };
  const handleNextMoveConfirm = (nextMove) => {
    const target = nextMoveTarget;
    if (!target) return;
    if (latestSessionTimestampRef.current) {
      saveSessionNextMove(latestSessionTimestampRef.current, nextMove);
    }
    setNextMoveTarget(null);
    queueDebriefAndCompleteNow(target.redirectTo || null, target.source || "body-scan-next-move");
  };
  const handleNextMoveSkip = () => {
    const target = nextMoveTarget;
    if (!target) return;
    setNextMoveTarget(null);
    queueDebriefAndCompleteNow(target.redirectTo || null, target.source || "body-scan-next-move-skip");
  };
  // What Shifted handlers (BODY_SCAN_WHAT_SHIFTED_SPEC.md)
  const handleWhatShiftedLockIn = () => {
    if (!postStateChip) return; // disabled in UI when no chip selected, this is a guard
    const cleanLabel = String(shiftLabel || "").trim();
    try {
      const shiftEvent = buildShiftEvent({
        source: "body-scan-what-shifted",
        toolId: "scan",
        toolMode: null,
        preState: feelState,
        postState: postStateChip,
        shiftLabel: cleanLabel,
        sessionTimestamp: latestSessionTimestampRef.current,
        regulationType
      });
      appendShiftEventToStorage(shiftEvent);
      window.plausible("Body Scan What Shifted Completed", {
        props: {
          had_label: cleanLabel.length > 0 ? "yes" : "no",
          pre_state: feelState || "none",
          post_state: postStateChip
        }
      });
      window.plausible("Shift Classified", {
        props: {
          category: shiftEvent.category || "null",
          subcategory: shiftEvent.subcategory || "none",
          tool: "body-scan",
          mode: "none"
        }
      });
    } catch {}
    // User named the shift, so post-state replaces stale pre-state chip
    try { secureWrite("stillform_feelstate", { value: postStateChip, day: TimeKeeper.stillformDay() }); } catch {}
    setShowWhatShifted(false);
    setShiftLabelExpanded(false);
    if (isLowDemand) {
      // Low-demand close: skip debrief gate + Next Move flow, render LowDemandComplete directly.
      setShowBodyScanLowDemandComplete(true);
      return;
    }
    queueDebriefAndCompleteNow(null, "body-scan-what-shifted-complete");
  };

  const handleWhatShiftedSkip = (reasonOverride) => {
    const reason = reasonOverride || shiftSkipReason || "not-needed";
    try {
      const shiftEvent = buildShiftEvent({
        source: "body-scan-what-shifted-skip",
        toolId: "scan",
        toolMode: null,
        preState: feelState,
        postState: null, // skip = no post-state chip
        shiftLabel: null,
        sessionTimestamp: latestSessionTimestampRef.current,
        regulationType
      });
      appendShiftEventToStorage({ ...shiftEvent, skipped: true, skipReason: reason });
      window.plausible("Body Scan What Shifted Skipped", {
        props: { skip_reason: reason }
      });
      window.plausible("Shift Classified", {
        props: {
          category: shiftEvent.category || "null",
          subcategory: "skipped",
          tool: "body-scan",
          mode: "none"
        }
      });
    } catch {}
    setShowWhatShifted(false);
    setShiftLabelExpanded(false);
    if (isLowDemand) {
      setShowBodyScanLowDemandComplete(true);
      return;
    }
    queueDebriefAndCompleteNow(null, "body-scan-what-shifted-skip");
  };

  const completeDebriefGate = (reflectionText) => {
    const skipped = reflectionText === null;
    appendToolDebriefToStorage({
      id: `debrief_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`,
      timestamp: new Date().toISOString(),
      date: TimeKeeper.clockDay(),
      toolId: "scan",
      toolFamily: getToolFamily("scan"),
      regulationType,
      source: debriefTarget?.source || "body-scan",
      reflectionText: String(reflectionText || "").trim(),
      skipped,
      preState: feelState || null,
      route: debriefTarget?.redirectTo || null
    });
    try { window.plausible("Tool Debrief Completed", { props: { tool: "scan", skipped: skipped ? "yes" : "no" } }); } catch {}
    const nextRoute = debriefTarget?.redirectTo || undefined;
    setDebriefTarget(null);
    onComplete(nextRoute);
  };

  const areas = [
    {
      name: "Jaw & Face",
      prompt: "Unclench your jaw. Let your tongue rest. Soften your eyes.",
      holdObservation: "Notice if the pressure creates a release or more resistance. Either is information.",
      pointEffect: "Interrupt racing thoughts",
      pointName: "GV24.5 — Third Eye Point",
      pointLocation: "Place two fingers between your eyebrows, just above the bridge of your nose.",
      pointInstruction: "Apply firm, steady pressure. Close your eyes. Hold.",
      holdSeconds: 60,
      benefit: "Reduces tension headaches. Interrupts mental overload."
    },
    {
      name: "Shoulders & Neck",
      prompt: "Notice if your shoulders are raised. Let them drop completely.",
      holdObservation: "Feel the weight of your arms. Notice if your neck wants to follow and soften.",
      pointEffect: "Release shoulder tension",
      pointName: "GB21 — Shoulder Well",
      pointLocation: "Find the highest point of your shoulder muscle, halfway between your neck and the edge of your shoulder.",
      pointInstruction: "Press firmly with your thumb or two fingers. You may feel a tender ache — that's the right spot. Hold.",
      holdSeconds: 45,
      benefit: "Primary stress relief point. Releases held tension."
    },
    {
      name: "Chest & Breath",
      prompt: "Is your breath shallow? Take one slow, full breath down to your belly.",
      holdObservation: "Notice your breath without directing it. Is it expanding into the pressure or pulling away?",
      pointEffect: "Interrupt emotional escalation",
      pointName: "CV17 — Sea of Tranquility",
      pointLocation: "Find the center of your breastbone, level with your heart. Place your flat palm here.",
      pointInstruction: "Apply firm, steady pressure with your palm. Breathe into it. Hold.",
      holdSeconds: 60,
      benefit: "Interrupts emotional escalation. Regulates the breath."
    },
    {
      name: "Hands & Arms",
      prompt: "Are your hands gripping anything? Open them fully. Let your arms go heavy.",
      holdObservation: "Notice if the tenderness in the point shifts or spreads. Stay with it.",
      pointEffect: "Reduce stress load",
      pointName: "LI4 — Union Valley",
      pointLocation: "Find the webbing between your thumb and index finger. Pinch the highest point of the muscle there.",
      pointInstruction: "Squeeze firmly — this point is often tender. Switch hands halfway. Hold.",
      holdSeconds: 45,
      benefit: "One of the most effective points for stress and tension overload."
    },
    {
      name: "Gut & Core",
      prompt: "Scan your stomach and core. Notice tightness without trying to fix it.",
      holdObservation: "Notice what your gut is doing — gripping, fluttering, or still. You don't need to interpret it yet.",
      pointEffect: "Stabilize racing heart and nausea",
      pointName: "PC6 — Inner Gate",
      pointLocation: "Turn your wrist palm-up. Measure three finger-widths down from your wrist crease, between the two tendons.",
      pointInstruction: "Press firmly with your thumb. Switch wrists halfway. Hold.",
      holdSeconds: 60,
      benefit: "Regulates the nervous system. Stabilizes heart rate and nausea."
    },
    {
      name: "Legs & Feet",
      prompt: "Feel the full weight of your legs. Press your feet flat into the floor.",
      holdObservation: "Feel the floor beneath you. Notice if the weight of your body starts to settle.",
      pointEffect: "Ground and stabilize",
      pointName: "ST36 — Leg Three Miles",
      pointLocation: "Find the outer edge of your kneecap, then measure four finger-widths straight down your shin.",
      pointInstruction: "Press firmly into the muscle beside the bone. Switch legs halfway. Hold.",
      holdSeconds: 60,
      benefit: "Grounds the nervous system. Restores energy and stability."
    }
  ];

  const [tension, setTension] = useState({});
  const [currentArea, setCurrentArea] = useState(0);
  const [phase, setPhase] = useState(isLowDemand ? "scan" : "intro");
  const [holdCount, setHoldCount] = useState(0);
  const [holding, setHolding] = useState(false);

  // Scan pace multiplier from Settings
  const paceMultiplier = (() => {
    const p = localStorage.getItem("stillform_scan_pace") || "standard";
    return p === "fast" ? 0.5 : p === "slow" ? 1.75 : 1;
  })();
  const scaledAreas = areas.map(a => ({ ...a, holdSeconds: Math.round(a.holdSeconds * paceMultiplier) }));
  const [done, setDone] = useState(false);
  const [showPointName, setShowPointName] = useState(false);

  // Audio — low grounding tone during holds
  const [audioOn, setAudioOn] = useState(() => {
    // Low-demand mode force-enables audio (paced auditory cueing is mechanism, not preference).
    if (isLowDemand) return true;
    try { return localStorage.getItem("stillform_audio") === "on"; } catch { return false; }
  });
  const audioCtx = useRef(null);
  const activeOsc = useRef(null);

  useEffect(() => {
    try {
      audioCtx.current = new (window.AudioContext || window.webkitAudioContext)();
    } catch {}
    return () => {
      try {
        if (activeOsc.current) { activeOsc.current.stop(); activeOsc.current = null; }
        if (audioCtx.current) audioCtx.current.close();
      } catch {}
    };
  }, []);

  const toggleAudio = () => {
    const next = !audioOn;
    setAudioOn(next);
    try { localStorage.setItem("stillform_audio", next ? "on" : "off"); } catch {}
  };

  // Play/stop tone when holding
  useEffect(() => {
    if (!audioOn || !audioCtx.current) return;
    try { if (activeOsc.current) { activeOsc.current.stop(); activeOsc.current = null; } } catch {}

    if (!holding) return;

    try {
      const ctx = audioCtx.current;
      if (ctx.state === "suspended") ctx.resume();
      const osc = ctx.createOscillator();
      const gain = ctx.createGain();
      osc.type = "sine";
      osc.frequency.setValueAtTime(140, ctx.currentTime);
      osc.connect(gain);
      gain.connect(ctx.destination);
      gain.gain.setValueAtTime(0, ctx.currentTime);
      gain.gain.linearRampToValueAtTime(0.06, ctx.currentTime + 1);
      osc.start(ctx.currentTime);
      activeOsc.current = osc;
    } catch {}

    return () => {
      try {
        if (activeOsc.current) {
          const ctx = audioCtx.current;
          if (ctx) {
            const gain = ctx.createGain();
            activeOsc.current.disconnect();
            activeOsc.current.connect(gain);
            gain.connect(ctx.destination);
            gain.gain.setValueAtTime(0.06, ctx.currentTime);
            gain.gain.linearRampToValueAtTime(0, ctx.currentTime + 0.5);
          }
          setTimeout(() => { try { activeOsc.current?.stop(); activeOsc.current = null; } catch {} }, 600);
        }
      } catch {}
    };
  }, [holding, audioOn]);

  useEffect(() => {
    if (!holding) return;
    const target = scaledAreas[currentArea].holdSeconds;
    if (holdCount >= target) { setHolding(false); return; }
    const t = setTimeout(() => setHoldCount(c => c + 1), 1000);
    return () => clearTimeout(t);
  }, [holding, holdCount, currentArea]);

  const startHold = () => { setHoldCount(0); setHolding(true); };

  const handleNext = () => {
    setPhase("scan");
    setHolding(false);
    setHoldCount(0);
    setShowPointName(false);
    if (currentArea < areas.length - 1) {
      haptic.tick();
      setCurrentArea(a => a + 1);
    } else {
      haptic.complete();
      setDone(true);
    }
  };

  const area = scaledAreas[currentArea];
  const holdTarget = area.holdSeconds;
  const holdProgress = Math.min((holdCount / holdTarget) * 100, 100);
  const renderAreaOverview = (areaName) => {
    const highlightStyle = { fill: "var(--amber-20)", stroke: "var(--amber)", strokeWidth: 1 };
    return (
      <svg viewBox="0 0 180 200" width="140" height="140" style={{ overflow: "visible" }} aria-label={`${areaName} body map`}>
        <circle cx="90" cy="24" r="14" fill="none" stroke="rgba(255,255,255,0.50)" strokeWidth="1" />
        <path d="M70 42 L62 74 L66 150 L82 194" fill="none" stroke="rgba(255,255,255,0.50)" strokeWidth="1.2" />
        <path d="M110 42 L118 74 L114 150 L98 194" fill="none" stroke="rgba(255,255,255,0.50)" strokeWidth="1.2" />
        <path d="M66 72 L114 72 L108 126 L72 126 Z" fill="none" stroke="rgba(255,255,255,0.50)" strokeWidth="1.1" />
        <path d="M62 74 L40 102" fill="none" stroke="rgba(255,255,255,0.42)" strokeWidth="1.1" />
        <path d="M118 74 L140 102" fill="none" stroke="rgba(255,255,255,0.42)" strokeWidth="1.1" />
        <path d="M40 102 L38 150" fill="none" stroke="rgba(255,255,255,0.42)" strokeWidth="1.1" />
        <path d="M140 102 L142 150" fill="none" stroke="rgba(255,255,255,0.42)" strokeWidth="1.1" />
        {areaName === "Jaw & Face" && (
          <>
            <ellipse cx="90" cy="30" rx="15" ry="9" {...highlightStyle} />
            <text x="90" y="188" textAnchor="middle" fill="rgba(255,255,255,0.75)" fontSize="9" fontFamily="'IBM Plex Mono', monospace">Face + jaw region</text>
          </>
        )}
        {areaName === "Shoulders & Neck" && (
          <>
            <rect x="58" y="44" width="64" height="16" rx="8" {...highlightStyle} />
            <text x="90" y="188" textAnchor="middle" fill="rgba(255,255,255,0.75)" fontSize="9" fontFamily="'IBM Plex Mono', monospace">Shoulders + neck region</text>
          </>
        )}
        {areaName === "Chest & Breath" && (
          <>
            <rect x="74" y="74" width="32" height="26" rx="10" {...highlightStyle} />
            <text x="90" y="188" textAnchor="middle" fill="rgba(255,255,255,0.75)" fontSize="9" fontFamily="'IBM Plex Mono', monospace">Chest + breath region</text>
          </>
        )}
        {areaName === "Hands & Arms" && (
          <>
            <rect x="31" y="114" width="16" height="22" rx="7" {...highlightStyle} />
            <rect x="133" y="114" width="16" height="22" rx="7" {...highlightStyle} />
            <text x="90" y="188" textAnchor="middle" fill="rgba(255,255,255,0.75)" fontSize="9" fontFamily="'IBM Plex Mono', monospace">Hands + forearms region</text>
          </>
        )}
        {areaName === "Gut & Core" && (
          <>
            <rect x="74" y="100" width="32" height="24" rx="10" {...highlightStyle} />
            <text x="90" y="188" textAnchor="middle" fill="rgba(255,255,255,0.75)" fontSize="9" fontFamily="'IBM Plex Mono', monospace">Gut + core region</text>
          </>
        )}
        {areaName === "Legs & Feet" && (
          <>
            <rect x="70" y="144" width="14" height="36" rx="7" {...highlightStyle} />
            <rect x="96" y="144" width="14" height="36" rx="7" {...highlightStyle} />
            <text x="90" y="188" textAnchor="middle" fill="rgba(255,255,255,0.75)" fontSize="9" fontFamily="'IBM Plex Mono', monospace">Legs + feet region</text>
          </>
        )}
      </svg>
    );
  };

  const scanSavedRef = useRef(false);
  const scanElapsedRef = useRef(0);
  const scanAutoRef = useRef(false);
  if (nextMoveTarget) {
    return (
      <NextMoveStep
        description="Choose one concrete action before leaving Body Scan."
        onConfirm={handleNextMoveConfirm}
        onSkip={handleNextMoveSkip}
      />
    );
  }
  if (debriefTarget) {
    if (!scienceCardShown) {
      return (
        <ScienceCard
          toolId="scan"
          lastBodyScanArea={areas[currentArea]?.name || null}
          feelStateBefore={debriefTarget.preState || feelState || null}
          feelStateAfter={debriefTarget.postState || null}
          sessionCount={getSessionCountFromStorage()}
          onContinue={() => setScienceCardShown(true)}
        />
      );
    }
    return (
      <ToolDebriefGate
        toolId="scan"
        regulationType={regulationType}
        onContinue={completeDebriefGate}
      />
    );
  }
  if (showBodyScanLowDemandComplete) {
    // Low-demand finish — chip already saved (or skipped) via handleWhatShifted handlers above.
    // Renders the shared LowDemandComplete tap-to-close screen, then onComplete fires onClose.
    return <LowDemandComplete onClose={() => onComplete(undefined)} />;
  }

  if (showWhatShifted) {
    // BODY SCAN WHAT SHIFTED — Russell circumplex post-state moment + optional free-text label
    // Per BODY_SCAN_WHAT_SHIFTED_SPEC.md and THREE_CATEGORY_DATA_FEED_SPEC.md
    // Unsure added May 3 — gating decision: post-state required, with honest "I don't know yet" exit (parity with Reframe)
    const feelChips = [
      { id: "excited", label: "Excited" },
      { id: "focused", label: "Focused" },
      { id: "settled", label: "Settled" },
      { id: "anxious", label: "Anxious" },
      { id: "angry", label: "Angry" },
      { id: "stuck", label: "Stuck" },
      { id: "mixed", label: "Mixed" },
      { id: "flat", label: "Flat" },
      { id: "distant", label: "Distant" },
      { id: "unsure", label: "Unsure" }
    ];
    const preChipLabel = feelChips.find(c => c.id === feelState)?.label || null;
    const lockInEnabled = !!postStateChip;

    return (
      <div style={{ maxWidth: 460, margin: "0 auto", paddingTop: 24, padding: "24px 16px 8px" }}>
        <div className="t-mono-sm" style={{ color: "var(--amber)", marginBottom: 12 }}>
          What Shifted
        </div>
        <div className="t-body-md quiet" style={{ marginBottom: 12 }}>
          Your body moved through six points. Name where it lands now — that's what locks the regulation in.
        </div>
        {/* Physiology naming — names interoception specifically as the practiced skill.
            Per May 5 prelaunch gap audit: session-1 retention hinges on users feeling
            something specific happened. */}
        <div style={{
          fontSize: 12,
          color: "var(--text-muted)",
          lineHeight: 1.6,
          marginBottom: 24,
          paddingLeft: 12,
          borderLeft: "1px solid var(--amber-dim)"
        }}>
          You practiced interoception — the awareness of internal body state. It's a measurable skill that strengthens with reps.
        </div>

        {preChipLabel && (
          <div className="t-mono-sm" style={{ marginBottom: 8 }}>
            Started: {preChipLabel}
          </div>
        )}

        <div style={{ display: "flex", gap: 6, flexWrap: "wrap", marginBottom: 24 }}>
          {feelChips.map(f => (
            <div key={f.id} style={{ display: "inline-flex", alignItems: "center" }}>
              <button
                onClick={() => { haptic.tick(); setPostStateChip(f.id); }}
                style={{
                  background: postStateChip === f.id ? "var(--amber-glow)" : "transparent",
                  border: `0.5px solid ${postStateChip === f.id ? "color-mix(in srgb, var(--amber) 60%, transparent)" : "var(--border)"}`,
                  borderRadius: 20,
                  padding: "8px 16px",
                  fontSize: 13,
                  color: postStateChip === f.id ? "var(--amber)" : "var(--text-dim)",
                  cursor: "pointer",
                  fontFamily: "'DM Sans', sans-serif",
                  transition: "border-color var(--motion-default) var(--ease-prestige), color var(--motion-default) var(--ease-prestige)"
                }}>
                {f.label}
              </button>
              {CHIP_DEFINITIONS[f.id] && setInfoModal && (
                <button
                  onClick={() => setInfoModal(CHIP_DEFINITIONS[f.id])}
                  aria-label={`What does ${f.label} mean?`}
                  style={{ background: "none", border: "none", color: "var(--text-muted)", cursor: "pointer", fontSize: 12, padding: "0 4px", lineHeight: 1, marginLeft: -2 }}>
                  ⓘ
                </button>
              )}
            </div>
          ))}
        </div>

        {!isLowDemand && !shiftLabelExpanded && (
          <button
            onClick={() => setShiftLabelExpanded(true)}
            style={{
              background: "transparent",
              border: "none",
              color: "var(--text-dim)",
              fontSize: 13,
              cursor: "pointer",
              fontFamily: "'DM Sans', sans-serif",
              padding: "8px 0",
              marginBottom: 16
            }}>
            ▸ What shifted in your body?
          </button>
        )}

        {!isLowDemand && shiftLabelExpanded && (
          <div style={{ marginBottom: 16 }}>
            <textarea
              value={shiftLabel}
              onChange={(e) => setShiftLabel(e.target.value)}
              placeholder="In one line — what's different in your body now? (optional)"
              rows={3}
              style={{
                width: "100%",
                background: "var(--surface2)",
                border: "0.5px solid var(--border)",
                borderRadius: "var(--r)",
                padding: "10px 12px",
                fontSize: 13,
                color: "var(--text)",
                fontFamily: "'DM Sans', sans-serif",
                outline: "none",
                resize: "vertical",
                marginBottom: 8
              }}
            />
            <div className="t-caption" style={{ color: "var(--text-muted)", lineHeight: 1.5 }}>
              Naming the somatic shift — even in one line — strengthens the pattern. Optional.
            </div>
          </div>
        )}

        <div style={{ display: "flex", gap: 8, flexWrap: "wrap", marginTop: 16 }}>
          <button
            className="btn btn-primary"
            onClick={handleWhatShiftedLockIn}
            disabled={!lockInEnabled}
            style={{ opacity: lockInEnabled ? 1 : 0.45, cursor: lockInEnabled ? "pointer" : "not-allowed" }}>
            Lock it in
          </button>
          <button className="btn btn-ghost" onClick={() => handleWhatShiftedSkip()}>
            Skip
          </button>
        </div>
      </div>
    );
  }

  if (done) {
    if (!scanSavedRef.current) {
      scanSavedRef.current = true;
      const saved = saveSession();
      scanElapsedRef.current = saved?.elapsed || 0;
      latestSessionTimestampRef.current = saved?.timestamp || null;
    }
    // May 7, 2026 redesign — was short-circuiting straight to LowDemandComplete in low-demand,
    // which stripped the post-state chip picker (the lowest-demand metacognitive act and the
    // data point that classifies the shift). A depleted user who DID shift had no way to mark
    // it; their session evaporated. Now low-demand users still flow into showWhatShifted —
    // the render branches on isLowDemand to hide the heavy bits (free-text shift label) while
    // keeping the chip picker. Handlers also branch: save the shift event, then render the
    // shared LowDemandComplete (skipping debrief gate / Next Move).
    // What Shifted gate — replace the old 2s auto-route to Reframe with the metacognitive close
    if (!scanAutoRef.current) { scanAutoRef.current = true; setTimeout(() => setShowWhatShifted(true), 2000); }
    const elapsed = scanElapsedRef.current;
    const sessionCount = getSessionCount();
    const signalProfile = (() => { try { return secureRead("stillform_signal_profile", null); } catch { return null; } })();
    return (
      <div className="complete">
        <div className="complete-icon" style={{ animation: "pulse 1.2s ease-in-out 3" }}>✓</div>
        <h2>Signal cleared.</h2>
        <div className="t-mono-xs" style={{ marginBottom: 16 }}>
          System calibrated · {formatTime(elapsed)}
        </div>
        {signalProfile?.firstAreas?.length > 0 && (
          <div style={{ background: "var(--surface)", border: "0.5px solid var(--amber-dim)", borderRadius: "var(--r)", padding: "12px 16px", marginBottom: 16, textAlign: "left" }}>
            <div style={{ fontFamily: "'IBM Plex Mono', monospace", fontSize: 8, letterSpacing: "0.2em", textTransform: "uppercase", color: "var(--amber)", marginBottom: 8 }}>Signal Shift</div>
            {signalProfile.firstAreas.slice(0, 3).map(area => (
              <div key={area} style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 5 }}>
                <span className="t-mono-sm">{area}</span>
                <span style={{ fontFamily: "'IBM Plex Mono', monospace", fontSize: 10, color: "var(--amber)" }}>Pressure released</span>
              </div>
            ))}
          </div>
        )}
        {sessionCount > 1 && <div className="t-mono-xs" style={{ letterSpacing: "0.1em", marginBottom: 16 }}>SESSION {sessionCount}</div>}
        {sessionCount === 1 && (
          <div style={{ background: "var(--surface)", border: "0.5px solid var(--amber-dim)", borderRadius: "var(--r)", padding: "14px 18px", marginBottom: 16, textAlign: "center" }}>
            <div className="t-mono-xs" style={{ color: "var(--amber)", marginBottom: 6 }}>First calibration</div>
            <div className="t-body-sm quiet" style={{ lineHeight: 1.5 }}>System is learning you. Each session sharpens the read.</div>
          </div>
        )}
        {/* PRACTICE TREND — engagement architecture Build #5 micro-credit.
            ONE specific number per close, picked by relevance. Returns null
            when data is too sparse for an honest credit (better silence
            than fabricated proof). Compact, glanceable in the ~2s window
            before auto-advance to What Shifted. Operator-tier label —
            not "Achievement" (gamified). */}
        {(() => {
          const latestSession = (() => { try { return getSessionsFromStorage().slice(-1)[0]; } catch { return null; } })();
          const credit = (() => { try { return computeAchievement(latestSession); } catch { return null; } })();
          if (!credit) return null;
          return (
            <div style={{
              background: "var(--surface)",
              border: "0.5px solid var(--border)",
              borderRadius: "var(--r)",
              padding: "12px 16px",
              marginBottom: 16,
              textAlign: "left"
            }}>
              <div className="t-mono-xs" style={{ color: "var(--text-muted)", letterSpacing: "0.14em", marginBottom: 6 }}>
                Practice trend
              </div>
              <div style={{
                fontSize: 14,
                fontFamily: "'DM Sans', sans-serif",
                color: "var(--text)",
                lineHeight: 1.4,
                marginBottom: credit.context ? 4 : 0
              }}>
                {credit.headline}
              </div>
              {credit.context && (
                <div style={{
                  fontSize: 12,
                  fontFamily: "'DM Sans', sans-serif",
                  color: "var(--text-dim)",
                  lineHeight: 1.5
                }}>
                  {credit.context}
                </div>
              )}
            </div>
          );
        })()}
        <div className="t-mono-xs" style={{ letterSpacing: "0.1em", marginBottom: 16, animation: "pulse 1s ease-in-out infinite" }}>
          NAMING THE SHIFT…
        </div>
        <button className="btn btn-ghost" style={{ fontSize: 12 }} onClick={() => queueDebriefAndComplete(undefined, "scan-complete-exit")}>Exit session</button>
        
      </div>
    );
  }

  if (phase === "intro") return (
    <div style={{ maxWidth: 400, margin: "0 auto", padding: "0 8px" }}>
      <div style={{ display: "flex", justifyContent: "center", alignItems: "baseline", gap: 6, marginBottom: 6 }}>
        <h2 style={{ fontFamily: "'Cormorant Garamond', serif", fontSize: 32, fontWeight: 300, margin: 0 }}>
          Body scan.
        </h2>
        {setInfoModal && (
          <button
            onClick={() => setInfoModal({
              title: "Why Body Scan?",
              body: "Body Scan redirects attention from cognitive content to physical sensation. The science: focused interoceptive attention shifts which brain network is in the foreground. The salience network — the system that decides what your brain attends to — gets reset by deliberate attention to body signals (Menon 2011). When the loop is in your head, the salience network is stuck on cognitive content. Pulling attention into the body interrupts that priority and lets attention re-allocate.\n\nThis is why body-first works for spirals where reframing alone doesn't land. You can't think your way out of a state your nervous system is still in. The body scan isn't a calming technique — it's an attentional rerouting that creates the conditions for cognition to clear afterward."
            })}
            aria-label="Why Body Scan?"
            style={{ background: "none", border: "none", color: "var(--text-muted)", cursor: "pointer", fontSize: 13, padding: "0 4px", lineHeight: 1 }}
          >
            ⓘ
          </button>
        )}
      </div>
      <div className="t-body-sm quiet" style={{ lineHeight: 1.6, marginBottom: 24, textAlign: "center" }}>
        Six areas, head to feet. Notice what's there before you change anything.
      </div>
      {/* Pre-regulation chips removed per Nook 2021 + 2024-2025 replications:
          emotion naming before mindful acceptance impedes regulation effectiveness.
          Affect labeling now lives post-regulation only. */}
      <div style={{ display: "flex", justifyContent: "center", marginTop: 24 }}>
        <button className="btn btn-primary" style={{ fontSize: 16, padding: "14px 40px" }} onClick={() => setPhase("scan")}>
          Begin
        </button>
      </div>
    </div>
  );

  return (
    <div className="scan-body">
      {scaledAreas.map((a, i) => (
        <div key={i} className={`scan-area ${i === currentArea ? "active" : i < currentArea ? "done" : ""}`}
          onClick={() => i <= currentArea && setCurrentArea(i)}>
          <div className="scan-area-name">{a.name}</div>
          {i !== currentArea && <div className="scan-area-prompt">{i < currentArea ? "✓ Complete" : a.prompt}</div>}
          {i === currentArea && phase === "scan" && (
            <>
              <div style={{ display: "flex", justifyContent: "center", marginTop: 10, marginBottom: 10, opacity: 0.95 }}>
                {renderAreaOverview(a.name)}
              </div>
              <div className="scan-area-prompt" style={{ marginTop: 8 }}>{a.prompt}</div>
              <div style={{ marginTop: 12, marginBottom: 12, fontSize: 12, color: "var(--text-dim)", fontStyle: "italic", lineHeight: 1.6 }}>
                Notice what's here. You don't need to change it — just let it be.
              </div>
              {!isLowDemand && (
                <>
                  <div style={{ marginTop: 4, marginBottom: 8, fontSize: 12, color: "var(--text-dim)", letterSpacing: "0.08em" }}>TENSION LEVEL</div>
                  <div className="tension-bar">
                    {[1,2,3,4,5].map(n => (
                      <div key={n} className={`tension-dot ${(tension[i] || 0) >= n ? "active" : ""}`}
                        onClick={(e) => { e.stopPropagation(); setTension(t => ({ ...t, [i]: n })); }} />
                    ))}
                  </div>
                </>
              )}
              <div style={{ marginTop: 20, display: "flex", gap: 8 }}>
                <button className="btn btn-primary" style={{ flex: 1, fontSize: 13 }}
                  onClick={(e) => { e.stopPropagation(); setPhase("pressure"); }}>
                  Apply pressure here →
                </button>
                <button onClick={(e) => { e.stopPropagation(); handleNext(); }} style={{
                  background: "none", border: "1px solid var(--border)", borderRadius: "var(--r-lg)",
                  padding: "8px 12px", fontSize: 11, cursor: "pointer",
                  color: "var(--text-muted)", fontFamily: "'DM Sans', sans-serif"
                }}>
                  Skip →
                </button>
              </div>
            </>
          )}
          {i === currentArea && phase === "pressure" && (
            <>
              <div style={{ marginTop: 12, marginBottom: 6, fontSize: 12, color: "var(--text-dim)", letterSpacing: "0.06em", textTransform: "uppercase" }}>
                Step {currentArea + 1} of {scaledAreas.length}
              </div>
              <div style={{ fontSize: 13, color: "var(--text)", lineHeight: 1.6, marginBottom: 6 }}>
                Press the <span style={{ color: "var(--amber)" }}>amber point</span> shown below.
              </div>
              {/* Acupressure point diagram */}
              <div style={{ display: "flex", justifyContent: "center", marginTop: 16, marginBottom: 8 }}>
                <svg viewBox="0 0 160 160" width="140" height="140" style={{ overflow: "visible" }}>
                  {a.name === "Jaw & Face" && <>
                    {/* Head */}
                    <ellipse cx="80" cy="54" rx="28" ry="34" fill="none" stroke="rgba(255,255,255,0.50)" strokeWidth="1.5"/>
                    {/* Neck */}
                    <line x1="72" y1="86" x2="70" y2="102" stroke="rgba(255,255,255,0.42)" strokeWidth="1.5"/>
                    <line x1="88" y1="86" x2="90" y2="102" stroke="rgba(255,255,255,0.42)" strokeWidth="1.5"/>
                    {/* Jaw line */}
                    <path d="M55 68 Q80 82 105 68" fill="none" stroke="rgba(255,255,255,0.42)" strokeWidth="1.2"/>
                    {/* Pressure point — between eyebrows */}
                    <circle cx="80" cy="43" r="5" fill="var(--amber)" opacity="0.9"/>
                    <circle cx="80" cy="43" r="9" fill="none" stroke="var(--amber)" strokeWidth="0.5" opacity="0.3"/>
                    {/* Label */}
                    <text x="80" y="128" textAnchor="middle" fill="rgba(255,255,255,0.72)" fontSize="9" fontFamily="'IBM Plex Mono', monospace">GV24.5 · between eyebrows</text>
                  </>}

                  {a.name === "Shoulders & Neck" && <>
                    {/* Head */}
                    <circle cx="80" cy="28" r="14" fill="none" stroke="rgba(255,255,255,0.50)" strokeWidth="1.5"/>
                    {/* Neck */}
                    <line x1="75" y1="41" x2="74" y2="54" stroke="rgba(255,255,255,0.50)" strokeWidth="1.5"/>
                    <line x1="85" y1="41" x2="86" y2="54" stroke="rgba(255,255,255,0.50)" strokeWidth="1.5"/>
                    {/* Shoulders */}
                    <path d="M74 54 Q60 56 38 70" fill="none" stroke="rgba(255,255,255,0.2)" strokeWidth="1.6"/>
                    <path d="M86 54 Q100 56 122 70" fill="none" stroke="rgba(255,255,255,0.2)" strokeWidth="1.6"/>
                    {/* Torso top */}
                    <line x1="38" y1="70" x2="42" y2="110" stroke="rgba(255,255,255,0.1)" strokeWidth="1.5"/>
                    <line x1="122" y1="70" x2="118" y2="110" stroke="rgba(255,255,255,0.1)" strokeWidth="1.5"/>
                    {/* Pressure point — GB21 left shoulder */}
                    <circle cx="56" cy="62" r="5" fill="var(--amber)" opacity="0.9"/>
                    <circle cx="56" cy="62" r="9" fill="none" stroke="var(--amber)" strokeWidth="0.5" opacity="0.3"/>
                    {/* Label */}
                    <text x="80" y="136" textAnchor="middle" fill="rgba(255,255,255,0.72)" fontSize="9" fontFamily="'IBM Plex Mono', monospace">GB21 · shoulder well</text>
                  </>}

                  {a.name === "Chest & Breath" && <>
                    {/* Head */}
                    <circle cx="80" cy="18" r="11" fill="none" stroke="rgba(255,255,255,0.50)" strokeWidth="1.5"/>
                    {/* Neck */}
                    <line x1="76" y1="28" x2="75" y2="36" stroke="rgba(255,255,255,0.42)" strokeWidth="1.5"/>
                    <line x1="84" y1="28" x2="85" y2="36" stroke="rgba(255,255,255,0.42)" strokeWidth="1.5"/>
                    {/* Shoulders */}
                    <path d="M75 36 Q62 38 48 48" fill="none" stroke="rgba(255,255,255,0.52)" strokeWidth="1.5"/>
                    <path d="M85 36 Q98 38 112 48" fill="none" stroke="rgba(255,255,255,0.52)" strokeWidth="1.5"/>
                    {/* Torso / chest */}
                    <path d="M48 48 L44 110 L116 110 L112 48 Z" fill="none" stroke="rgba(255,255,255,0.52)" strokeWidth="1.5"/>
                    {/* Sternum center line */}
                    <line x1="80" y1="48" x2="80" y2="110" stroke="rgba(255,255,255,0.36)" strokeWidth="0.8" strokeDasharray="3,3"/>
                    {/* Pressure point — CV17 center sternum */}
                    <circle cx="80" cy="66" r="5" fill="var(--amber)" opacity="0.9"/>
                    <circle cx="80" cy="66" r="9" fill="none" stroke="var(--amber)" strokeWidth="0.5" opacity="0.3"/>
                    {/* Label */}
                    <text x="80" y="138" textAnchor="middle" fill="rgba(255,255,255,0.72)" fontSize="9" fontFamily="'IBM Plex Mono', monospace">CV17 · center sternum</text>
                  </>}

                  {a.name === "Hands & Arms" && <>
                    {/* Hand outline — palm facing up */}
                    <path d="M60 110 L60 65 Q60 58 56 50 M60 65 Q62 56 64 44 M60 65 Q65 55 70 43 M60 65 Q67 57 75 48 M60 65 Q58 57 52 52" fill="none" stroke="rgba(255,255,255,0.52)" strokeWidth="1.6"/>
                    {/* Palm base */}
                    <path d="M52 52 Q48 70 50 85 Q54 100 60 110 Q66 100 70 85 Q72 70 75 48" fill="none" stroke="rgba(255,255,255,0.50)" strokeWidth="1.5"/>
                    {/* Thumb */}
                    <path d="M52 52 Q44 48 40 56 Q38 64 46 68" fill="none" stroke="rgba(255,255,255,0.52)" strokeWidth="1.5"/>
                    {/* Pressure point — LI4 webbing */}
                    <circle cx="52" cy="57" r="5" fill="var(--amber)" opacity="0.9"/>
                    <circle cx="52" cy="57" r="9" fill="none" stroke="var(--amber)" strokeWidth="0.5" opacity="0.3"/>
                    {/* Label */}
                    <text x="80" y="140" textAnchor="middle" fill="rgba(255,255,255,0.72)" fontSize="9" fontFamily="'IBM Plex Mono', monospace">LI4 · thumb–index web</text>
                  </>}

                  {a.name === "Gut & Core" && <>
                    {/* Arm outline — inner wrist */}
                    <path d="M55 20 L55 100 Q55 112 65 118 Q75 124 85 118 Q95 112 95 100 L95 20" fill="none" stroke="rgba(255,255,255,0.52)" strokeWidth="1.6"/>
                    {/* Wrist crease */}
                    <line x1="52" y1="95" x2="98" y2="95" stroke="rgba(255,255,255,0.2)" strokeWidth="1.2"/>
                    <line x1="52" y1="100" x2="98" y2="100" stroke="rgba(255,255,255,0.1)" strokeWidth="1.2"/>
                    {/* Two tendons */}
                    <line x1="72" y1="20" x2="72" y2="92" stroke="rgba(255,255,255,0.1)" strokeWidth="0.8" strokeDasharray="2,3"/>
                    <line x1="78" y1="20" x2="78" y2="92" stroke="rgba(255,255,255,0.1)" strokeWidth="0.8" strokeDasharray="2,3"/>
                    {/* Pressure point — PC6, 3 fingers below wrist */}
                    <circle cx="75" cy="78" r="5" fill="var(--amber)" opacity="0.9"/>
                    <circle cx="75" cy="78" r="9" fill="none" stroke="var(--amber)" strokeWidth="0.5" opacity="0.3"/>
                    {/* 3-finger measurement indicator */}
                    <line x1="104" y1="78" x2="104" y2="95" stroke="rgba(255,255,255,0.50)" strokeWidth="1.2"/>
                    <line x1="101" y1="78" x2="107" y2="78" stroke="rgba(255,255,255,0.50)" strokeWidth="1.2"/>
                    <line x1="101" y1="95" x2="107" y2="95" stroke="rgba(255,255,255,0.50)" strokeWidth="1.2"/>
                    <text x="112" y="88" fill="rgba(255,255,255,0.25)" fontSize="7" fontFamily="'IBM Plex Mono', monospace">3 fin</text>
                    {/* Label */}
                    <text x="80" y="150" textAnchor="middle" fill="rgba(255,255,255,0.72)" fontSize="9" fontFamily="'IBM Plex Mono', monospace">PC6 · inner wrist</text>
                  </>}

                  {a.name === "Legs & Feet" && <>
                    {/* Knee outline */}
                    <ellipse cx="80" cy="42" rx="22" ry="18" fill="none" stroke="rgba(255,255,255,0.52)" strokeWidth="1.5"/>
                    {/* Thigh */}
                    <line x1="64" y1="36" x2="58" y2="10" stroke="rgba(255,255,255,0.50)" strokeWidth="1.6"/>
                    <line x1="96" y1="36" x2="102" y2="10" stroke="rgba(255,255,255,0.50)" strokeWidth="1.6"/>
                    {/* Shin */}
                    <line x1="66" y1="58" x2="62" y2="120" stroke="rgba(255,255,255,0.52)" strokeWidth="1.6"/>
                    <line x1="94" y1="58" x2="98" y2="120" stroke="rgba(255,255,255,0.52)" strokeWidth="1.6"/>
                    {/* Shin bone — tibia */}
                    <line x1="74" y1="58" x2="72" y2="118" stroke="rgba(255,255,255,0.1)" strokeWidth="0.8" strokeDasharray="3,3"/>
                    {/* 4-finger measurement */}
                    <line x1="108" y1="62" x2="108" y2="94" stroke="rgba(255,255,255,0.50)" strokeWidth="1.2"/>
                    <line x1="105" y1="62" x2="111" y2="62" stroke="rgba(255,255,255,0.50)" strokeWidth="1.2"/>
                    <line x1="105" y1="94" x2="111" y2="94" stroke="rgba(255,255,255,0.50)" strokeWidth="1.2"/>
                    <text x="115" y="80" fill="rgba(255,255,255,0.25)" fontSize="7" fontFamily="'IBM Plex Mono', monospace">4 fin</text>
                    {/* Pressure point — ST36, 4 fingers below kneecap */}
                    <circle cx="80" cy="94" r="5" fill="var(--amber)" opacity="0.9"/>
                    <circle cx="80" cy="94" r="9" fill="none" stroke="var(--amber)" strokeWidth="0.5" opacity="0.3"/>
                    {/* Label */}
                    <text x="80" y="148" textAnchor="middle" fill="rgba(255,255,255,0.72)" fontSize="9" fontFamily="'IBM Plex Mono', monospace">ST36 · below kneecap</text>
                  </>}
                </svg>
              </div>
              <div className="t-caption" style={{ color: "var(--text-muted)", marginBottom: 10 }}>
                Visual legend: amber circle = where to apply pressure.
              </div>

              <div style={{ background: "var(--amber-glow)", border: "1px solid var(--amber-dim)", borderRadius: "var(--r-lg)", padding: "16px 20px" }}>
                <div style={{ fontSize: 15, fontWeight: 500, color: "var(--amber)", marginBottom: 10 }}>{a.pointEffect}</div>
                <div className="t-body-md" style={{ marginBottom: 10 }}><strong>Where:</strong> {a.pointLocation}</div>
                <div className="t-body-md" style={{ marginBottom: 10 }}><strong>How:</strong> {a.pointInstruction}</div>
                <div className="t-body-sm quiet" style={{ fontStyle: "italic", marginBottom: 8 }}>{a.benefit}</div>
                <button
                  onClick={(e) => { e.stopPropagation(); setShowPointName(!showPointName); }}
                  style={{ background: "none", border: "none", fontSize: 11, color: "var(--text-muted)", cursor: "pointer", padding: 0, letterSpacing: "0.06em" }}
                >
                  {showPointName ? `▾ ${a.pointName}` : "▸ Acupressure point name"}
                </button>
              </div>
              {!holding && holdCount === 0 && (
                <div style={{ display: "flex", gap: 8, marginTop: 16, alignItems: "center" }}>
                  <button className="btn btn-primary" style={{ flex: 1, fontSize: 13 }}
                    onClick={(e) => { e.stopPropagation(); startHold(); }}>
                    Stay here for {holdTarget}s
                  </button>
                  <button onClick={(e) => { e.stopPropagation(); toggleAudio(); }} style={{
                    background: audioOn ? "var(--amber-glow)" : "var(--surface)",
                    border: `1px solid ${audioOn ? "var(--amber-dim)" : "var(--border)"}`,
                    borderRadius: "var(--r-lg)", padding: "8px 12px", fontSize: 11, cursor: "pointer",
                    color: audioOn ? "var(--amber)" : "var(--text-dim)", fontFamily: "'DM Sans', sans-serif"
                  }}>
                    {audioOn ? "♪" : "♪"}
                  </button>
                  <button onClick={(e) => { e.stopPropagation(); handleNext(); }} style={{
                    background: "none", border: "1px solid var(--border)", borderRadius: "var(--r-lg)",
                    padding: "8px 12px", fontSize: 11, cursor: "pointer",
                    color: "var(--text-muted)", fontFamily: "'DM Sans', sans-serif"
                  }}>
                    Skip →
                  </button>
                </div>
              )}
              {(holding || holdCount > 0) && (
                <div style={{ marginTop: 16 }}>
                  <div style={{ fontSize: 12, color: "var(--text-dim)", marginBottom: 8, letterSpacing: "0.08em" }}>
                    {holding ? `Staying — ${holdTarget - holdCount}s` : "Stayed."}
                  </div>
                  <div style={{ background: "var(--border)", borderRadius: "var(--r)", height: 4, overflow: "hidden" }}>
                    <div style={{ width: `${holdProgress}%`, height: "100%", background: holdProgress >= 100 ? "var(--green)" : "var(--amber)", transition: "width 1s linear" }} />
                  </div>
                  {holding && (
                    <>
                      {area.holdObservation && (
                        <div style={{ marginTop: 16, fontSize: 13, color: "var(--text-dim)", fontStyle: "italic", lineHeight: 1.7, padding: "12px 16px", background: "var(--surface)", borderRadius: "var(--r-lg)", border: "0.5px solid var(--border)" }}>
                          {area.holdObservation}
                        </div>
                      )}
                      <button onClick={(e) => { e.stopPropagation(); handleNext(); }} style={{
                        background: "none", border: "none", fontSize: 11, color: "var(--text-muted)",
                        cursor: "pointer", fontFamily: "'DM Sans', sans-serif", marginTop: 12,
                        letterSpacing: "0.06em"
                      }}>
                        Skip →
                      </button>
                    </>
                  )}
                  {!holding && holdCount >= holdTarget && (() => {
                    setTimeout(() => handleNext(), 1500);
                    return (
                      <div style={{ marginTop: 16 }}>
                        <div style={{ fontSize: 11, color: "var(--text-muted)", animation: "pulse 1s ease-in-out infinite", marginBottom: 8 }}>
                          {currentArea < areas.length - 1 ? "Moving to next area…" : "Scan complete…"}
                        </div>
                        <button className="btn btn-ghost" style={{ fontSize: 12 }}
                          onClick={(e) => { e.stopPropagation(); handleNext(); }}>
                          Skip ahead →
                        </button>
                      </div>
                    );
                  })()}
                </div>
              )}
            </>
          )}
        </div>
      ))}
    </div>
  );
}

// --------------------------------------------------------------------
// SCIENCE CARD — Plain-Language Neuroscience Surface
// 20 hand-written static fallback cards. Used when AI generation fails.
// Each card drawn directly from the verified corpus in reframe.js.
// --------------------------------------------------------------------
const STATIC_SCIENCE_CARDS = [
  { topic: "cyclic_sighing_effect", body: "A 2023 Stanford randomized trial of 111 participants compared three breathwork patterns with mindfulness meditation across one month of daily 5-minute practice. Cyclic sighing produced greater mood improvement and respiratory rate reduction than mindfulness meditation (p < 0.05).", citation: "Balban et al. 2023 · Cell Reports Medicine", paywalled: false, source_url: "https://pubmed.ncbi.nlm.nih.gov/36630953/" },
  { topic: "slow_breathing_mechanism", body: "Slow breathing techniques (under 10 breaths per minute) enhance autonomic, cerebral, and psychological flexibility. Reviews link slow breathing to parasympathetic activity, central nervous system changes, and EEG theta power related to emotional control.", citation: "Zaccaro et al. 2018 · Frontiers in Human Neuroscience", paywalled: false, source_url: "https://pmc.ncbi.nlm.nih.gov/articles/PMC6137615/" },
  { topic: "diaphragmatic_effect", body: "A 2017 study trained 40 adults in diaphragmatic breathing across 8 weeks. The breathing group showed significantly reduced negative affect and improved sustained attention compared to controls. Cortisol levels decreased over the study period, though the comparison between groups did not reach statistical significance.", citation: "Ma et al. 2017 · Frontiers in Psychology", paywalled: false, source_url: "https://pmc.ncbi.nlm.nih.gov/articles/PMC5455070/" },
  { topic: "acupressure_effect", body: "A 2015 systematic review and meta-analysis compared acupressure to sham control across multiple randomized trials in adults. The review found acupressure produced a significant reduction in anxiety outcomes versus sham comparison.", citation: "Au et al. 2015 · Acupuncture in Medicine", paywalled: true, source_url: "https://pubmed.ncbi.nlm.nih.gov/26002571/" },
  { topic: "interoception_emotion_mechanism", body: "Interoception describes how the body's internal signals — heartbeat, breath, gut activity — are transmitted, processed in the brain, and represented in conscious experience. Influential theories propose that emotional feelings arise from these physiological signals being interpreted by the brain.", citation: "Critchley & Garfinkel 2017 · Current Opinion in Psychology", paywalled: false, source_url: "https://www.sciencedirect.com/science/article/pii/S2352250X17300106" },
  { topic: "reappraisal_meta_mechanism", body: "A 2014 meta-analysis of 48 neuroimaging studies found that reappraisal activates cognitive control regions and lateral temporal cortex while modulating the bilateral amygdala. The proposed mechanism: cognitive control modifies semantic representations of an emotional stimulus, and these altered representations attenuate amygdala activity.", citation: "Buhle et al. 2014 · Cerebral Cortex", paywalled: false, source_url: "https://pmc.ncbi.nlm.nih.gov/articles/PMC4193464/" },
  { topic: "affect_labeling_mechanism", body: "Putting a name on an emotion — affect labeling — diminishes the response of the amygdala and other limbic regions while increasing activity in the right ventrolateral prefrontal cortex. The shift happens in fMRI even when participants are not explicitly trying to regulate.", citation: "Lieberman et al. 2007 · Psychological Science", paywalled: false, source_url: "https://sanlab.psych.ucla.edu/wp-content/uploads/sites/31/2015/05/Lieberman_AL-2007.pdf" },
  { topic: "affect_labeling_implicit_mechanism", body: "Affect labeling produces effects across four domains — experiential, autonomic, neural, and behavioral — that match those seen during explicit emotion regulation, even though affect labeling does not feel like a regulatory process while it's happening.", citation: "Torre & Lieberman 2018 · Emotion Review", paywalled: true, source_url: "https://static1.squarespace.com/static/651b09f505bc433349d85ab7/t/651d2f2843e6d165beeccb23/1696411432954/Torre(2018)ER.pdf" },
  { topic: "granularity_protective_effect", body: "A 2015 review consolidated multiple studies finding that under intense distress, individuals with higher emotional granularity were less likely to resort to maladaptive coping — binge drinking, aggression, self-injurious behavior — and showed less neural reactivity to rejection.", citation: "Kashdan, Barrett & McKnight 2015 · Current Directions in Psychological Science", paywalled: false, source_url: "https://c3po.media.mit.edu/wp-content/uploads/sites/45/2016/01/Kashdan-Barrett-Mcknight_2015.pdf" },
  { topic: "granularity_trainable_mechanism", body: "Emotional granularity — the ability to experience emotions in precise, context-specific terms — is a skill that can be acquired and improved through practice. The 2021 study found granularity increased as participants engaged in repeated structured self-assessment of their emotional states.", citation: "Hoemann, Barrett & Quigley 2021 · Frontiers in Psychology", paywalled: false, source_url: "https://pmc.ncbi.nlm.nih.gov/articles/PMC8355493/" },
  { topic: "sleep_amygdala_effect", body: "A 2007 fMRI study found sleep-deprived participants showed a 60% greater magnitude of amygdala activation in response to negative emotional stimuli compared to sleep-rested controls. The volumetric extent of amygdala activation was three-fold larger in the deprivation group.", citation: "Yoo et al. 2007 · Current Biology", paywalled: false, source_url: "https://pubmed.ncbi.nlm.nih.gov/17956744/" },
  { topic: "dmn_breathing_mechanism", body: "Attention to breath as a basic mindfulness practice reduces emotional responses in the amygdala while increasing functional connectivity between the amygdala and prefrontal cortex. The breath becomes a focal point that engages the brain's regulatory architecture.", citation: "Doll et al. 2016 · NeuroImage", paywalled: true, source_url: "https://pubmed.ncbi.nlm.nih.gov/27033686/" },
  { topic: "hrv_mechanism", body: "Heart rate variability biofeedback works by strengthening the baroreceptor reflex — the homeostatic system that adjusts heart rate against blood pressure changes. Recent proposals also implicate vagal afferent pathways to frontal cortical areas as part of the mechanism.", citation: "Lehrer & Gevirtz 2014 · Frontiers in Psychology", paywalled: false, source_url: "https://pmc.ncbi.nlm.nih.gov/articles/PMC4104929/" },
  { topic: "sit_application", body: "Stillform's daily practice during low-stakes moments is the inoculation phase. Setting tone when nothing is wrong builds the response that runs when something is. Practice during winning is what makes composure available during losing.", citation: "Meichenbaum 1985 · Stress Inoculation Training, Pergamon Press", paywalled: true, source_url: "https://archive.org/details/stressinoculatio0000meic" },
  { topic: "implementation_intentions_effect", body: "A 2006 meta-analysis by Gollwitzer and Sheeran across 94 independent studies and over 8,000 participants found implementation intentions produced a medium-to-large effect on goal attainment (Cohen's d = 0.65). The effect held across achievement, relationship, and health domains.", citation: "Gollwitzer & Sheeran 2006 · Advances in Experimental Social Psychology", paywalled: true, source_url: "https://cancercontrol.cancer.gov/sites/default/files/2020-06/goal_intent_attain.pdf" },
  { topic: "window_mechanism", body: "The window of tolerance is the optimal arousal zone in which a person can think clearly, regulate emotions, and engage socially. Above the window: hyperarousal — panic, rage, overwhelm. Below: hypoarousal — numbness, shutdown, dissociation.", citation: "Siegel 1999 · The Developing Mind, Guilford Press", paywalled: true, source_url: "https://www.guilford.com/books/The-Developing-Mind/Daniel-Siegel/9781462543045" },
  { topic: "mct_mechanism", body: "Metacognitive therapy targets how a person responds to thoughts (rumination, worry, suppression) rather than the content of those thoughts. The shift is from analyzing what a thought says to observing the thinking pattern itself — engaging the metacognitive level rather than the cognitive content.", citation: "Wells 2009 · Metacognitive Therapy, Guilford Press", paywalled: true, source_url: "https://www.guilford.com/books/Metacognitive-Therapy-for-Anxiety-and-Depression/Adrian-Wells/9781609184964/summary" },
  { topic: "mct_effect", body: "A 2018 meta-analysis evaluated 25 trials of metacognitive therapy across anxiety, depression, and other psychological complaints. The analysis found large effect sizes for symptom reduction in adult patients and indicated MCT was superior to waitlist and active treatment control conditions in many comparisons.", citation: "Normann & Morina 2018 · Frontiers in Psychology", paywalled: false, source_url: "https://pmc.ncbi.nlm.nih.gov/articles/PMC6246690/" },
  { topic: "misattribution_application", body: "The bio-filter is built on the well-documented phenomenon of misattributing arousal. What feels like overwhelm may be the system running on too little sleep, depletion, or pain — a hardware signal interpreted as a software experience.", citation: "Schachter & Singer 1962 · Psychological Review", paywalled: true, source_url: "https://en.wikipedia.org/wiki/Two-factor_theory_of_emotion" },
  { topic: "pain_mechanism", body: "Pain demands attention. It interrupts ongoing cognitive activity by forcing prioritization of the pain signal. The interruptive function depends on both the threat value of the pain and the demands of the environment — pain is selected for action from within complex motivational landscapes to urge escape.", citation: "Eccleston & Crombez 1999 · Psychological Bulletin", paywalled: true, source_url: "https://pubmed.ncbi.nlm.nih.gov/10349356/" }
];

// LocalStorage helpers for variety guard — last 5 card topics retained
const SCIENCE_CARD_HISTORY_KEY = "stillform_card_history";
function getRecentCardTopics() {
  try {
    const raw = localStorage.getItem(SCIENCE_CARD_HISTORY_KEY);
    if (!raw) return [];
    const parsed = JSON.parse(raw);
    return Array.isArray(parsed) ? parsed.slice(-5) : [];
  } catch { return []; }
}
function appendCardTopicToHistory(topic) {
  if (!topic) return;
  try {
    const current = getRecentCardTopics();
    const next = [...current, topic].slice(-5);
    localStorage.setItem(SCIENCE_CARD_HISTORY_KEY, JSON.stringify(next));
  } catch {}
}

// Pick a static fallback card that's not in recentTopics if possible
function pickStaticFallbackCard(recentTopics = []) {
  const eligible = STATIC_SCIENCE_CARDS.filter(c => !recentTopics.includes(c.topic));
  const pool = eligible.length > 0 ? eligible : STATIC_SCIENCE_CARDS;
  return pool[Math.floor(Math.random() * pool.length)];
}

// --------------------------------------------------------------------
// ScienceCard — post-session card showing one finding from the science library
// Appears AFTER post-rate / What Shifted, BEFORE ToolDebriefGate
// --------------------------------------------------------------------
function ScienceCard({ toolId, lastBreathPattern = null, lastBodyScanArea = null, feelStateBefore = null, feelStateAfter = null, sessionCount = 0, onContinue }) {
  const [card, setCard] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [showInfo, setShowInfo] = useState(false);
  const fetchedRef = useRef(false);

  useEffect(() => {
    if (fetchedRef.current) return;
    fetchedRef.current = true;

    const fetchCard = async () => {
      const recentTopics = getRecentCardTopics();
      const authToken = (typeof sbGetSession === "function" && sbGetSession()?.access_token) || "";
      const installId = typeof getOrCreateInstallId === "function" ? getOrCreateInstallId() : null;

      try {
        const response = await fetch(REFRAME_API_URL, {
          method: "POST",
          headers: {
            "Content-Type": "application/json",
            ...(authToken ? { Authorization: `Bearer ${authToken}` } : {})
          },
          body: JSON.stringify({
            input: "science_card_request",
            mode: "science_card",
            lastTool: toolId,
            lastBreathPattern,
            lastBodyScanArea,
            feelStateBefore,
            feelStateAfter,
            recentTopics,
            sessionCount,
            install_id: installId,
            user_id: (typeof sbGetUser === "function" && sbGetUser()?.id) || null
          })
        });
        const data = await response.json();
        if (response.ok && data && data.body && data.citation) {
          setCard({ openingLine: data.openingLine, body: data.body, citation: data.citation, topic: data.topic, source_url: data.source_url || null, paywalled: data.paywalled === true, source: "ai" });
          appendCardTopicToHistory(data.topic);
        } else {
          // AI failed — use static fallback
          const fallback = pickStaticFallbackCard(recentTopics);
          setCard({ openingLine: null, body: fallback.body, citation: fallback.citation, topic: fallback.topic, source_url: fallback.source_url || null, paywalled: fallback.paywalled === true, source: "static" });
          appendCardTopicToHistory(fallback.topic);
        }
      } catch (err) {
        // Network error — static fallback
        const fallback = pickStaticFallbackCard(recentTopics);
        setCard({ openingLine: null, body: fallback.body, citation: fallback.citation, topic: fallback.topic, source_url: fallback.source_url || null, paywalled: fallback.paywalled === true, source: "static" });
        appendCardTopicToHistory(fallback.topic);
      } finally {
        setLoading(false);
      }
    };

    fetchCard();
  }, [toolId, lastBreathPattern, lastBodyScanArea, feelStateBefore, feelStateAfter, sessionCount]);

  useEffect(() => {
    if (card && !loading) {
      try {
        window.plausible("Science Card Shown", {
          props: {
            topic: card.topic || "unknown",
            tool: toolId || "unknown",
            source: card.source || "unknown",
            hadOpeningLine: card.openingLine ? "yes" : "no"
          }
        });
      } catch {}
    }
  }, [card, loading, toolId]);

  const handleContinue = () => {
    try { window.plausible("Science Card Continued", { props: { topic: card?.topic || "unknown", source: card?.source || "unknown" } }); } catch {}
    onContinue();
  };
  const handleSkip = () => {
    try { window.plausible("Science Card Skipped", { props: { topic: card?.topic || "unknown", source: card?.source || "unknown" } }); } catch {}
    onContinue();
  };
  const handleInfoOpen = () => {
    setShowInfo(true);
    try { window.plausible("Science Card Info Opened"); } catch {}
  };

  if (loading) {
    return (
      <div style={{ maxWidth: 460, margin: "0 auto", paddingTop: 10 }}>
        <div style={{ background: "var(--surface)", border: "0.5px solid var(--amber-dim)", borderRadius: "var(--r-lg)", padding: "32px 16px", textAlign: "center" }}>
          <div className="t-mono-xs" style={{ color: "var(--amber)", opacity: 0.6 }}>
            Loading…
          </div>
        </div>
      </div>
    );
  }

  if (!card) return null;

  return (
    <div style={{ maxWidth: 460, margin: "0 auto", paddingTop: 10 }}>
      <div style={{ background: "var(--surface)", border: "0.5px solid var(--amber-dim)", borderRadius: "var(--r-lg)", padding: "20px 18px" }}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 12 }}>
          <div className="t-mono-xs" style={{ color: "var(--amber)" }}>
            The science behind this
          </div>
          <button
            onClick={handleInfoOpen}
            aria-label="About these cards"
            style={{
              background: "none", border: "0.5px solid var(--border)", borderRadius: "50%",
              width: 22, height: 22, display: "flex", alignItems: "center", justifyContent: "center",
              cursor: "pointer", color: "var(--text-muted)", fontSize: 11,
              fontFamily: "'IBM Plex Mono', monospace", padding: 0,
              WebkitTapHighlightColor: "transparent"
            }}
          >
            ⓘ
          </button>
        </div>

        {card.openingLine && (
          <div style={{ fontFamily: "'Cormorant Garamond', serif", fontSize: 18, fontWeight: 400, color: "var(--text)", lineHeight: 1.3, marginBottom: 12 }}>
            {card.openingLine}
          </div>
        )}

        <div className="t-body-md quiet" style={{ marginBottom: 14, fontFamily: "'DM Sans', sans-serif" }}>
          {card.body}
        </div>

        <div style={{ fontFamily: "'IBM Plex Mono', monospace", fontSize: 10, color: "var(--text-muted)", letterSpacing: "0.06em", marginBottom: 10, fontStyle: "italic" }}>
          {card.citation}
        </div>

        {card.source_url && (
          <div style={{ marginBottom: 16 }}>
            <a
              href={card.source_url}
              target="_blank"
              rel="noopener noreferrer"
              onClick={() => { try { window.plausible("Science Card Source Opened", { props: { topic: card.topic || "unknown", paywalled: card.paywalled ? "yes" : "no" } }); } catch {} }}
              style={{
                fontFamily: "'IBM Plex Mono', monospace",
                fontSize: 10,
                color: "var(--amber)",
                letterSpacing: "0.06em",
                textDecoration: "none",
                borderBottom: "0.5px dotted var(--amber-dim)",
                paddingBottom: 1
              }}
            >
              Read the study →{card.paywalled ? " (paywalled)" : ""}
            </a>
          </div>
        )}

        <div style={{ display: "flex", justifyContent: "flex-end", gap: 8 }}>
          <button
            onClick={handleSkip}
            style={{
              background: "none",
              border: "0.5px solid var(--border)",
              borderRadius: "var(--r)",
              color: "var(--text-muted)",
              fontSize: 12,
              cursor: "pointer",
              padding: "8px 14px",
              fontFamily: "'DM Sans', sans-serif"
            }}
          >
            Skip
          </button>
          <button
            onClick={handleContinue}
            className="btn btn-primary"
            style={{ fontSize: 12, padding: "8px 14px" }}
          >
            Continue
          </button>
        </div>
      </div>

      {showInfo && (
        <div
          style={{
            position: "fixed", inset: 0, background: "rgba(0,0,0,0.7)",
            display: "flex", alignItems: "center", justifyContent: "center",
            zIndex: 1000, padding: 20
          }}
          onClick={() => setShowInfo(false)}
        >
          <div
            onClick={(e) => e.stopPropagation()}
            style={{
              background: "var(--surface)",
              border: "0.5px solid var(--amber-dim)",
              borderRadius: "var(--r-lg)",
              padding: "22px 18px",
              maxWidth: 440,
              width: "100%",
              maxHeight: "85vh",
              overflowY: "auto"
            }}
          >
            <div className="t-mono-xs" style={{ color: "var(--amber)", marginBottom: 14 }}>
              The science behind this
            </div>
            <div className="t-body-sm quiet" style={{ lineHeight: 1.7, fontFamily: "'DM Sans', sans-serif" }}>
              <p style={{ marginTop: 0 }}>The findings shown here are drawn from the peer-reviewed research underlying Stillform's tools.</p>
              <p>Drawn from a curated library that grounds Stillform's mechanisms. AI-generated when available, static otherwise.</p>
              <p>The "Read the study" link goes to the source research. Some studies are openly published; others remain behind academic paywalls.</p>
              <p style={{ marginBottom: 0 }}>Stillform isn't affiliated with any of these journals or publishers. The science stands on its own; we cite it because it's proven.</p>
            </div>
            <div style={{ display: "flex", justifyContent: "flex-end", marginTop: 16 }}>
              <button
                onClick={() => setShowInfo(false)}
                className="btn btn-primary"
                style={{ fontSize: 12, padding: "8px 14px" }}
              >
                Close
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

function ToolDebriefGate({ toolId, regulationType, onContinue }) {
  const promptSet = getToolDebriefPromptSet(toolId, regulationType);
  const [selected, setSelected] = useState("");

  useEffect(() => {
    setSelected("");
  }, [toolId, regulationType]);

  const options = Array.isArray(promptSet?.options) ? promptSet.options : [];
  const continueEnabled = !!selected;

  return (
    <div style={{ maxWidth: 460, margin: "0 auto", paddingTop: 10 }}>
      <div style={{ background: "var(--surface)", border: "0.5px solid var(--amber-dim)", borderRadius: "var(--r-lg)", padding: "18px 16px" }}>
        <div className="t-mono-xs" style={{ color: "var(--amber)", marginBottom: 8 }}>
          Lock in how you processed
        </div>
        <div className="t-body-sm quiet" style={{ lineHeight: 1.6, marginBottom: 10 }}>
          {promptSet?.prompt || "Choose one line that best fits this session."}
        </div>
        <div className="t-caption" style={{ color: "var(--text-muted)", marginBottom: 12 }}>
          Take a moment to name what you used.
        </div>

        <div style={{ display: "flex", flexDirection: "column", gap: 6, marginBottom: 14 }}>
          {options.map((option) => (
            <button
              key={option}
              onClick={() => setSelected(option)}
              style={{
                textAlign: "left",
                background: selected === option ? "var(--amber-glow)" : "var(--surface2)",
                border: `0.5px solid ${selected === option ? "var(--amber-dim)" : "var(--border)"}`,
                borderRadius: "var(--r-sm)",
                padding: "10px 12px",
                color: selected === option ? "var(--amber)" : "var(--text-dim)",
                cursor: "pointer",
                fontSize: 12,
                lineHeight: 1.45,
                fontFamily: "'DM Sans', sans-serif"
              }}
            >
              {option}
            </button>
          ))}
          <button
            onClick={() => setSelected("I need another pass to lock this in.")}
            style={{
              textAlign: "left",
              background: selected === "I need another pass to lock this in." ? "var(--amber-glow)" : "var(--surface2)",
              border: `0.5px solid ${selected === "I need another pass to lock this in." ? "var(--amber-dim)" : "var(--border)"}`,
              borderRadius: "var(--r-sm)",
              padding: "10px 12px",
              color: selected === "I need another pass to lock this in." ? "var(--amber)" : "var(--text-dim)",
              cursor: "pointer",
              fontSize: 12,
              lineHeight: 1.45,
              fontFamily: "'DM Sans', sans-serif"
            }}
          >
            I need another pass to lock this in.
          </button>
        </div>

        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", gap: 10 }}>
          <button
            onClick={() => onContinue(null)}
            style={{
              background: "none",
              border: "none",
              color: "var(--text-muted)",
              fontSize: 11,
              cursor: "pointer",
              fontFamily: "'IBM Plex Mono', monospace",
              letterSpacing: "0.1em",
              textTransform: "uppercase",
              padding: "8px 4px",
              WebkitTapHighlightColor: "transparent"
            }}
          >
            Skip
          </button>
          <button
            className="btn btn-primary"
            disabled={!continueEnabled}
            onClick={() => continueEnabled && onContinue(selected)}
            style={{ opacity: continueEnabled ? 1 : 0.45, cursor: continueEnabled ? "pointer" : "not-allowed" }}
          >
            Continue
          </button>
        </div>
      </div>
    </div>
  );
}

function NextMoveStep({
  onConfirm,
  onSkip,
  title = "Next Move",
  description = "Choose one concrete action before you leave this session.",
  confirmLabel = "Save next move",
  skipLabel = "Skip for now"
}) {
  const [selectedActionId, setSelectedActionId] = useState(null);
  const [customAction, setCustomAction] = useState("");
  const selectedAction = NEXT_MOVE_ACTION_OPTIONS.find((item) => item.id === selectedActionId) || null;
  const cleanedCustomAction = String(customAction || "").trim().slice(0, 180);
  const ready = !!selectedActionId && (selectedActionId !== "custom" || cleanedCustomAction.length > 0);

  const handleConfirm = () => {
    if (!ready || typeof onConfirm !== "function") return;
    const label = selectedActionId === "custom"
      ? cleanedCustomAction
      : (selectedAction?.label || NEXT_MOVE_ACTION_LABELS[selectedActionId] || "Next move");
    onConfirm({
      id: `nextmove_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`,
      actionId: selectedActionId,
      label,
      customText: selectedActionId === "custom" ? cleanedCustomAction : null,
      createdAt: new Date().toISOString(),
      followUp: {
        dueAt: new Date(Date.now() + NEXT_MOVE_FOLLOW_UP_DELAY_MS).toISOString()
      }
    });
  };

  return (
    <div style={{ maxWidth: 460, margin: "0 auto", paddingTop: 10 }}>
      <div style={{ background: "var(--surface)", border: "0.5px solid var(--amber-dim)", borderRadius: "var(--r-lg)", padding: "18px 16px" }}>
        <div className="t-mono-xs" style={{ color: "var(--amber)", marginBottom: 8 }}>
          {title}
        </div>
        <div className="t-body-sm quiet" style={{ lineHeight: 1.6, marginBottom: 12 }}>
          {description}
        </div>
        <div style={{ display: "flex", gap: 8, flexWrap: "wrap", marginBottom: 14 }}>
          {NEXT_MOVE_ACTION_OPTIONS.map((item) => {
            const active = selectedActionId === item.id;
            return (
              <button aria-pressed={active}
                key={item.id}
                onClick={() => setSelectedActionId(item.id)}
                style={{
                  background: active ? "var(--amber-glow)" : "var(--surface2)",
                  border: `0.5px solid ${active ? "var(--amber-dim)" : "var(--border)"}`,
                  borderRadius: 999,
                  padding: "7px 12px",
                  color: active ? "var(--amber)" : "var(--text-dim)",
                  fontSize: 12,
                  cursor: "pointer",
                  fontFamily: "'DM Sans', sans-serif"
                }}
              >
                {item.label}
              </button>
            );
          })}
        </div>
        {selectedActionId === "custom" && (
          <div style={{ marginBottom: 14 }}>
            <textarea
              value={customAction}
              onChange={(event) => setCustomAction(String(event.target.value || "").slice(0, 180))}
              placeholder="Name one specific action you will take."
              rows={3}
              style={{
                width: "100%",
                background: "var(--surface2)",
                border: "0.5px solid var(--border)",
                borderRadius: "var(--r)",
                padding: "10px 12px",
                color: "var(--text)",
                fontSize: 12,
                lineHeight: 1.5,
                fontFamily: "'DM Sans', sans-serif",
                resize: "vertical",
                outline: "none"
              }}
            />
            <div style={{ marginTop: 6, fontSize: 10, color: "var(--text-muted)", textAlign: "right" }}>
              {Math.max(0, 180 - String(customAction || "").length)} characters left
            </div>
          </div>
        )}
        <button
          className="btn btn-primary"
          disabled={!ready}
          onClick={handleConfirm}
          style={{ width: "100%", opacity: ready ? 1 : 0.45, cursor: ready ? "pointer" : "not-allowed" }}
        >
          {confirmLabel}
        </button>
        {typeof onSkip === "function" && (
          <button
            className="btn btn-ghost"
            onClick={onSkip}
            style={{ width: "100%", marginTop: 8 }}
          >
            {skipLabel}
          </button>
        )}
      </div>
    </div>
  );
}

function NextMoveFollowUpCard({ session, onSubmit }) {
  const [didIt, setDidIt] = useState(null);
  const [helped, setHelped] = useState(null);
  const sessionTimestamp = String(session?.timestamp || "");
  const nextMoveLabel = getNextMoveLabel(session?.nextMove) || "that next move";

  useEffect(() => {
    setDidIt(null);
    setHelped(null);
  }, [sessionTimestamp]);

  useEffect(() => {
    if (didIt !== "yes") setHelped(null);
  }, [didIt]);

  if (!sessionTimestamp) return null;

  const helpedRequired = didIt === "yes";
  const submitReady = didIt !== null && (!helpedRequired || helped !== null);
  const handleSubmit = () => {
    if (!submitReady || typeof onSubmit !== "function") return;
    const didItCompleted = didIt === "yes";
    onSubmit({
      sessionTimestamp,
      didIt: didItCompleted ? true : null,
      helped: didItCompleted
        ? (helped === "yes" ? true : helped === "no" ? false : null)
        : null
    });
  };

  return (
    <div style={{ marginBottom: 16, background: "var(--surface)", border: "0.5px solid var(--amber-dim)", borderRadius: "var(--r)", padding: "14px 14px 12px" }}>
      <div style={{ fontFamily: "'IBM Plex Mono', monospace", fontSize: 8, letterSpacing: "0.12em", textTransform: "uppercase", color: "var(--amber)", marginBottom: 8 }}>
        Next Move follow-up
      </div>
      <div className="t-body-sm quiet" style={{ lineHeight: 1.55, marginBottom: 10 }}>
        You chose: <span style={{ color: "var(--text)" }}>{nextMoveLabel}</span>
      </div>
      <div style={{ marginBottom: 10 }}>
        <div className="t-caption" style={{ color: "var(--text-muted)", marginBottom: 6 }}>Did you do it?</div>
        <div style={{ display: "flex", gap: 6, flexWrap: "wrap" }}>
          {[
            { id: "yes", label: "Yes" },
            { id: "not-yet", label: "Not yet" }
          ].map((item) => {
            const active = didIt === item.id;
            return (
              <button aria-pressed={active}
                key={item.id}
                onClick={() => setDidIt(item.id)}
                style={{
                  background: active ? "var(--amber-glow)" : "transparent",
                  border: `1px solid ${active ? "var(--amber-dim)" : "var(--border)"}`,
                  borderRadius: 999,
                  padding: "5px 11px",
                  fontSize: 11,
                  color: active ? "var(--amber)" : "var(--text-muted)",
                  cursor: "pointer",
                  fontFamily: "'DM Sans', sans-serif"
                }}
              >
                {item.label}
              </button>
            );
          })}
        </div>
      </div>
      <div style={{ marginBottom: 12 }}>
        <div className="t-caption" style={{ color: "var(--text-muted)", marginBottom: 6 }}>Did it help?</div>
        <div style={{ display: "flex", gap: 6, flexWrap: "wrap", opacity: helpedRequired ? 1 : 0.5 }}>
          {[
            { id: "yes", label: "Yes" },
            { id: "no", label: "No" },
            { id: "not-sure", label: "Not sure yet" }
          ].map((item) => {
            const active = helped === item.id;
            return (
              <button aria-pressed={active}
                key={item.id}
                onClick={() => {
                  if (!helpedRequired) return;
                  setHelped(item.id);
                }}
                style={{
                  background: active ? "var(--amber-glow)" : "transparent",
                  border: `1px solid ${active ? "var(--amber-dim)" : "var(--border)"}`,
                  borderRadius: 999,
                  padding: "5px 11px",
                  fontSize: 11,
                  color: active ? "var(--amber)" : "var(--text-muted)",
                  cursor: helpedRequired ? "pointer" : "not-allowed",
                  fontFamily: "'DM Sans', sans-serif"
                }}
              >
                {item.label}
              </button>
            );
          })}
        </div>
        {!helpedRequired && (
          <div style={{ marginTop: 6, fontSize: 10, color: "var(--text-muted)" }}>
            Optional until you complete the action.
          </div>
        )}
      </div>
      <button
        className="btn btn-primary"
        disabled={!submitReady}
        onClick={handleSubmit}
        style={{ width: "100%", opacity: submitReady ? 1 : 0.45, cursor: submitReady ? "pointer" : "not-allowed" }}
      >
        Save follow-up
      </button>
    </div>
  );
}

// Speech-to-text hook — uses Web Speech API (free, built into browsers)
function useSpeechToText(onResult) {
  const [listening, setListening] = useState(false);
  const recognitionRef = useRef(null);
  const intentionalStop = useRef(false);

  const toggle = () => {
    if (listening) {
      intentionalStop.current = true;
      recognitionRef.current?.stop();
      setListening(false);
      return;
    }
    const SpeechRecognition = window.SpeechRecognition || window.webkitSpeechRecognition;
    if (!SpeechRecognition) return;
    intentionalStop.current = false;
    const recognition = new SpeechRecognition();
    recognition.continuous = true;
    recognition.interimResults = false;
    recognition.lang = "en-US";
    recognition.onresult = (event) => {
      let transcript = "";
      for (let i = event.resultIndex; i < event.results.length; i++) {
        if (event.results[i].isFinal) transcript += event.results[i][0].transcript;
      }
      if (transcript) onResult(transcript);
    };
    recognition.onerror = () => { intentionalStop.current = true; setListening(false); };
    recognition.onend = () => {
      // Mobile Chrome kills continuous recognition after each pause
      // Auto-restart unless user intentionally stopped
      if (!intentionalStop.current) {
        try { recognition.start(); } catch { setListening(false); }
      } else {
        setListening(false);
      }
    };
    recognitionRef.current = recognition;
    recognition.start();
    setListening(true);
  };

  useEffect(() => { return () => { intentionalStop.current = true; recognitionRef.current?.stop(); }; }, []);

  const supported = typeof window !== "undefined" && (window.SpeechRecognition || window.webkitSpeechRecognition);
  return { listening, toggle, supported };
}

// Reusable mic button for any text field
function MicButton({ onTranscript }) {
  const speech = useSpeechToText(onTranscript);
  if (!speech.supported) return null;
  return (
    <button onClick={speech.toggle} style={{
      background: speech.listening ? "rgba(200,60,60,0.15)" : "var(--surface)",
      border: `1px solid ${speech.listening ? "rgba(200,60,60,0.4)" : "var(--border)"}`,
      borderRadius: "var(--r-lg)", padding: "6px 12px", cursor: "pointer", fontSize: 12,
      color: speech.listening ? "rgba(200,80,80,0.9)" : "var(--text-dim)",
      fontFamily: "'DM Sans', sans-serif", transition: "all 0.2s",
      animation: speech.listening ? "pulse 1.5s ease-in-out infinite" : "none"
    }}>
      🎙 {speech.listening ? "Listening..." : "Speak"}
    </button>
  );
}

